const RESPONSES: Record<StarCategory, Record<ZodiacSignId, StarResponse[]>> = {
  love: {
    aries: [
      { text: "Marte, il tuo pianeta governatore, accende oggi una fiamma che non puoi ignorare. La tua natura impulsiva e coraggiosa ti spinge verso una connessione intensa e viscerale. Qualcuno del tuo passato potrebbe riaffacciarsi nella tua vita, portando con se' emozioni che credevi sopite. Il fuoco che ti contraddistingue arde piu' forte del solito.", advice: "Lascia che il cuore guidi ma ricorda che la pazienza, rara nel tuo segno di fuoco, oggi sara' la tua alleata piu' grande." },
      { text: "Venere attraversa il tuo cielo con un'energia che amplifica il tuo naturale magnetismo da Ariete. La tua passione e' contagiosa e chi ti sta vicino la percepisce chiaramente. E' il momento perfetto per dichiarare cio' che senti senza filtri, con quella sincerita' diretta che solo un segno di fuoco come il tuo sa esprimere. Le stelle ti sostengono in ogni gesto audace.", advice: "Il coraggio in amore viene sempre ricompensato. Non rimandare quella conversazione importante: il tuo istinto marziano sa gia' cosa dire." },
      { text: "La tua energia di fuoco oggi si trasforma in un magnetismo dolce e avvolgente. Come Ariete, sei abituato a conquistare con la forza della tua personalita', ma oggi le stelle ti chiedono di ascoltare di piu'. Una connessione inaspettata si avvicina, portata dal transito favorevole di Venere nel tuo settore sentimentale. Lascia che sia l'altro a fare il primo passo, per una volta.", advice: "Non forzare nulla, lascia che la magia accada naturalmente. La tua impazienza innata potrebbe rovinare un momento perfetto." },
      { text: "Il tuo fuoco interiore oggi brilla con una luce particolare che attira anime coraggiose quanto la tua. Marte ti dona un'aura di sicurezza che rende ogni tuo gesto irresistibile. Potresti incontrare qualcuno che non si lascia intimidire dalla tua intensita', anzi ne e' affascinato. Questa e' una rara combinazione celeste che premia chi, come te, non ha paura di mostrare la propria vulnerabilita'.", advice: "Sii autentico al cento per cento. La tua natura diretta e senza maschere e' esattamente cio' che l'altra persona cerca." },
      { text: "Le costellazioni indicano un risveglio emotivo potente per il tuo segno. Come primo segno dello zodiaco, sei nato per iniziare nuovi capitoli, e oggi ne inizia uno sentimentale. L'energia marziana che ti governa si mescola con la dolcezza di una Luna favorevole, creando un'alchimia rara. Preparati a sentire emozioni che vanno oltre la superficie, nel profondo del tuo cuore guerriero.", advice: "Approfitta di questa giornata per fare il primo passo. L'esitazione non appartiene al tuo segno: agisci ora." },
      { text: "Oggi Marte e Venere danzano insieme nel tuo cielo, unendo passione e tenerezza in un mix esplosivo. Come Ariete, tendi a vivere l'amore come una conquista, ma le stelle ti invitano a rallentare e assaporare ogni istante. Un messaggio inatteso potrebbe cambiare completamente la tua prospettiva sentimentale. Non sottovalutare il potere delle parole scritte con il cuore.", advice: "Rispondi con il cuore, non con l'orgoglio. La tua natura competitiva non serve in amore: qui vince chi si arrende." },
      { text: "Le stelle sussurrano di un legame che si rafforza sotto l'influenza protettiva di Marte. La tua lealta' feroce, tipica dell'Ariete, viene finalmente riconosciuta e apprezzata da chi ti sta accanto. Questo e' un momento in cui la tua natura passionale trova il suo complemento perfetto. Non aver paura di mostrare il lato tenero che nascondi dietro la corazza del guerriero.", advice: "Dedica tempo di qualita' a chi ami. Anche i guerrieri hanno bisogno di deporre le armi e lasciarsi abbracciare." },
      { text: "Il fuoco del tuo segno oggi illumina il sentiero verso una comprensione piu' profonda di te stesso in amore. Come Ariete, sei abituato ad agire d'impulso, ma le stelle ti mostrano che la vera forza sta nel saper aspettare il momento giusto. Una persona speciale sta osservando la tua evoluzione con ammirazione. Il coraggio di cambiare approccio potrebbe regalarti cio' che cerchi.", advice: "Usa questa energia per creare connessioni profonde, non solo intense. La profondita' e' il prossimo livello per il tuo cuore." },
      { text: "Una scelta sentimentale importante si presenta sotto il cielo del tuo segno. Marte ti dona la lucidita' necessaria per vedere oltre le apparenze. La tua natura di fuoco ti fa preferire azioni rapide, ma oggi le costellazioni premiano chi riflette prima di agire. Ascolta quella vocina interiore che conosci bene: e' la saggezza dell'Ariete maturo che sa quando combattere e quando amare.", advice: "La risposta che cerchi e' gia' nel tuo cuore. Fidati del tuo istinto ma concedigli il tempo di parlarti chiaramente." },
      { text: "Oggi il tuo carisma raggiunge livelli stellari, amplificato dal transito favorevole di Marte nel tuo segno. La tua energia di fuoco attira naturalmente chi cerca calore e autenticita'. Una persona potrebbe confessarti qualcosa che non ti aspetti, qualcosa che cambiera' la dinamica tra voi. Il tuo coraggio naturale sara' fondamentale per accogliere questa rivelazione con grazia.", advice: "Ascolta con il cuore aperto e rispondi con la generosita' che contraddistingue i migliori figli di Marte." },
    ],
    taurus: [
      { text: "Venere, la tua dolce governatrice, illumina oggi il settore piu' intimo del tuo cuore. Come Toro, cerchi stabilita' e sicurezza in amore, e le stelle ti confermano che sei sulla strada giusta. La tua pazienza leggendaria sta per essere premiata con una manifestazione concreta dei tuoi desideri sentimentali. Qualcosa di solido e duraturo si sta costruendo mattone dopo mattone.", advice: "Abbi pazienza, le cose belle richiedono il tempo che il tuo segno di terra sa rispettare. Non accelerare cio' che deve maturare." },
      { text: "La sensualita' che contraddistingue il tuo segno oggi e' amplificata da una Luna particolarmente favorevole. Come figlio di Venere, hai un talento innato per i gesti romantici e le attenzioni concrete. Qualcuno si accorgera' di quanto sei speciale proprio attraverso quei piccoli dettagli che curi con tanta dedizione. La bellezza che vedi nel mondo si riflette nelle tue relazioni.", advice: "Esprimi i tuoi sentimenti con gesti concreti. Un regalo pensato con cura o una cena preparata con amore parlano piu' di mille parole." },
      { text: "Le stelle vedono un periodo di grande armonia per il tuo cuore terrestre. La tua natura di Toro ti rende un partner fedele e devoto, qualita' che oggi vengono particolarmente apprezzate. Un legame che hai coltivato con pazienza e costanza mostra finalmente i suoi frutti piu' dolci. Venere ti avvolge in un'aura di calore che rende ogni momento condiviso prezioso e indimenticabile.", advice: "La costanza e' il tuo superpotere in amore. Non smettere di innaffiare quel giardino sentimentale che hai piantato con tanta cura." },
      { text: "Qualcuno ammira in silenzio la tua solidita' e affidabilita'. Come segno di terra governato da Venere, emani una sicurezza che pochi possiedono. Oggi potresti scoprire un'ammirazione segreta che si nascondeva proprio sotto i tuoi occhi. La tua capacita' di creare comfort e bellezza intorno a te funziona come un magnete per le anime che cercano un porto sicuro.", advice: "Apri gli occhi ai segnali che ti circondano. Non tutto l'amore si dichiara a voce alta: a volte si nasconde nei gesti quotidiani." },
      { text: "Le costellazioni indicano un momento di rara serenita' sentimentale per il tuo segno. La tua natura taurina, radicata e presente, ti permette di godere appieno della pace che hai costruito. Non cercare complicazioni dove c'e' semplicita': la bellezza dell'amore sta spesso nelle cose ordinarie vissute con straordinaria presenza. Venere sorride al tuo modo di amare con i piedi per terra.", advice: "Non cercare perfezione dove c'e' gia' bellezza. Il tuo perfezionismo venusiano a volte ti impedisce di vedere quanto hai gia'." },
      { text: "Un gesto romantico inaspettato ti scaldera' il cuore oggi, toccando quella sensibilita' profonda che il Toro nasconde sotto la sua corazza di forza. La tua natura sensuale si risveglia con l'influenza di Venere nel tuo settore dei piaceri. Questo e' il momento di lasciarti andare alla dolcezza senza razionalizzare ogni emozione. Anche la terra piu' solida ha bisogno della pioggia per fiorire.", advice: "Ricambia con la stessa intensita' e non aver paura di mostrare il tuo lato vulnerabile. La forza vera e' anche tenerezza." },
      { text: "La Luna nel tuo segno amplifica le emozioni e la tua connessione con i sensi. Come Toro, vivi l'amore attraverso il tatto, il gusto, i profumi, e oggi ogni sensazione e' moltiplicata. Qualcuno potrebbe sorprenderti con una dichiarazione che va dritto al cuore della tua natura terrestre. Lasciati travolgere senza opporre la resistenza al cambiamento tipica del tuo segno.", advice: "Oggi e' il giorno giusto per parlare di sentimenti profondi. La tua voce calma e rassicurante ha il potere di guarire." },
      { text: "Le stelle rivelano che la persona giusta per te apprezza esattamente la tua autenticita' senza fronzoli. La lealta' del Toro, la sua dedizione silenziosa e la capacita' di costruire qualcosa di concreto sono doni rari nel mondo moderno. Non sentirti mai in dovere di cambiare la tua essenza per compiacere qualcuno. Chi merita il tuo amore imparera' ad amarne anche la testardaggine.", advice: "Non cambiare per piacere a qualcuno. La tua natura di terra e' una roccia su cui si costruiscono castelli d'amore." },
      { text: "Un periodo di profonda connessione fisica e emotiva si apre davanti a te sotto la benedizione di Venere. Come Toro, hai bisogno di sentire l'amore non solo con il cuore ma con tutto il corpo. Le stelle favoriscono l'intimita' e i momenti di condivisione autentica. Coltiva ogni istante con la stessa cura con cui cureresti un giardino prezioso, perche' i frutti saranno dolcissimi.", advice: "Coltiva l'intimita' con piccoli gesti quotidiani. Un massaggio, una cena a lume di candela: il Toro conquista attraverso i sensi." },
      { text: "Le stelle vedono un futuro luminoso e stabile per il tuo cuore. La pazienza che il tuo segno di terra ha investito nelle relazioni sta finalmente mostrando risultati tangibili. Venere promette che l'amore che cerchi non e' un sogno irraggiungibile ma una realta' che si sta materializzando. Fidati del percorso lento ma inesorabile che il destino ha tracciato per te, perche' ogni passo ti avvicina.", advice: "L'amore vero arriva quando smetti di inseguirlo. Il Toro sa aspettare e la ricompensa e' sempre all'altezza dell'attesa." },
    ],
    gemini: [
      { text: "Mercurio, il tuo brillante pianeta governatore, oggi accende conversazioni che possono cambiare tutto. Come Gemelli, il tuo modo di innamorarti passa prima dalla mente e poi dal cuore, e oggi le stelle favoriscono proprio questo tipo di connessione intellettuale. Un dialogo profondo e stimolante potrebbe trasformarsi nella scintilla di qualcosa di molto piu' grande. Le parole giuste al momento giusto aprono porte che nessuna chiave potrebbe.", advice: "Parla con sincerita' e senza le maschere che a volte indossi. La tua eloquenza mercuriana oggi tocchera' il cuore di chi ascolta." },
      { text: "La dualita' che caratterizza il tuo segno oggi lavora a tuo favore in amore. Come Gemelli, porti leggerezza e profondita' nella stessa persona, un mix irresistibile per chi sa apprezzarlo. Mercurio ti dona un'eloquenza che va oltre le parole: ogni tuo gesto comunica desiderio e curiosita'. Qualcuno e' completamente affascinato dalla tua capacita' di rendere ogni momento un'avventura.", advice: "Usa il dono della comunicazione per avvicinarti. Scrivi quel messaggio che hai in mente da giorni: le stelle dicono che e' il momento." },
      { text: "Le stelle vedono una doppia possibilita' sentimentale che rispecchia perfettamente la tua natura gemellare. Il tuo segno d'aria ti dona la capacita' unica di vedere l'amore da prospettive diverse, e oggi questa visione multipla e' un vantaggio enorme. Non si tratta di scegliere tra due persone, ma tra due versioni di te stesso in amore. Mercurio illumina la strada verso la scelta piu' autentica.", advice: "Ascolta meno la mente analitica e piu' le emozioni. Come segno d'aria tendi a razionalizzare, ma l'amore va vissuto, non spiegato." },
      { text: "Un incontro stimolante sul piano intellettuale potrebbe trasformarsi in qualcosa di inaspettatamente romantico. Come Gemelli, hai bisogno di una mente che tenga il passo con la tua, qualcuno che sappia stimolarti e sorprenderti. Mercurio porta oggi sulla tua strada una persona che sa giocare con le parole quanto te. La conversazione che ne nascera' potrebbe essere l'inizio di un capitolo bellissimo.", advice: "Non sottovalutare la connessione mentale. Per un Gemelli, la seduzione piu' potente e' quella che passa attraverso l'intelligenza." },
      { text: "Le costellazioni indicano leggerezza e gioia nei tuoi rapporti, esattamente l'energia che il tuo segno d'aria ama di piu'. Oggi Mercurio ti libera dalle preoccupazioni sentimentali e ti invita a vivere l'amore con la spontaneita' di un bambino. La tua versatilita' ti permette di adattarti a qualsiasi situazione romantica, trasformando anche un momento ordinario in qualcosa di magico e memorabile.", advice: "Lasciati andare alla spontaneita' che ti e' naturale. Non pianificare ogni dettaglio: i momenti migliori sono quelli improvvisati." },
      { text: "Qualcuno e' profondamente affascinato dalla tua capacita' di essere mille persone in una sola. La versatilita' dei Gemelli non e' instabilita', e' ricchezza, e oggi le stelle lo rendono evidente a chi ti sta vicino. Mercurio amplifica il tuo charme naturale rendendo ogni tua parola un piccolo incantesimo. Non aver paura di mostrare tutte le sfaccettature del tuo carattere complesso.", advice: "Mostra ogni lato di te senza paura di confondere. Chi ti ama davvero amara' tutte le versioni di te, non solo quella comoda." },
      { text: "Un messaggio, una chiamata o un incontro casuale potrebbe stravolgere la tua vita sentimentale in modo positivo. Come segno governato da Mercurio, il dio della comunicazione, le informazioni che arrivano a te hanno sempre un significato piu' profondo. Oggi le stelle ti chiedono di prestare attenzione a ogni sincronicita', ogni coincidenza. Il destino parla la tua lingua: quella delle connessioni impreviste.", advice: "Non ignorare le piccole coincidenze. Per un Gemelli, l'universo manda messaggi attraverso le parole e gli incontri casuali." },
      { text: "Le stelle parlano di una curiosita' reciproca che si sta trasformando in attrazione vera. La tua mente da Gemelli, sempre in movimento, oggi rallenta per osservare qualcuno con occhi nuovi. Mercurio e Venere si allineano per offrirti un'esperienza sentimentale che unisce stimolo intellettuale e calore emotivo. E' raro trovare entrambi nella stessa persona, ma oggi le probabilita' sono a tuo favore.", advice: "Esplora senza paura di scoprire cose nuove. La curiosita' e' la bussola del Gemelli: seguila anche in amore." },
      { text: "La tua energia sociale oggi raggiunge il suo apice sotto l'influenza potenziata di Mercurio. Come Gemelli, sei il segno che trasforma ogni interazione in un'opportunita', e oggi una di queste interazioni potrebbe rivelarsi speciale. Qualcuno che incontri in un contesto inaspettato ti fara' battere il cuore. La magia dell'imprevisto e' il terreno fertile dove nascono le storie piu' belle.", advice: "Sii aperto alle sorprese del destino. Per un Gemelli, l'amore arriva spesso da dove meno te lo aspetti." },
      { text: "Mercurio e Venere danzano insieme nel tuo cielo creando un'armonia rara tra parola e sentimento. Come Gemelli, a volte la testa e il cuore parlano lingue diverse, ma oggi sono perfettamente sincronizzati. Parole d'amore che normalmente faresti fatica a pronunciare oggi escono con naturalezza e grazia. Approfittane per dire cio' che senti a chi conta davvero nella tua vita.", advice: "Accogli e offri parole d'amore con la stessa facilita' con cui respiri. Oggi la comunicazione del cuore e' la tua arte piu' potente." },
    ],
    cancer: [
      { text: "La Luna, tua fedele governatrice, illumina oggi i sentimenti piu' profondi del tuo cuore acquatico. Come Cancro, possiedi un'intelligenza emotiva che pochi segni possono eguagliare, e oggi questa dote e' amplificata al massimo. Le tue intuizioni sentimentali sono infallibili: se senti che qualcosa sta cambiando tra te e un'altra persona, fidati. Le maree emotive ti guidano verso un porto sicuro.", advice: "La vulnerabilita' e' una forza immensa, non una debolezza. Apriti con chi merita di vedere il tuo mondo interiore." },
      { text: "Le stelle vedono un nido d'amore che si rafforza sotto la protezione della tua Luna. Come segno d'acqua, hai bisogno di sicurezza emotiva per fiorire, e oggi le costellazioni ti offrono esattamente questo. Un legame che hai curato con la tua tipica dedizione materna sta raggiungendo un livello di intimita' che pochi conoscono. La tua capacita' di nutrire chi ami e' un dono che oggi viene pienamente ricambiato.", advice: "Dedica attenzione ai piccoli dettagli della relazione. Il tuo intuito lunare sa esattamente cosa serve per far sentire amato l'altro." },
      { text: "Un'emozione intensa ti attraversera' oggi come un'onda che non puoi controllare, e va bene cosi'. Come Cancro, le tue emozioni sono il tuo superpotere, non il tuo punto debole. La Luna amplifica la tua capacita' di connetterti a un livello che va oltre le parole, dove i cuori si parlano in silenzio. Qualcuno percepira' questa tua apertura e rispondera' con una sincerita' che ti commuovera'.", advice: "Non avere paura di mostrare cio' che provi. Il tuo segno d'acqua ha il dono di sciogliere anche i cuori piu' freddi." },
      { text: "Qualcuno ha bisogno del tuo calore unico e avvolgente. Come Cancro, sei il rifugio naturale dello zodiaco, il porto dove le anime stanche trovano riparo. Oggi la tua naturale empatia ti guidera' verso una persona che ha bisogno esattamente di cio' che solo tu puoi offrire. Il tuo cuore grande e protettivo fara' la differenza nella giornata di qualcuno, e questo gesto tornera' a te moltiplicato.", advice: "Offri il tuo sostegno senza aspettarti nulla in cambio. La generosita' emotiva del Cancro e' la magia piu' pura che esista." },
      { text: "Le costellazioni indicano un possibile ritorno alle origini sentimentali per il tuo segno. La tua natura nostalgica e il legame profondo con il passato, tipici del Cancro, potrebbero portare alla superficie ricordi e connessioni che credevi chiuse. La Luna ti invita a valutare con saggezza se riaprire certe porte, perche' non tutti i ritorni portano felicita'. Ascolta il tuo istinto, lui sa distinguere.", advice: "Valuta con la saggezza del tuo elemento acqua se riaprire quella porta. Il tuo cuore e' generoso, ma deve anche proteggersi." },
      { text: "La tua intuizione sentimentale oggi e' al massimo livello, potenziata dalla Luna nel suo aspetto piu' luminoso. Come Cancro, hai un sesto senso per le emozioni altrui che rasenta la telepatia. Oggi capirai cose che non vengono dette, leggerai tra le righe di ogni gesto e parola. Questa chiaroveggenza emotiva ti permettera' di prendere decisioni sentimentali con una sicurezza che sorprendera' anche te stesso.", advice: "Il tuo sesto senso in amore non sbaglia mai. Fidati delle sensazioni viscerali, sono la bussola della tua anima acquatica." },
      { text: "Un gesto di tenerezza ricevuto oggi riempira' il tuo cuore sensibile fino all'orlo. Come segno governato dalla Luna, le piccole attenzioni per te valgono piu' di qualsiasi grande dichiarazione. Qualcuno ha capito che per conquistare un Cancro servono costanza, dolcezza e autenticita'. Questo riconoscimento della tua vera natura e' il regalo piu' prezioso che le stelle potessero farti.", advice: "Conserva questi momenti nella memoria del cuore. Per un Cancro, i ricordi felici sono il tesoro piu' prezioso." },
      { text: "Le stelle parlano di sicurezza emotiva finalmente raggiunta nel tuo percorso sentimentale. Come Cancro, hai attraversato maree alte e basse per arrivare a questo punto di equilibrio. La Luna benedice il legame che hai costruito con pazienza e dedizione, riconoscendo la profondita' unica che il tuo segno d'acqua porta in ogni relazione. Stai creando qualcosa di raro e prezioso: un amore che e' anche casa.", advice: "Continua su questa strada con fiducia. Il Cancro costruisce lentamente ma crea legami che durano per sempre." },
      { text: "La dolcezza e' la tua arma segreta e oggi si rivela piu' potente che mai. Come Cancro, possiedi una grazia emotiva che disarma chiunque, la capacita' di far sentire l'altro il centro del tuo universo. Oggi questa qualita' lunare sara' irresistibile per chi ti circonda. Non sottovalutare mai il potere di un abbraccio dato con il cuore: per il tuo segno, il contatto fisico e' linguaggio puro dell'anima.", advice: "Un abbraccio sincero vale piu' di mille parole. La tua natura protettiva oggi guarisce chi tocchi con il cuore." },
      { text: "Le maree emotive si calmano e un periodo di serenita' sentimentale profonda ti attende. Dopo settimane di alti e bassi emotivi tipici del tuo segno d'acqua, la Luna ti concede una tregua dolce e rigenerante. Come Cancro, hai bisogno di questi momenti di pace per ricaricare la tua immensa riserva di amore. Goditi la quiete sapendo che e' meritata e che prepara il terreno per gioie ancora piu' grandi.", advice: "Goditi la pace dopo la tempesta emotiva. Il Cancro sa che anche il mare piu' agitato prima o poi trova la calma." },
    ],
    leo: [
      { text: "Il Sole, tuo potente governatore, illumina oggi il settore dell'amore con una luce calda e dorata. Come Leone, sei nato per brillare e per essere amato, e le stelle confermano che oggi il palcoscenico sentimentale e' tutto tuo. La tua generosita' naturale e il tuo calore avvolgente attraggono come una calamita chi cerca autenticita' e passione. Preparati a ricevere l'ammirazione che meriti.", advice: "Lascia che la tua luce attiri chi la merita davvero. Non tutti sono degni del calore del Leone: scegli con saggezza." },
      { text: "Le stelle vedono ammirazione e desiderio concentrarsi intorno a te come farfalle attratte dalla fiamma. Come segno di fuoco governato dal Sole, hai un carisma innato che oggi raggiunge il suo apice. Ma ricorda che il vero amore non e' solo adorazione: e' anche accettazione dei tuoi momenti di ombra. Cerca chi ti ama per la tua luce ma resta anche quando il cielo si copre.", advice: "Scegli chi ti ama per cio' che sei davvero, non per lo spettacolo che offri. Il Leone autentico merita un amore altrettanto reale." },
      { text: "Una dichiarazione coraggiosa e' nell'aria e le stelle ti sostengono con tutta la loro forza. Come Leone, il tuo orgoglio a volte ti impedisce di mostrare la vulnerabilita', ma oggi il Sole ti chiede un atto di coraggio diverso. Dichiarare i propri sentimenti richiede piu' forza di qualsiasi battaglia, e tu hai quella forza nel sangue. Il tuo cuore regale merita di essere espresso senza paura.", advice: "Il leone non teme di mostrare i sentimenti. La vera regalita' sta nel saper essere forte e tenero allo stesso tempo." },
      { text: "Oggi il tuo magnetismo solare e' letteralmente inarrestabile e chiunque ti incroci lo percepira'. La tua aura di fuoco, amplificata dal Sole nel suo aspetto piu' generoso, ti rende il centro di ogni stanza. Qualcuno che ti osserva da lontano potrebbe finalmente trovare il coraggio di avvicinarsi, attratto dalla tua energia vitale. L'amore per il Leone spesso arriva con uno scoppio di luce.", advice: "Usa il tuo carisma solare con generosita' e consapevolezza. Il potere di far sentire speciale qualcuno e' il tuo dono piu' grande." },
      { text: "Le costellazioni parlano di una passione che arde con l'intensita' tipica del tuo segno di fuoco. Il Sole alimenta una fiamma sentimentale che hai nutrito con la tua dedizione leonina. Ma ricorda che anche il fuoco piu' potente ha bisogno di cura per non spegnersi. La passione va alimentata con attenzioni quotidiane, gesti di tenerezza e la presenza costante che il tuo cuore generoso sa offrire.", advice: "La passione va nutrita ogni giorno, non data per scontata. Anche il Sole tramonta per poi risorgere piu' splendente di prima." },
      { text: "Un gesto grandioso in amore sara' apprezzato molto piu' di quanto immagini. Come Leone, hai il talento naturale per il romanticismo teatrale, quei momenti che lasciano il segno nella memoria. Oggi le stelle ti incoraggiano a esprimere i tuoi sentimenti in grande stile, come solo un segno governato dal Sole sa fare. Non temere di essere troppo: per chi ti ama, non lo sarai mai abbastanza.", advice: "Non temere di essere romantico in modo grandioso. Il Leone che ama con tutto se stesso e' uno spettacolo che incanta." },
      { text: "Le stelle indicano lealta' e protezione come pilastri del tuo rapporto sentimentale. Come Leone, quando ami lo fai con una devozione feroce e incondizionata che pochi segni possono eguagliare. Questa intensita' oggi viene riconosciuta e ricambiata con la stessa forza. Il Sole benedice le unioni basate sul rispetto reciproco e sulla capacita' di crescere insieme senza mai smettere di ammirarsi.", advice: "La fedelta' del Leone e' leggendaria. Continua a proteggere chi ami con la forza del tuo cuore solare." },
      { text: "Qualcuno e' pronto a seguirti ovunque il tuo spirito reale decida di andare. Come Leone, hai bisogno di un partner che sia anche un alleato, qualcuno che creda nei tuoi sogni grandi quanto il tuo cuore. Oggi le stelle ti mostrano che questa persona potrebbe gia' essere nella tua vita. Riconosci chi ti ama non per il tuo trono ma per l'anima generosa che ci siede sopra.", advice: "L'amore vero si riconosce nei momenti difficili, non solo nelle celebrazioni. Chi resta quando il Sole si nasconde, quello e' amore." },
      { text: "Il tuo cuore regale merita un amore altrettanto nobile e coraggioso. Come primo segno di fuoco fisso, il Leone non si accontenta di relazioni tiepide o mediocri. Oggi le stelle ti ricordano di alzare i tuoi standard e di non accettare meno di cio' che meriti. La tua generosita' non deve mai essere confusa con la disponibilita' illimitata. Anche il re piu' buono deve proteggere il proprio cuore.", advice: "Alza i tuoi standard sentimentali. Il Leone che conosce il proprio valore attira un amore che lo rispecchia." },
      { text: "Le stelle vedono celebrazione e gioia nella tua sfera sentimentale. Un momento speciale si avvicina, uno di quelli che il tuo segno solare ama vivere in grande stile. Il Sole e Venere collaborano per regalarti un'esperienza romantica memorabile. Come Leone, sai trasformare qualsiasi momento in un evento, e oggi questa capacita' si esprime al massimo nel campo dell'amore. Preparati a brillare insieme.", advice: "Preparati a festeggiare l'amore con lo stile che ti contraddistingue. Il Leone celebra la vita e il cuore con uguale magnificenza." },
    ],
    virgo: [
      { text: "Le stelle invitano la tua mente analitica a concedere piu' spazio al cuore oggi. Come Vergine, governata da Mercurio in aspetto terrestre, tendi ad analizzare ogni emozione prima di viverla. Ma l'amore non segue la logica, e oggi le costellazioni ti chiedono di lasciar andare il controllo. La spontaneita' che ti spaventa potrebbe rivelarsi la chiave per sbloccare una connessione che aspettavi da tempo.", advice: "Smetti di analizzare e inizia a sentire. La perfezione che cerchi esiste gia', solo che la stai cercando con gli occhi sbagliati." },
      { text: "Mercurio affina la tua percezione ai massimi livelli e oggi noterai dettagli sentimentali che tutti gli altri ignorano. Come Vergine, il tuo occhio attento legge le microespressioni, i toni di voce, i gesti involontari. Questa capacita' di osservazione oggi ti rivelera' qualcosa di importante sulla persona che ti sta a cuore. I piccoli gesti che noti sono la mappa segreta dei sentimenti altrui.", advice: "I piccoli gesti rivelano i grandi sentimenti. Il tuo occhio da Vergine vede cio' che altri non possono: fidati di cio' che osservi." },
      { text: "Un atto di servizio e dedizione verso chi ami parlera' oggi piu' forte di qualsiasi dichiarazione romantica. Come Vergine, esprimi l'amore attraverso le azioni concrete: preparare il caffe' al mattino, ricordare un appuntamento importante, risolvere un problema pratico. Questo linguaggio d'amore silenzioso ma potente oggi viene finalmente riconosciuto e apprezzato per quello che e': devozione pura.", advice: "Mostra l'amore attraverso le azioni concrete che ti vengono naturali. Il tuo modo pratico di amare e' poesia per chi sa leggerla." },
      { text: "Le costellazioni indicano che la ricerca della perfezione in amore sta cedendo il passo a qualcosa di piu' autentico. Come Vergine, il tuo idealismo sentimentale a volte ti impedisce di vedere la bellezza di cio' che e' imperfetto. Oggi Mercurio ti dona la saggezza di accettare le imperfezioni come parte essenziale dell'amore vero. Le crepe sono i punti da cui entra la luce piu' bella.", advice: "Le imperfezioni rendono unico e irripetibile ogni rapporto. Accetta l'altro cosi' com'e', come vorresti essere accettato tu." },
      { text: "Qualcuno apprezza profondamente la tua dedizione silenziosa e costante. Come segno di terra, la Vergine costruisce l'amore mattone dopo mattone, senza fanfare ma con una solidita' che il tempo non scalfisce. Oggi questa persona trovera' il modo di dimostrarti quanto la tua presenza discreta ma insostituibile significhi. Mercurio porta alla luce cio' che le parole spesso non riescono ad esprimere.", advice: "Accetta i complimenti con grazia senza sminuirti. La Vergine merita di sentirsi apprezzata quanto apprezza gli altri." },
      { text: "Le stelle parlano di una connessione che nasce dalla mente e conquista il cuore, il percorso perfetto per il tuo segno. Come Vergine, hai bisogno di stimolo intellettuale prima di aprire le porte del cuore. Oggi Mercurio porta sulla tua strada un'affinita' mentale che potrebbe evolversi in qualcosa di molto piu' profondo. Non avere fretta di catalogare questa emozione: lascia che si sviluppi al suo ritmo naturale.", advice: "Lascia che la mente apra la strada al cuore senza forzare i tempi. L'amore della Vergine matura come il vino migliore." },
      { text: "Un ordine nuovo e armonioso si sta stabilendo nella tua vita sentimentale. Come Vergine, hai bisogno di struttura anche nelle emozioni, e oggi le stelle ti confermano che la fase di caos sentimentale sta lasciando il posto a una chiarezza rigenerante. Mercurio organizza i pensieri del cuore e ti permette di vedere con lucidita' dove stai andando. Questa consapevolezza e' il fondamento su cui costruire.", advice: "Accogli il cambiamento con fiducia. Il nuovo ordine sentimentale rispecchia la crescita interiore della tua anima terrestre." },
      { text: "La tua attenzione meticolosa ai dettagli oggi ti rendera' il partner o il pretendente ideale. Come Vergine, ricordi le preferenze, le date importanti, le piccole cose che fanno sentire l'altro visto e compreso. Questo talento oggi brillera' particolarmente, creando un momento di connessione profonda. Mercurio ti guida nel trasformare l'osservazione in un atto d'amore tangibile e indimenticabile.", advice: "Ricorda quel dettaglio menzionato tempo fa e agisci su di esso. La cura per i dettagli e' il linguaggio d'amore della Vergine." },
      { text: "Le stelle vedono guarigione emotiva nel tuo percorso sentimentale. Come Vergine, tendi a trattenere le ferite e ad analizzarle all'infinito, impedendo loro di guarire. Oggi Mercurio ti offre la lucidita' per perdonare e lasciare andare il peso del passato. Le cicatrici del cuore non sono difetti da nascondere ma prove di resilienza. La tua capacita' di ricostruire e' la forza segreta della terra.", advice: "Perdona il passato per accogliere il futuro a braccia aperte. La Vergine che si libera dal perfezionismo emotivo trova la pace." },
      { text: "Oggi la tua praticita' innata sara' la chiave per risolvere una questione sentimentale che sembrava un labirinto. Come Vergine, hai la rara capacita' di scomporre i problemi emotivi in parti gestibili e trovare soluzioni concrete. Mercurio potenzia la tua logica applicata al cuore, permettendoti di vedere con chiarezza dove gli altri vedono solo confusione. A volte l'amore ha bisogno di un piano, non solo di poesia.", advice: "A volte l'amore ha bisogno di organizzazione pratica. La Vergine che unisce cuore e metodo trova l'equilibrio perfetto." },
    ],
    libra: [
      { text: "Venere, tua splendida governatrice, danza oggi nel settore dei sentimenti portando armonia e bellezza in ogni tua relazione. Come Bilancia, sei il segno dell'equilibrio e della grazia, e oggi queste qualita' risplendono con una luce particolare. La tua capacita' naturale di creare connessioni armoniose e' al massimo. Ogni interazione sentimentale sara' avvolta da un'eleganza che solo il tuo segno d'aria sa offrire.", advice: "Cerca l'equilibrio perfetto tra dare e ricevere. La Bilancia che bilancia anche il cuore trova la serenita' duratura." },
      { text: "Le stelle vedono bellezza e grazia permeare ogni aspetto dei tuoi rapporti. Come segno governato da Venere, hai un senso estetico che si estende anche all'amore: cerchi la bellezza nelle relazioni come in un'opera d'arte. Oggi questa ricerca viene premiata con un momento di perfezione sentimentale. L'armonia che hai costruito con pazienza e diplomazia si manifesta in tutta la sua magnificenza.", advice: "L'eleganza del tuo cuore conquista sempre e in modo duraturo. La Bilancia non ha bisogno di gridare per farsi notare." },
      { text: "Una decisione sentimentale importante si avvicina e le stelle ti guidano verso la scelta piu' equilibrata. Come Bilancia, la tua famosa indecisione nasconde in realta' un desiderio profondo di giustizia e armonia. Venere ti offre oggi la chiarezza per capire cosa e' veramente importante per il tuo cuore. Non si tratta di scegliere il perfetto, ma di riconoscere cio' che porta pace alla tua anima.", advice: "Scegli cio' che porta pace e equilibrio al tuo cuore. La Bilancia che ascolta la propria armonia interiore non sbaglia mai." },
      { text: "Qualcuno desidera la tua compagnia e la tua luce venusiana molto piu' di quanto tu possa immaginare. Come Bilancia, a volte sottovaluti l'effetto che la tua presenza ha sugli altri: la tua gentilezza, il tuo sorriso diplomatico, la tua capacita' di far sentire tutti a proprio agio. Oggi questa persona trovera' il modo di fartelo sapere, e la rivelazione ti lascera' piacevolmente sorpreso e commosso.", advice: "Non sottovalutare mai il tuo fascino naturale. La grazia della Bilancia e' una forza silenziosa ma irresistibile." },
      { text: "Le costellazioni parlano di una partnership sentimentale alla pari, il tipo di relazione che il tuo segno desidera piu' di ogni altra cosa. Come Bilancia, hai bisogno di un rapporto dove il dare e il ricevere sono in perfetto equilibrio. Venere oggi porta sul tuo cammino la possibilita' di vivere esattamente questo tipo di connessione. Un rapporto tra due persone complete che scelgono di condividere le proprie vite.", advice: "L'amore migliore e' quello tra due persone intere che scelgono di stare insieme. La Bilancia lo sa: l'equilibrio nasce dalla completezza." },
      { text: "Un invito romantico potrebbe arrivare dalla direzione piu' inaspettata e sorprendente. Come segno d'aria governato da Venere, sei naturalmente aperto alle sorprese che il destino riserva. La tua capacita' di vedere il bello in ogni situazione oggi ti porta a scoprire romanticismo dove altri vedono solo quotidianita'. Accetta l'invito con la grazia che ti contraddistingue e lasciati trasportare dalla magia del momento.", advice: "Di' si' alle sorprese del destino con la fiducia della Bilancia. L'universo conosce il tuo senso estetico e ti mandera' qualcosa di bello." },
      { text: "Le stelle indicano che il tuo approccio diplomatico e gentile in amore sta dando frutti straordinari. Come Bilancia, non hai bisogno di forza bruta o drammi per conquistare: la tua arma e' la gentilezza raffinata. Venere amplifica questa qualita' oggi, rendendo ogni tuo gesto un capolavoro di eleganza sentimentale. Chi ti sta vicino si sente speciale semplicemente perche' tu sai come trattare le persone.", advice: "La gentilezza e' la via piu' breve verso qualsiasi cuore. La diplomazia venusiana della Bilancia e' un'arte che pochi padroneggiano." },
      { text: "Oggi le stelle ti invitano a guardare oltre la superficie delle cose, al di la' dell'apparenza estetica che tanto ami. Come Bilancia, la bellezza e' un valore fondamentale, ma l'amore piu' profondo vive in luoghi che l'occhio non raggiunge. Venere ti sussurra che la vera bellezza di una persona si nasconde nelle sue ferite guarite, nelle sue fragilita' accettate, nella sua autenticita' imperfetta.", advice: "La vera bellezza si nasconde nell'anima e nelle imperfezioni. La Bilancia che guarda oltre la superficie trova tesori inestimabili." },
      { text: "Un periodo di romanticismo puro e cristallino si apre davanti a te sotto la benedizione di Venere. Le stelle cospirano letteralmente a tuo favore, allineandosi per creare momenti di perfezione sentimentale. Come Bilancia, sei nel tuo elemento quando l'amore ha la grazia di una danza e la delicatezza di un sussurro. Lasciati trasportare da questa corrente venusiana senza resistere.", advice: "Lasciati trasportare dalla magia del momento. La Bilancia in amore e' come un fiore che si apre: naturale, elegante, irresistibile." },
      { text: "Venere ti sussurra oggi che l'amore che cerchi e' gia' nell'aria che respiri. Come segno d'aria, sei circondato da connessioni potenziali in ogni momento, ma oggi una di queste si distingue per la sua intensita' e autenticita'. Le stelle hanno preparato un incontro che rispecchia i tuoi valori piu' profondi: bellezza, armonia e reciprocita'. Apri i sensi e lascia che l'amore ti trovi.", advice: "Apri tutti i sensi alla bellezza sentimentale che ti circonda. La Bilancia che si fida del proprio cuore venusiano trova sempre la strada." },
    ],
    scorpio: [
      { text: "Plutone, tuo misterioso governatore, intensifica oggi le emozioni a un livello che solo il tuo segno d'acqua puo' sostenere. Come Scorpione, vivi l'amore come una trasformazione totale, un viaggio nelle profondita' dell'anima. Un legame sta per raggiungere un nuovo livello di intimita' che cambiera' per sempre la tua prospettiva. Le acque profonde del tuo cuore celano tesori che oggi verranno alla luce.", advice: "Non temere la profondita' dei tuoi sentimenti. Lo Scorpione che abbraccia la propria intensita' scopre l'amore nella sua forma piu' pura." },
      { text: "Le stelle vedono passione e mistero avvolgerti come un mantello di seta nera. Il tuo magnetismo scorpionico oggi e' assolutamente irresistibile, potenziato dal transito favorevole di Plutone. Chi ti incontra percepisce immediatamente la profondita' e l'intensita' che emani. Questo non e' fascino superficiale: e' il richiamo ancestrale di un'anima che conosce i segreti piu' profondi dell'amore e della trasformazione.", advice: "Usa il tuo magnetismo con saggezza e consapevolezza. Il potere dello Scorpione in amore e' immenso: gestiscilo con responsabilita'." },
      { text: "Un segreto sentimentale potrebbe venire alla luce oggi, rivelando verita' che cambiano le carte in tavola. Come Scorpione, sei il detective dello zodiaco: nulla sfugge alla tua percezione acuta. Plutone favorisce la trasparenza e la verita', anche quando fa male. Ma ricorda che la verita' e' sempre liberatoria, anche quando il primo impatto spaventa. Le acque profonde portano a galla cio' che deve essere visto.", advice: "La verita' libera sempre, anche quando fa paura. Lo Scorpione che sceglie la trasparenza costruisce legami indistruttibili." },
      { text: "La tua intensita' emotiva oggi attira anime coraggiose che non temono la tua profondita'. Come segno d'acqua governato da Plutone, non tutti possono sostenere il tuo sguardo penetrante e la tua richiesta di autenticita' totale. Ma oggi qualcuno si avvicina senza paura, pronto a immergersi nelle tue acque. Questa persona capisce che amare uno Scorpione significa accettare la trasformazione come stile di vita.", advice: "Accogli con gratitudine chi non teme la tua profondita'. Lo Scorpione merita un amore che sia coraggioso quanto il suo cuore." },
      { text: "Le costellazioni parlano di rinascita nel settore sentimentale del tuo cielo. Come Scorpione, la morte e rinascita sono il tuo ciclo naturale, anche in amore. Un capitolo si chiude per farne aprire uno infinitamente piu' luminoso. Plutone ti guida attraverso questa transizione con la certezza che cio' che muore lascia spazio a qualcosa di piu' vero. La fenice dentro di te e' pronta a volare.", advice: "Lascia andare il vecchio per accogliere il nuovo senza rimpianti. La rinascita e' il superpotere dello Scorpione: fidati del processo." },
      { text: "Un desiderio nascosto nel profondo della tua anima scorpionica sta per manifestarsi nella realta'. Plutone allinea le energie cosmiche per portare alla superficie cio' che hai tenuto segreto anche a te stesso. Come Scorpione, sei abituato a navigare le acque dell'inconscio, ma oggi queste acque ti portano un regalo. Cio' che hai desiderato intensamente sta trovando la via per raggiungerti.", advice: "Cio' che desideri intensamente si avvicina. L'universo risponde alla potenza emotiva dello Scorpione: credi nel tuo potere di manifestazione." },
      { text: "La lealta' feroce che offri in amore oggi sara' ricambiata con uguale intensita'. Come Scorpione, per te la fedelta' non e' una scelta ma un codice d'onore che guida ogni relazione. Plutone benedice questa devozione assoluta portando sulla tua strada chi condivide gli stessi valori profondi. Le stelle vedono un legame che si cementa nella reciproca certezza di poter contare l'uno sull'altro, sempre.", advice: "Chi merita la tua devozione assoluta lo dimostrera' con i fatti. Lo Scorpione riconosce la lealta' vera: non accettare imitazioni." },
      { text: "Oggi la tua intuizione sentimentale raggiunge livelli quasi soprannaturali sotto l'influenza di Plutone. Come Scorpione, percepisci le bugie, le mezze verita' e i sentimenti non dichiarati con una precisione che intimorisce. Ma oggi questo radar emotivo ti guida verso qualcosa di bellissimo: una verita' che conferma cio' che il tuo cuore gia' sapeva. Fidati di quella sensazione viscerale che non ti abbandona mai.", advice: "Il tuo istinto in amore e' infallibile. Lo Scorpione che segue le proprie sensazioni profonde non si perde mai." },
      { text: "Un'attrazione potente e quasi magnetica si manifesta oggi nella tua vita sentimentale. Come segno d'acqua governato da Plutone, le tue connessioni non sono mai superficiali: ogni incontro ha il potenziale di trasformarti. Oggi le stelle parlano di una chimica cosi' intensa da togliere il fiato, il tipo di attrazione che lo Scorpione cerca e che pochi segni possono offrire. Vivi questa intensita' con consapevolezza.", advice: "Vivi l'intensita' dell'attrazione con presenza e consapevolezza. Lo Scorpione sa che il fuoco piu' potente va gestito, non temuto." },
      { text: "Le stelle vedono una trasformazione profonda in corso nel tuo cuore scorpionico. L'amore ti sta cambiando in meglio, scavando oltre le difese che hai costruito con tanta cura. Plutone ti ricorda che ogni muro abbattuto e' un passo verso la liberta' emotiva. Come Scorpione, la tua forza non sta nel proteggere il cuore ma nel avere il coraggio di esporlo. La vulnerabilita' e' il tuo prossimo livello di potere.", advice: "Accetta di evolvere attraverso l'amore senza resistere. Lo Scorpione che si trasforma e' la versione piu' potente di se stesso." },
    ],
    sagittarius: [
      { text: "Giove, il tuo magnifico governatore, espande oggi gli orizzonti del tuo cuore avventuroso. Come Sagittario, l'amore per te deve avere il sapore della scoperta e il profumo di terre lontane. Le stelle vedono una connessione che arriva da una direzione inaspettata, forse legata a un viaggio o a un incontro con qualcuno di una cultura diversa dalla tua. Il tuo cuore nomade sta per trovare un compagno di viaggio.", advice: "Tieni il cuore aperto alle culture e prospettive diverse. Il Sagittario trova l'amore la' dove il mondo si allarga." },
      { text: "Le stelle vedono un'avventura sentimentale emozionante profilarsi all'orizzonte del tuo cielo. Come segno di fuoco governato da Giove, hai bisogno di emozione e crescita costante nelle relazioni. L'amore per un Sagittario non puo' mai essere statico: deve essere un viaggio continuo alla scoperta dell'altro. Oggi le costellazioni ti offrono esattamente questo: un'esperienza che espande il cuore e la mente.", advice: "L'amore e' il viaggio piu' bello che puoi intraprendere. Il Sagittario che vive le relazioni come avventure non si annoia mai." },
      { text: "La tua liberta' e' sacra come Sagittario, ma oggi le stelle ti mostrano che condividerla con qualcuno non la diminuisce, la moltiplica. Giove insegna l'abbondanza, e in amore questo significa che donare non ti svuota. La persona giusta per te e' quella che corre accanto a te, non quella che ti chiede di fermarti. Cerca chi ha le tue stesse ali, non chi vuole tagliartele.", advice: "Non confondere la compagnia con la prigione. Il Sagittario libero in coppia ha trovato il vero amore." },
      { text: "Un incontro filosofico profondo potrebbe accendere una fiamma che va ben oltre l'intelletto. Come Sagittario, sei attratto dalle menti che sanno vedere il quadro grande, che parlano di senso della vita e di avventure dello spirito. Giove porta oggi sulla tua strada qualcuno che condivide la tua sete di significato. Le conversazioni che ne nasceranno saranno il preludio di un legame che tocca l'anima.", advice: "Le menti affini creano i legami piu' forti e duraturi. Il Sagittario si innamora prima della mente e poi di tutto il resto." },
      { text: "L'ottimismo contagioso che caratterizza il tuo segno oggi diventa un'arma irresistibile in amore. Come Sagittario, il tuo sorriso illumina qualsiasi stanza e il tuo entusiasmo per la vita e' una calamita per chi cerca gioia autentica. Giove amplifica questa energia positiva, rendendoti un faro per le anime in cerca di luce. Chi ti incontra oggi portera' con se' il ricordo del tuo calore per molto tempo.", advice: "L'entusiasmo sagittariano e' contagioso e magnetico. Non trattenerlo: il tuo modo di vivere con gioia e' il tuo regalo al mondo." },
      { text: "Qualcuno condivide la tua identica sete di avventura e le stelle vi stanno guidando nella stessa direzione. Come Sagittario, il compagno ideale non e' chi ti aspetta a casa ma chi parte con te. Giove oggi crea le condizioni perfette per incontrare o riconoscere questa anima affine. La freccia del tuo arco sta puntando verso un orizzonte che include qualcuno di speciale accanto a te.", advice: "Cercate insieme nuovi orizzonti da esplorare. Il Sagittario in coppia che viaggia e cresce non conosce limiti." },
      { text: "Giove, il pianeta della fortuna, oggi porta benedizioni speciali nel settore dell'amore. Come Sagittario, sei naturalmente fortunato in amore perche' il tuo approccio sincero e diretto disarma qualsiasi difesa. Oggi questa fortuna si manifesta in modo particolarmente tangibile. Un'opportunita' sentimentale si presenta: potrebbe essere un nuovo incontro o la riscoperta di qualcuno che gia' conosci sotto una luce nuova.", advice: "La fortuna favorisce gli audaci e tu sei il piu' audace dello zodiaco. Osa un po' piu' del solito, Giove ti copre le spalle." },
      { text: "Le stelle parlano di sincerita' e trasparenza come fondamenta del tuo prossimo capitolo sentimentale. Come Sagittario, la tua onesta' a volte puo' sembrare brutale, ma e' esattamente cio' che il mondo ha bisogno. Giove premia chi dice la verita' con il cuore, e oggi la tua franchise' sara' apprezzata come mai prima. La persona giusta per te non vuole belle bugie ma verita' dette con amore.", advice: "Di' sempre la verita', anche quando e' scomoda. L'onesta' del Sagittario e' rara e preziosa in un mondo di maschere." },
      { text: "Un'esperienza condivisa con qualcuno di speciale rafforza un legame in modo indissolubile. Come Sagittario, credi che i ricordi insieme siano il cemento piu' forte di qualsiasi relazione, e hai ragione. Giove favorisce oggi la creazione di momenti indimenticabili. Pianifica qualcosa di speciale: un'avventura, un viaggio, una nuova esperienza. E' nei momenti straordinari che l'amore si rivela nella sua essenza.", advice: "I ricordi condivisi sono tesori inestimabili. Il Sagittario che crea avventure insieme costruisce un amore che dura per sempre." },
      { text: "Le stelle vedono crescita reciproca come tema dominante del tuo periodo sentimentale. Come Sagittario, non puoi amare qualcuno che ti limita o ti chiede di ridimensionare i tuoi sogni. Giove conferma che la relazione giusta e' quella che ti rende una versione migliore di te stesso. L'amore vero per il tuo segno e' un'espansione, mai una contrazione. Cerca chi ti ispira a diventare la freccia che vola piu' lontano.", advice: "Scegli chi ti ispira a crescere e a volare piu' in alto. Il Sagittario innamorato diventa la versione migliore di se stesso." },
    ],
    capricorn: [
      { text: "Saturno, il tuo saggio governatore, oggi benedice i rapporti costruiti con pazienza e impegno autentico. Come Capricorno, credi che l'amore vero si costruisca nel tempo, con dedizione e responsabilita'. Le stelle confermano che la solidita' che hai creato nelle tue relazioni non e' ordinaria: e' straordinaria. Mentre altri cercano emozioni passeggere, tu stai edificando qualcosa che resistera' a qualsiasi tempesta.", advice: "Le fondamenta che hai costruito con pazienza reggono qualsiasi tempesta. Il Capricorno in amore e' un architetto di legami eterni." },
      { text: "Le stelle vedono ambizione anche nel campo sentimentale, e per un Capricorno questo non e' un difetto ma una virtu'. Come segno di terra governato da Saturno, punti in alto in ogni aspetto della vita, amore compreso. Oggi le costellazioni ti incoraggiano a non accontentarti di un amore tiepido o conveniente. Meriti una passione che sia all'altezza della tua determinazione e della montagna che stai scalando.", advice: "Non accontentarti di un amore mediocre che non ti ispira. Il Capricorno merita una vetta sentimentale all'altezza delle sue ambizioni." },
      { text: "La tua determinazione incrollabile oggi attira chi cerca un porto sicuro nella tempesta della vita. Come Capricorno, sei la roccia su cui gli altri costruiscono, il pilastro che non vacilla. Saturno amplifica questa qualita', rendendoti ancora piu' affidabile e desiderabile. Qualcuno si sta rendendo conto che la tua stabilita' non e' noia ma sicurezza, non e' rigidita' ma costanza. E ne e' profondamente innamorato.", advice: "La tua affidabilita' e' il dono sentimentale piu' prezioso. Il Capricorno che resta saldo nelle difficolta' conquista cuori per sempre." },
      { text: "Un traguardo sentimentale importante si avvicina dopo un cammino di pazienza saturniana. Come Capricorno, sei abituato a lavorare duro per ottenere risultati, e in amore non e' diverso. Le stelle premiano oggi la tua costanza con un momento di gioia profonda. Cio' che hai costruito con impegno e dedizione sta raggiungendo la maturita': come un frutto che finalmente e' pronto per essere colto e assaporato.", advice: "Le cose migliori arrivano a chi sa aspettare con dignita'. La pazienza del Capricorno e' la strategia piu' vincente in amore." },
      { text: "Le costellazioni indicano che e' tempo di abbassare quelle difese saturniane che proteggono il tuo cuore. Come Capricorno, hai costruito mura alte e solide intorno alle tue emozioni per proteggerti dal dolore. Ma oggi Saturno ti ricorda che la vera forza non sta nel muro, ma nel coraggio di aprire il cancello. Mostrare fragilita' a chi ami non e' debolezza: e' il piu' grande atto di fiducia che puoi offrire.", advice: "Mostrare fragilita' richiede piu' coraggio di qualsiasi impresa. Il Capricorno che apre il cuore scopre la liberta' vera." },
      { text: "Qualcuno rispetta profondamente la tua integrita' e il tuo senso dell'onore in amore. Come Capricorno, la tua parola vale oro e le tue promesse sono sacre. Saturno ti ha insegnato che il rispetto e' la base di ogni relazione duratura, e oggi questa lezione porta i suoi frutti. La persona giusta per te non e' chi ti fa battere il cuore piu' forte, ma chi ti fa sentire rispettato e valorizzato ogni giorno.", advice: "Il rispetto reciproco e' la valuta dell'amore vero. Il Capricorno che viene rispettato ha trovato la sua persona." },
      { text: "Le stelle parlano di un amore che cresce lentamente ma con una forza inarrestabile, esattamente come piace al tuo segno. Come Capricorno, diffidi delle passioni fulminanti che bruciano in fretta. Saturno benedice le storie che maturano nel tempo, che si approfondiscono con ogni stagione condivisa. Questo approccio paziente all'amore e' la tua saggezza piu' grande. Non lasciare che nessuno ti faccia sentire sbagliato per questo.", advice: "La costanza batte sempre l'intensita' fugace. Il Capricorno che ama con metodo costruisce un impero sentimentale." },
      { text: "Un momento di tenerezza inaspettata penetrera' oggi oltre le tue difese saturniane. Come Capricorno, raramente ti lasci sorprendere dalle emozioni, ma oggi qualcosa o qualcuno riuscira' a toccare quel punto morbido che nascondi con tanta cura. Non resistere a questa dolcezza imprevista: anche la montagna piu' alta ha vallate fiorite. Saturno ti concede il permesso di commuoverti senza vergogna.", advice: "Lasciati sorprendere dalla tenerezza senza opporre resistenza. Anche il Capricorno piu' stoico merita momenti di pura dolcezza." },
      { text: "Saturno ti ricorda oggi che l'amore e' anche responsabilita', cura costante e impegno quotidiano. Come Capricorno, non fuggi da queste parole come altri segni farebbero: le abbracci come parte della tua natura. Prendersi cura di qualcuno e' per te un privilegio, non un peso. Le stelle vedono questa maturita' emotiva brillare con una luce che attira chi cerca un amore adulto, serio e profondamente reale.", advice: "Prendersi cura di qualcuno e' un privilegio riservato ai cuori forti. Il Capricorno che ama con responsabilita' ama nel modo piu' nobile." },
      { text: "Le stelle vedono un futuro sentimentale stabile e luminoso costruito sulla roccia della tua dedizione. Come Capricorno, ogni relazione che intraprendi e' un progetto a lungo termine, un investimento emotivo che gestisci con la stessa serieta' di un investimento finanziario. Saturno oggi conferma che i rendimenti stanno arrivando. Stai costruendo qualcosa di raro nel mondo moderno: un amore che resiste al tempo.", advice: "Stai costruendo qualcosa di duraturo e prezioso. Il Capricorno in amore pensa in decenni, non in settimane: questa e' la tua grandezza." },
    ],
    aquarius: [
      { text: "Urano, il tuo rivoluzionario governatore, porta oggi sorprese elettrizzanti nel settore dell'amore. Come Acquario, il tuo modo di vivere i sentimenti e' unico e anticonvenzionale, e le stelle premiano questa originalita'. Qualcosa di completamente inaspettato sta per scuotere la tua routine sentimentale in modo positivo. L'amore per il tuo segno d'aria non segue mai copioni prevedibili, e oggi ne avrai la conferma.", advice: "Accogli l'insolito con la curiosita' che ti contraddistingue. L'Acquario che abbraccia l'imprevisto trova l'amore piu' autentico." },
      { text: "Le stelle vedono una connessione unica e irripetibile che rispecchia la tua natura fuori dal comune. Come Acquario, il tuo modo di amare sfida le convenzioni e riscrive le regole. Urano amplifica questa energia rivoluzionaria, portando nella tua vita qualcuno che apprezza la tua diversita' come un tesoro. Non conformarti mai alle aspettative altrui su come dovresti amare: il tuo modo e' valido e prezioso.", advice: "Non conformarti mai in amore. L'Acquario che resta fedele alla propria unicita' attira connessioni altrettanto straordinarie." },
      { text: "Un'amicizia potrebbe trasformarsi in qualcosa di molto piu' profondo sotto l'influenza di Urano. Come Acquario, le tue storie d'amore piu' significative sono spesso nate dalla complicita' amicale. Il tuo segno d'aria ha bisogno prima di tutto di una connessione intellettuale e di valori condivisi, e queste basi si costruiscono meglio nell'amicizia. Guarda con occhi nuovi chi ti e' gia' vicino.", advice: "Le migliori storie d'amore nascono dall'amicizia vera. L'Acquario che si innamora del migliore amico trova il partner perfetto." },
      { text: "La tua indipendenza magnetica affascina profondamente chi ha il coraggio di avvicinarsi. Come Acquario, emani un'aura di liberta' e autenticita' che e' irresistibile per le anime evolute. Urano oggi potenzia questa qualita', facendo di te un magnete per chi cerca una relazione che non sia una gabbia dorata. Qualcuno ammira il fatto che tu non abbia bisogno di nessuno, eppure scelga di condividere.", advice: "Resta fedele alla tua essenza indipendente. L'Acquario che non ha bisogno ma sceglie di amare offre l'amore piu' libero." },
      { text: "Le costellazioni parlano di liberta' condivisa come fondamento del tuo ideale d'amore. Come Acquario, credi che l'amore non debba mai essere una gabbia ma uno spazio infinito dove due liberta' si incontrano e si arricchiscono. Urano conferma che questa visione non e' utopica ma profondamente saggia. La relazione che cerchi esiste: e' quella dove entrambi volano e scelgono di volare nella stessa direzione.", advice: "Ama senza possedere e sarai amato senza catene. L'Acquario insegna al mondo che l'amore vero e' liberta' condivisa." },
      { text: "Un'idea brillante e originale per sorprendere chi ami ti illuminera' la mente oggi. Come Acquario, la tua creativita' in amore e' leggendaria: non fai mai la cosa ovvia. Urano stimola oggi la tua inventiva sentimentale, spingendoti verso gesti che lasciano il segno nella memoria. Un regalo unico, un'esperienza fuori dall'ordinario, una sorpresa che nessun altro potrebbe concepire: questo e' amare alla maniera dell'Acquario.", advice: "L'originalita' nei gesti d'amore e' la tua firma inconfondibile. L'Acquario che sorprende con creativita' e' impossibile da dimenticare." },
      { text: "Urano stimola conversazioni profonde e rivoluzionarie con chi ti sta a cuore. Come Acquario, hai bisogno di dialoghi che vadano oltre la superficie, che esplorino idee, valori e visioni del mondo. Oggi le stelle portano esattamente questo tipo di scambio nella tua vita sentimentale. Una conversazione che inizia come dibattito potrebbe finire come la dichiarazione d'amore piu' originale mai fatta dal tuo segno d'aria.", advice: "Le parole che scambi oggi hanno il potere di trasformare una relazione. L'Acquario comunica in modo unico: questa e' la sua magia." },
      { text: "Le stelle vedono un'evoluzione significativa nei tuoi sentimenti, una maturazione emotiva rara per il tuo segno. Come Acquario, a volte tendi a vivere l'amore piu' con la testa che con il cuore, mantenendo una distanza di sicurezza. Urano oggi abbatte questa barriera invisibile, permettendoti di sentire con una profondita' che ti sorprendera'. Non temere questa vulnerabilita': e' la porta verso la versione piu' completa di te.", advice: "La crescita emotiva e' il viaggio piu' coraggioso. L'Acquario che impara a sentire profondamente raggiunge il suo pieno potenziale." },
      { text: "Qualcuno condivide i tuoi ideali e la tua visione di un mondo migliore. Come Acquario, hai bisogno di un partner che sia anche un compagno di causa, qualcuno che creda nei tuoi sogni di cambiamento. Urano porta oggi sulla tua strada un'anima affine con cui non solo condividi l'attrazione ma anche la missione. L'amore per il tuo segno e' piu' forte quando ha uno scopo che va oltre la coppia.", advice: "L'amore piu' forte per un Acquario e' quello che ha una missione condivisa. Cerca chi sogna lo stesso futuro che sogni tu." },
      { text: "Le stelle indicano un periodo di rara apertura emotiva per il tuo segno d'aria. Urano scioglie le resistenze che normalmente tieni come scudo protettivo. Come Acquario, la tua mente brillante a volte sovrasta il cuore, ma oggi i due sono in perfetto equilibrio. Approfittane per mostrare il lato tenero che pochi conoscono, quello che si nasconde dietro l'intelletto e l'indipendenza. Sara' un regalo per te e per chi ami.", advice: "Mostrare il cuore non ti rende debole ma completo. L'Acquario che bilancia mente e cuore diventa inarrestabile in amore." },
    ],
    pisces: [
      { text: "Nettuno, il tuo sognante governatore, avvolge oggi i tuoi sentimenti in un velo di pura magia cosmica. Come Pesci, vivi l'amore come un'esperienza mistica che trascende il mondo materiale. La tua sensibilita' e' un dono che pochissimi possiedono: la capacita' di sentire le emozioni degli altri come fossero tue. Oggi questa connessione empatica raggiunge livelli straordinari, rendendo possibile l'impossibile in amore.", advice: "L'amore che sogni a occhi aperti puo' diventare realta'. Il Pesci che crede nella magia dell'amore la attrae naturalmente." },
      { text: "Le stelle vedono romanticismo nella sua forma piu' pura e cristallina per il tuo segno d'acqua. Come Pesci, la tua sensibilita' e' un dono raro in un mondo che spesso la confonde con fragilita'. Nettuno amplifica la tua capacita' di amare con una profondita' oceanica, senza condizioni e senza limiti. Non vergognarti mai di sentire troppo: in un mondo che sente troppo poco, tu sei il rimedio.", advice: "Non vergognarti mai di sentire troppo e troppo profondamente. La sensibilita' del Pesci e' la medicina di cui il mondo ha bisogno." },
      { text: "Un sogno ricorrente nasconde un messaggio importante dal tuo inconscio riguardo alla tua vita sentimentale. Come Pesci, i tuoi sogni sono portali verso verita' che la mente cosciente non riesce a cogliere. Nettuno comunica con te attraverso simboli, intuizioni e sensazioni che emergono durante il sonno. Presta attenzione a quei sogni vividi: contengono la chiave per comprendere il prossimo passo del tuo cuore.", advice: "L'inconscio nettuniano sa cose che la mente razionale ignora. Il Pesci che ascolta i propri sogni trova risposte preziose." },
      { text: "La tua empatia sconfinata oggi attira anime in cerca di comprensione autentica. Come Pesci, sei lo psicologo naturale dello zodiaco, capace di capire gli altri a un livello che rasenta il soprannaturale. Qualcuno si avvicinera' a te per questa qualita' unica, e la connessione che ne nascera' potrebbe andare ben oltre la semplice amicizia. Ma ricorda di proteggere la tua energia: dare troppo senza ricevere ti svuota.", advice: "Offri il tuo cuore empatico ma proteggi la tua energia. Il Pesci che impara a dire no quando serve ama meglio quando dice si'." },
      { text: "Le costellazioni parlano di un amore che va oltre la superficie e tocca la dimensione spirituale dell'anima. Come Pesci, non ti accontenti di connessioni superficiali: hai bisogno di sentire l'anima dell'altro vibrare in armonia con la tua. Nettuno favorisce oggi incontri che avvengono a questo livello profondo, dove le parole diventano superflue e i cuori comunicano in un linguaggio antico e universale.", advice: "La connessione spirituale e' il livello piu' alto d'amore. Il Pesci che trova un'anima gemella ha trovato la casa dell'anima." },
      { text: "Un gesto poetico e creativo conquisterai oggi chi ami. Come Pesci, l'arte e' il tuo linguaggio d'amore naturale: una poesia, una canzone, un disegno valgono piu' di qualsiasi regalo materiale. Nettuno ispira la tua creativita' sentimentale, guidando le tue mani e le tue parole verso espressioni di bellezza pura. L'amore per il tuo segno si esprime meglio quando diventa arte, e oggi sarai un artista del cuore.", advice: "L'amore si esprime magnificamente attraverso la creativita'. Il Pesci che trasforma i sentimenti in arte regala bellezza eterna." },
      { text: "Nettuno dissolve oggi i confini invisibili tra te e chi ami, creando un'intimita' che va oltre il fisico. Come Pesci, aspiri a quella fusione emotiva totale che altri segni troverebbero travolgente ma che per te e' ossigeno. Le stelle favoriscono una connessione profondissima, quasi telepatica, con qualcuno di speciale. Questo tipo di unione, rara e preziosa, e' il dono che Nettuno riserva ai suoi figli piu' sensibili.", advice: "Lasciati andare alla fusione emotiva che cerchi. Il Pesci che si unisce a un'anima affine crea qualcosa di trascendente." },
      { text: "Le stelle vedono guarigione profonda attraverso l'amore, il tema piu' potente per il tuo segno d'acqua. Come Pesci, credi che l'amore sia la medicina universale, e oggi Nettuno conferma questa verita'. Chi ti ama ha il potere di guarire ferite che credevi permanenti, e tu hai lo stesso potere nei confronti dell'altro. Questa reciprocita' terapeutica e' uno dei doni piu' belli che il cosmo offre al tuo segno.", advice: "Accetta l'amore come medicina dell'anima senza vergogna. Il Pesci che si lascia guarire puo' poi guarire il mondo intero." },
      { text: "La tua intuizione nettuniana ti guida con certezza verso la persona giusta al momento giusto. Come Pesci, non hai bisogno di app di dating o strategie: il tuo cuore ha un GPS emotivo infallibile. Oggi questa bussola interiore e' particolarmente precisa, guidandoti attraverso le correnti della vita verso un incontro significativo. Non forzare nulla: il flusso cosmico sa esattamente dove portarti.", advice: "Segui il flusso senza forzare nulla. Il Pesci che si fida del proprio GPS emotivo arriva sempre a destinazione." },
      { text: "Un periodo di sogni a occhi aperti porta oggi ispirazione sentimentale preziosa per il tuo segno. Come Pesci, la tua immaginazione e' un portale verso possibilita' che la logica non riesce a concepire. Nettuno alimenta oggi le visioni del tuo cuore con immagini di un amore che sembra troppo bello per essere vero. Ma per il tuo segno, la linea tra sogno e realta' e' sottilissima, e oggi potrebbe dissolversi.", advice: "I sogni a occhi aperti sono la mappa del tuo cuore. Il Pesci che segue le proprie visioni d'amore le trasforma in realta'." },
    ],
  },
  work: {
    aries: [
      { text: "Marte carica di energia esplosiva il tuo settore professionale, rendendoti una forza inarrestabile. Come Ariete, sei nato per guidare e oggi la tua naturale capacita' di leadership brilla con intensita' particolare. Un progetto importante sta per decollare grazie alla tua iniziativa e al tuo coraggio di agire quando altri esitano. Le stelle vedono vittoria per chi, come te, non ha paura di fare il primo passo.", advice: "Prendi l'iniziativa senza esitare: il tuo istinto marziano sa gia' la strada. L'Ariete che agisce per primo vince sempre." },
      { text: "Le stelle vedono una sfida professionale che sembra fatta apposta per il tuo spirito combattivo. Come Ariete governato da Marte, gli ostacoli non ti spaventano: ti eccitano. Oggi la tua determinazione e la tua energia di fuoco ti porteranno a superare un limite che credevi invalicabile. La tua capacita' di trasformare la pressione in carburante e' il segreto del tuo successo.", advice: "Affronta l'ostacolo a testa alta con la grinta del guerriero. L'Ariete che non indietreggia mai e' destinato alla vittoria." },
      { text: "Un'opportunita' professionale inaspettata richiede una decisione rapida e coraggiosa. Come Ariete, sei il segno piu' veloce dello zodiaco nel cogliere le occasioni, e oggi Marte amplifica questo tuo talento. Mentre altri analizzano e ponderano, tu agisci con l'istinto infallibile del leader nato. Le stelle favoriscono chi osa, e nessuno nello zodiaco osa quanto un Ariete motivato.", advice: "Chi esita perde e tu non sei nato per esitare. L'Ariete agisce con la velocita' del fulmine e la precisione del guerriero." },
      { text: "Le costellazioni indicano un periodo di grande produttivita' alimentata dal fuoco di Marte. La tua energia oggi sembra inesauribile, e ogni compito che affronti viene completato con una rapidita' che stupisce chi ti circonda. Come Ariete, la tua capacita' di mantenere un ritmo frenetico e' leggendaria. Sfrutta questa giornata al massimo per avanzare nei progetti che ti stanno piu' a cuore.", advice: "Canalizza l'energia marziana in obiettivi concreti e misurabili. L'Ariete focalizzato e' la forza piu' produttiva dello zodiaco." },
      { text: "Il tuo spirito competitivo oggi e' un motore potentissimo che ti spinge verso traguardi ambiziosi. Come Ariete, la competizione non e' stress ma stimolo, non e' ansia ma adrenalina. Marte alimenta questa fiamma interiore che ti rende sempre il primo ad arrivare. Ma oggi le stelle ti ricordano che la vittoria piu' grande e' quella contro i tuoi limiti, non contro gli altri.", advice: "Competi con la versione di ieri di te stesso. L'Ariete che supera i propri limiti raggiunge vette che nessuno credeva possibili." },
      { text: "Le stelle parlano di un riconoscimento professionale meritato che sta per arrivare. Come Ariete, a volte la tua impazienza ti fa dubitare che il lavoro duro venga notato, ma Marte garantisce che chi agisce con coraggio prima o poi viene premiato. Il tuo contributo unico, fatto di iniziativa e audacia, non e' passato inosservato. Preparati a ricevere l'apprezzamento che la tua energia di fuoco merita.", advice: "Continua con la stessa determinazione: il premio sta arrivando. L'Ariete costante viene sempre ricompensato dal cosmo." },
      { text: "Un'idea innovativa e audace potrebbe cambiare la direzione della tua carriera in modo significativo. Come Ariete, sei il pioniere dello zodiaco: vedi opportunita' dove altri vedono solo terreno inesplorato. Marte ti dona oggi l'audacia di proporre qualcosa che nessuno ha mai osato. Non aver paura di essere il primo: il sentiero che crei sara' quello che altri seguiranno.", advice: "Non aver paura di proporre qualcosa di radicalmente nuovo. L'Ariete che innova con coraggio lascia un segno indelebile." },
      { text: "Marte ti rende inarrestabile oggi sul fronte professionale, con un'energia che sembra provenire direttamente dalle stelle. Come Ariete, hai la rara capacita' di trasformare l'entusiasmo in risultati concreti in tempi record. Nessun ostacolo e' abbastanza grande da fermare un Ariete determinato, e oggi sei piu' determinato che mai. Il fuoco che ti governa arde con una potenza che apre ogni porta.", advice: "Usa questa determinazione straordinaria per avanzare sui fronti piu' importanti. L'Ariete in stato di grazia non conosce limiti." },
      { text: "Le stelle vedono un traguardo professionale vicinissimo dopo un percorso impegnativo. Come Ariete, hai la resistenza del guerriero che sa che l'ultimo miglio e' il piu' duro ma anche il piu' importante. Marte ti dona la forza per questo sprint finale, alimentando il fuoco della tua ambizione con energia cosmica. Non mollare proprio adesso: la linea del traguardo e' a un passo e la vittoria e' tua.", advice: "Non mollare proprio ora che sei cosi' vicino alla meta. L'Ariete che persevera nell'ultimo sforzo conquista la gloria." },
      { text: "Oggi Marte allinea la tua energia con le opportunita' cosmiche in modo perfetto. Come Ariete, sei sempre pronto all'azione, ma oggi questa prontezza incontra il momento ideale. Un'idea che hai avuto tempo fa potrebbe trovare finalmente il terreno fertile per germogliare. Le stelle favoriscono i nuovi inizi professionali, e nessun segno inizia meglio di un Ariete con il fuoco negli occhi.", advice: "Il tempismo oggi e' perfetto per lanciare quell'iniziativa. L'Ariete che coglie il momento cosmico giusto e' imbattibile." },
    ],
    taurus: [
      { text: "La tua perseveranza taurina sta per dare frutti concreti e misurabili nel settore professionale. Come Toro governato da Venere, unisci senso pratico e gusto estetico in modo unico nel mondo del lavoro. Le stelle vedono stabilita' finanziaria crescente come ricompensa per la tua dedizione instancabile. Mentre altri saltano da un progetto all'altro, tu hai costruito con pazienza qualcosa di solido e duraturo.", advice: "Continua a costruire mattone dopo mattone con la pazienza del Toro. La costanza e' la strategia piu' vincente nel lungo periodo." },
      { text: "Un investimento professionale fatto con la saggezza tipica del tuo segno di terra sta per mostrare risultati tangibili. Come Toro, non ti fai abbagliare dalle promesse vuote: vuoi vedere i numeri, toccare i risultati con mano. Venere e Saturno collaborano per portarti una soddisfazione concreta nel campo finanziario. La tua capacita' di valutare rischi e opportunita' con senso pratico oggi e' premiata.", advice: "La pazienza e' la migliore strategia finanziaria e tu la possiedi naturalmente. Il Toro che investe con saggezza raccoglie abbondanza." },
      { text: "Le stelle indicano che la qualita' impeccabile del tuo lavoro verra' finalmente riconosciuta da chi conta. Come Toro, non ti accontenti del mediocre: ogni tuo progetto porta il marchio della cura meticolosa. Venere ti dona un senso estetico che si riflette in tutto cio' che produci, rendendo il tuo lavoro non solo funzionale ma anche bello. Questa attenzione alla qualita' oggi si trasforma in riconoscimento professionale.", advice: "Non scendere mai a compromessi sulla qualita'. Il Toro che mantiene i suoi standard altissimi si distingue dalla massa." },
      { text: "Un progetto a lungo termine a cui hai dedicato mesi di lavoro paziente si avvicina finalmente al traguardo. Come segno di terra, il Toro eccelle nei progetti che richiedono costanza, dedizione e visione a lungo termine. Le stelle vedono soddisfazione profonda per un risultato costruito con le tue mani. Questo non e' un successo nato dal caso ma dalla tua abilita' di perseverare quando altri avrebbero mollato.", advice: "Le fondamenta solide che hai costruito reggono grattacieli. Il Toro che completa un progetto con pazienza crea capolavori." },
      { text: "Le costellazioni parlano di una crescita professionale graduale ma inesorabile, perfettamente in linea con il tuo temperamento. Come Toro, non cerchi la fama istantanea ma il successo duraturo che si costruisce nel tempo. Venere e Saturno oggi confermano che ogni piccolo passo che hai fatto ti ha avvicinato alla vetta. La tua carriera e' come una quercia: cresce lentamente ma diventa indistruttibile.", advice: "Ogni piccolo passo conta enormemente nel lungo periodo. Il Toro che non si ferma mai arriva sempre piu' lontano degli altri." },
      { text: "Venere porta oggi armonia e positiva nell'ambiente lavorativo, creando relazioni professionali solide. Come Toro, il tuo modo calmo e affidabile di lavorare crea un'atmosfera di fiducia intorno a te. I colleghi e i superiori si sentono a proprio agio in tua presenza perche' emani stabilita'. Questo clima positivo oggi porta collaborazioni fruttuose e opportunita' che nascono dalla stima reciproca.", advice: "Un buon clima lavorativo moltiplica i risultati. Il Toro che coltiva relazioni professionali positive raccoglie alleati preziosi." },
      { text: "Le stelle vedono sicurezza economica in aumento grazie alla tua gestione oculata delle risorse. Come Toro, hai un rapporto naturale con il denaro e i beni materiali che altri segni invidiano. Venere ti dona l'istinto per gli affari e la capacita' di far fruttare ogni investimento. Oggi questo talento si manifesta in una notizia o un'opportunita' che rafforza la tua posizione finanziaria in modo significativo.", advice: "Gestisci con saggezza le risorse che arrivano. L'istinto finanziario del Toro e' uno dei piu' acuti dello zodiaco." },
      { text: "La tua affidabilita' leggendaria oggi si rivela essere la moneta piu' preziosa nel tuo ambiente professionale. Come Toro, quando prometti qualcosa, la consegni. Questa qualita', sempre piu' rara nel mondo del lavoro, ti distingue nettamente dalla massa. Chi si fida di te ti affida compiti sempre piu' importanti, e oggi questa fiducia si traduce in un'opportunita' di responsabilita' e crescita.", advice: "Chi si fida di te ti affida le responsabilita' piu' importanti. L'affidabilita' del Toro e' il biglietto da visita piu' potente." },
      { text: "Un'opportunita' concreta e tangibile si presenta nel tuo percorso professionale. Come Toro, la valuti con la prudenza che ti caratterizza, soppesando pro e contro con il tuo senso pratico infallibile. Venere favorisce decisioni ponderate ma decisive. Non lasciare che la tua naturale cautela si trasformi in immobilismo: a volte anche il Toro deve fare un salto di fede, pur mantenendo i piedi vicini alla terra.", advice: "Valuta con la tua prudenza naturale ma non tardare troppo a decidere. Il Toro che bilancia cautela e azione coglie le migliori opportunita'." },
      { text: "Le stelle parlano di abbondanza in arrivo come ricompensa per il tuo impegno costante e silenzioso. Come Toro, non cerchi applausi ma risultati, non vuoi riflettori ma solidita'. Venere benedice questo approccio discreto ma efficace, portando frutti maturi nel tuo settore professionale. Raccogli con orgoglio e gratitudine cio' che hai seminato con tanta cura: e' il momento del raccolto per il tuo segno.", advice: "Raccogli cio' che hai seminato con la fierezza del Toro. L'abbondanza che arriva e' il frutto del tuo lavoro instancabile." },
    ],
    gemini: [
      { text: "Mercurio stimola oggi la tua comunicazione professionale a livelli brillanti. Come Gemelli, le tue idee hanno la velocita' del vento e la luminosita' di una stella. In una riunione, una presentazione o anche in una semplice email, le tue parole oggi hanno un impatto straordinario. La tua mente d'aria elabora soluzioni creative che colleghi e superiori troveranno geniali e rinfrescanti.", advice: "Condividi le tue idee con la sicurezza del comunicatore nato. Le intuizioni dei Gemelli oggi valgono oro: non tenerle per te." },
      { text: "Le stelle vedono multitasking efficace e gestione fluida di piu' progetti simultanei. Come Gemelli, la tua mente e' progettata per gestire la complessita' con un'agilita' che altri trovano disumana. Mercurio potenzia questa capacita' oggi, permettendoti di passare da un compito all'altro senza perdere un colpo. La tua versatilita' e' il tuo superpotere professionale, e oggi risplende al massimo.", advice: "La versatilita' mercuriana e' il tuo vantaggio competitivo unico. Sfruttala al massimo oggi per avanzare su tutti i fronti." },
      { text: "Una conversazione professionale chiave potrebbe aprire porte che non sapevi nemmeno esistessero. Come Gemelli governato da Mercurio, sai che le parole giuste dette alla persona giusta nel momento giusto possono cambiare tutto. Oggi le stelle allineano questi tre fattori in modo perfetto. Preparati bene per quel meeting o quella telefonata: potrebbe essere il punto di svolta della tua carriera.", advice: "Prepara bene le tue parole per quella conversazione importante. Il Gemelli che comunica con strategia ottiene risultati straordinari." },
      { text: "Le costellazioni indicano networking professionale straordinariamente produttivo. Come segno d'aria, sei il connettore naturale dello zodiaco: metti in contatto persone, idee e opportunita' con una facilita' che lascia tutti stupiti. Mercurio amplifica oggi questa rete invisibile che hai tessuto nel tempo. Ogni contatto che hai coltivato potrebbe rivelarsi la chiave per una nuova opportunita' entusiasmante.", advice: "Ogni persona che incontri e' un potenziale alleato. Il networking dei Gemelli e' un'arte che oggi raggiunge la perfezione." },
      { text: "Un progetto che richiede creativita' e pensiero laterale e' perfetto per le tue abilita' gemellari. Come segno governato da Mercurio, la tua mente non segue sentieri lineari ma esplora connessioni inaspettate. Oggi questa capacita' si rivela determinante per risolvere un problema che ha bloccato tutti. La soluzione che trovi sara' elegante, originale e geniale, esattamente come la mente dei Gemelli.", advice: "Pensa fuori dagli schemi con la liberta' del tuo segno d'aria. La soluzione geniale e' quella che nessun altro ha considerato." },
      { text: "Le stelle parlano di apprendimento rapido che si trasforma in vantaggio competitivo. Come Gemelli, hai la capacita' unica di assorbire nuove competenze con una velocita' che intimorisce. Mercurio favorisce oggi l'acquisizione di conoscenze che ti renderanno unico nel tuo campo. Un corso, un libro, una conversazione con un esperto: ogni fonte di sapere oggi e' un investimento che ripaga immediatamente.", advice: "Investi nel tuo sapere con la fame di conoscenza dei Gemelli. Ogni nuova competenza e' un'arma nel tuo arsenale professionale." },
      { text: "Mercurio favorisce trattative, negoziazioni e accordi professionali di ogni tipo. Come Gemelli, hai il talento innato per trovare le parole che convincono, i compromessi che soddisfano tutti e le soluzioni che creano valore. Oggi questo talento diplomatico raggiunge il suo apice. Se hai un accordo da chiudere o una proposta da fare, questo e' il momento cosmico perfetto per agire.", advice: "Le parole giuste al momento giusto cambiano tutto. La capacita' negoziale dei Gemelli oggi e' un'arma imbattibile." },
      { text: "Due opportunita' professionali si presentano contemporaneamente, rispecchiando la dualita' del tuo segno. Come Gemelli, sei uno dei pochi segni che riesce a valutare opzioni multiple senza andare in confusione. Mercurio ti dona oggi la lucidita' per vedere i pro e i contro di ciascuna con chiarezza cristallina. Non aver paura di scegliere: la tua mente d'aria sa istintivamente quale percorso porta piu' lontano.", advice: "Segui l'opportunita' che stimola la tua mente e la tua curiosita'. Il Gemelli che sceglie con l'intelletto non sbaglia mai." },
      { text: "La tua curiosita' innata oggi ti porta a scoprire informazioni cruciali per il tuo lavoro. Come Gemelli, sei il ricercatore instancabile dello zodiaco: ogni dettaglio, ogni dato, ogni connessione ti incuriosisce. Mercurio guida le tue ricerche verso una scoperta che i tuoi colleghi non hanno fatto. Questa informazione potrebbe darti un vantaggio significativo se la usi con intelligenza strategica.", advice: "Non smettere mai di esplorare e fare domande. La curiosita' mercuriana dei Gemelli e' la fonte delle intuizioni piu' brillanti." },
      { text: "Le stelle vedono una collaborazione professionale fruttuosa e stimolante che si forma sotto l'influenza di Mercurio. Come Gemelli, dai il meglio quando lavori in team con menti brillanti che sanno tenere il tuo passo. Oggi le costellazioni portano nella tua orbita le persone giuste per un progetto ambizioso. Le menti brillanti insieme non si sommano: si moltiplicano, e il risultato sara' straordinario.", advice: "Le menti brillanti insieme creano sinergie esplosive. Il Gemelli in un team stimolante raggiunge risultati impossibili da solo." },
    ],
    cancer: [
      { text: "La Luna favorisce oggi la creativita' e l'intuizione nel tuo ambiente professionale. Come Cancro, possiedi un'intelligenza emotiva che nel mondo del lavoro e' un asset inestimabile. La tua capacita' di leggere le persone, capire le dinamiche nascoste e anticipare i bisogni ti rende un professionista unico. Oggi questa dote lunare si manifesta in un'intuizione che potrebbe cambiare la direzione di un progetto.", advice: "Fidati del tuo istinto lunare nelle decisioni professionali. L'intuizione del Cancro e' uno strumento di lavoro potentissimo." },
      { text: "Le stelle vedono il tuo ambiente lavorativo diventare piu' accogliente e produttivo grazie alla tua influenza. Come Cancro, hai il dono di trasformare qualsiasi spazio in un luogo dove le persone si sentono a casa. Questa capacita' lunare di creare comfort non e' superficiale: migliora concretamente la produttivita' e il benessere del team. Oggi i tuoi colleghi noteranno e apprezzeranno questa tua qualita'.", advice: "Porta il tuo calore naturale nello spazio di lavoro. Il Cancro che crea un ambiente positivo moltiplica i risultati di tutti." },
      { text: "Un progetto che ti appassiona riceve oggi il supporto che meritava da tempo. Come Cancro, quando credi in qualcosa ci metti il cuore, e questo si vede nella qualita' del tuo lavoro. La Luna illumina i meriti della tua dedizione, portandoli all'attenzione di chi ha il potere di darti il via libera. Le stelle confermano che quando il cuore guida, i risultati non possono che essere straordinari.", advice: "Quando il cuore guida un progetto, i risultati parlano da soli. Il Cancro appassionato e' una forza creativa inarrestabile." },
      { text: "Le costellazioni indicano un periodo di stabilita' finanziaria che rassicura la tua natura protettiva. Come Cancro, la sicurezza economica non e' un lusso ma una necessita' emotiva: hai bisogno di sapere che puoi proteggere te stesso e chi ami. La Luna favorisce oggi decisioni finanziarie sagge che rafforzano il tuo senso di sicurezza. Le stelle vedono un cuscinetto di protezione che si costruisce solidamente.", advice: "Crea un cuscinetto di sicurezza finanziaria per il futuro. Il Cancro che si sente protetto economicamente rende il meglio in ogni campo." },
      { text: "La tua capacita' di prenderti cura del team si rivela oggi un asset professionale di valore inestimabile. Come Cancro, sei il leader che nutre, che protegge e che crea un ambiente dove tutti possono dare il meglio. La Luna amplifica questa qualita' manageriale unica, rendendoti il punto di riferimento emotivo del gruppo. I leader migliori non sono quelli che comandano ma quelli che fanno crescere gli altri.", advice: "I leader piu' efficaci sono quelli che sanno ascoltare e nutrire. Il Cancro al comando crea team devoti e straordinariamente produttivi." },
      { text: "Le stelle parlano di un ritorno alla passione professionale originaria. Come Cancro, a volte il pragmatismo della vita lavorativa ti allontana da cio' che veramente ami fare. Oggi la Luna ti riconnette con quella scintilla iniziale che ti ha portato sulla tua strada. Questa riscoperta non e' nostalgia ma rinnovamento: il ricordare perche' hai iniziato e' il carburante per continuare con entusiasmo e dedizione.", advice: "Riconnettiti con la passione originale che ti ha guidato. Il Cancro che lavora con il cuore non conosce il burnout." },
      { text: "Un'emozione forte ti guidera' oggi verso la decisione professionale giusta. Come Cancro, le tue decisioni migliori non nascono dall'analisi fredda ma dall'integrazione di logica e intuizione. La Luna potenzia il tuo sesto senso professionale, dandoti la certezza di sapere quale direzione prendere. Non ignorare quella sensazione viscerale che ti dice cosa e' giusto: il tuo istinto e' il tuo miglior consulente.", advice: "Non ignorare le sensazioni viscerali sulle questioni di lavoro. Il Cancro che unisce intuizione e razionalita' prende decisioni impeccabili." },
      { text: "La Luna piena illumina un'opportunita' professionale nascosta che solo il tuo sguardo attento puo' cogliere. Come Cancro, hai la capacita' di vedere cio' che gli altri trascurano: le potenzialita' inespresse, i bisogni non soddisfatti, le nicchie inesplorate. Oggi questa visione lunare si concentra su un'occasione specifica che potrebbe portare grande soddisfazione sia professionale che economica.", advice: "Le migliori occasioni si nascondono dove altri non guardano. L'occhio lunare del Cancro vede opportunita' invisibili." },
      { text: "Le stelle vedono nutrimento e crescita organica nella tua carriera. Come un giardino curato con amore, il tuo percorso professionale sta fiorendo grazie alle cure costanti che gli hai dedicato. La Luna favorisce una crescita naturale e sostenibile, non forzata. Come Cancro, il tuo approccio al lavoro e' simile a quello che hai con le persone che ami: paziente, dedicato e profondamente personale.", advice: "Coltiva la carriera con la stessa cura con cui coltivi le relazioni. Il Cancro che nutre il proprio percorso raccoglie frutti dolcissimi." },
      { text: "Il tuo lato empatico si rivela oggi uno strumento professionale di rara efficacia. Come Cancro, la tua capacita' di metterti nei panni degli altri ti permette di capire clienti, colleghi e superiori a un livello che va oltre il professionale. La Luna amplifica questa intelligenza emotiva, rendendoti oggi il mediatore perfetto, il problem solver ideale e il leader empatico di cui ogni team ha bisogno.", advice: "L'intelligenza emotiva e' la competenza professionale del futuro. Il Cancro che la possiede per natura e' avanti anni luce." },
    ],
    leo: [
      { text: "Il Sole illumina la tua carriera con una luce dorata e potente, mettendoti sotto i riflettori professionali. Come Leone, sei nato per posizioni di visibilita' dove il tuo carisma e la tua creativita' possono esprimersi pienamente. Oggi questa energia solare raggiunge il picco, rendendo ogni tua azione sul lavoro memorabile. Preparati a ricevere attenzione e riconoscimento per cio' che hai costruito con passione.", advice: "Brilla con la consapevolezza del Leone che sa di meritare la scena. L'umilta' nel successo rende il tuo splendore ancora piu' magnetico." },
      { text: "Le stelle vedono un riconoscimento pubblico del tuo talento e del tuo impegno professionale. Come Leone governato dal Sole, il tuo lavoro non e' mai anonimo: porta sempre la tua firma inconfondibile. Oggi qualcuno di importante notera' quella firma e la apprezzera' apertamente. La tua creativita', la tua energia e il tuo carisma sono asset professionali che pochi possono eguagliare.", advice: "Accetta gli applausi che ti sei guadagnato con merito. Il Leone che riceve riconoscimenti con grazia ispira tutti a dare il meglio." },
      { text: "Un ruolo di leadership ti attende e le stelle ti incoronano come guida naturale del tuo team. Come Leone, la leadership e' nel tuo DNA solare: non la cerchi, la attrai. Oggi la tua capacita' di ispirare, motivare e guidare gli altri raggiunge livelli straordinari. Non si tratta di comandare ma di accendere negli altri la stessa passione che arde in te. Questo e' il tipo di leadership che cambia le cose.", advice: "Guida con la generosita' del cuore leonino, non con l'autorita'. Il Leone che ispira crea seguaci devoti, non subordinati." },
      { text: "Le costellazioni parlano di creativita' professionale al massimo livello. Come Leone, ogni tuo progetto e' un'opera d'arte, un'espressione della tua visione unica del mondo. Il Sole alimenta oggi questa vena creativa con un'energia che trasforma idee ordinarie in concetti straordinari. Non trattenere il tuo genio creativo: lascialo fluire liberamente e vedrai come trasforma tutto cio' che tocca.", advice: "Non censurare il tuo genio creativo per paura di essere troppo. Il Leone creativo che si esprime liberamente crea capolavori." },
      { text: "Oggi il tuo carisma solare conquista anche l'ambiente professionale piu' formale e rigido. Come Leone, hai il dono di portare calore e umanita' ovunque tu vada, anche nelle sale riunioni piu' austere. Il Sole ti rende oggi particolarmente convincente e magnetico: ogni tua parola ha un peso maggiore, ogni tua proposta brilla di una luce speciale. Usa questa influenza per far avanzare i tuoi progetti.", advice: "Usa la tua presenza solare per motivare e convincere. Il carisma del Leone in ambiente professionale apre porte blindate." },
      { text: "Le stelle vedono successo brillante in una presentazione, proposta o pitch importante. Come Leone, sei un performer naturale: sai come catturare l'attenzione e mantenerla. Il Sole ti dona oggi un'eloquenza e una sicurezza che rendono irresistibile qualsiasi tua proposta. Preparati bene e poi sali su quel palcoscenico professionale con la regalita' che ti contraddistingue: il successo e' assicurato.", advice: "Preparati con cura e poi brilla senza trattenerti. Il Leone che si prepara e poi improvvisa e' imbattibile." },
      { text: "Un progetto ambizioso prende vita concreta oggi grazie alla forza della tua visione leonina. Come Leone, non ti accontenti del mediocre o del gia' fatto: vuoi creare qualcosa di grandioso. Il Sole alimenta questa ambizione cosmica, dandoti la carica per trasformare i sogni piu' audaci in piani d'azione concreti. Le stelle favoriscono chi sogna in grande e agisce con determinazione regale.", advice: "Sogna in grande e agisci con la determinazione del Leone. Le stelle sostengono chi ha il coraggio delle proprie visioni ambiziose." },
      { text: "Il Sole ti dona oggi un'energia professionale inesauribile che stupira' chi ti circonda. Come Leone, la tua capacita' di mantenere alta l'energia e l'entusiasmo anche nelle giornate piu' impegnative e' leggendaria. Oggi questa vitalita' solare raggiunge il suo apice, permettendoti di portare a termine compiti che normalmente richiederebbero giorni. Sfrutta questa carica cosmica al massimo.", advice: "Sfrutta questa carica solare straordinaria per completare tutto. Il Leone energizzato dal Sole e' la forza piu' produttiva dello zodiaco." },
      { text: "Le stelle parlano di generosita' professionale che crea un circolo virtuoso di successo condiviso. Come Leone, il tuo cuore generoso ti spinge ad aiutare colleghi e collaboratori a crescere. Oggi questa generosita' solare torna a te moltiplicata: chi hai aiutato in passato sara' pronto a sostenerti. Il Leone che eleva gli altri si eleva sempre piu' in alto, perche' la vera regalita' e' nel dare.", advice: "Aiuta gli altri a crescere e crescerai insieme a loro. La generosita' professionale del Leone crea alleanze potentissime." },
      { text: "Un'opportunita' di brillare professionalmente si presenta oggi con un tempismo cosmico perfetto. Come Leone, sai riconoscere il momento giusto per entrare in scena e fare colpo. Il Sole allinea le circostanze a tuo favore: le persone giuste, il contesto giusto, il messaggio giusto. Non lasciare che la modestia ti freni: il palcoscenico e' preparato e le stelle aspettano la tua performance.", advice: "Il palcoscenico professionale e' pronto per te: sali e conquista. Il Leone che coglie il momento giusto entra nella storia." },
    ],
    virgo: [
      { text: "Mercurio affina la tua precisione a livelli quasi sovrumani nel settore professionale. Come Vergine, il tuo occhio per i dettagli e' uno strumento di lavoro che pochi possono eguagliare. Oggi ogni analisi, ogni report, ogni progetto che tocchi raggiunge un livello di perfezione che stupisce. La tua capacita' di vedere l'errore che nessuno nota e la soluzione che nessuno vede e' il tuo superpotere al lavoro.", advice: "La perfezione nei dettagli fa la differenza tra buono e straordinario. L'occhio della Vergine oggi e' un laser di precisione." },
      { text: "Le stelle vedono il tuo metodo organizzativo portare risultati impeccabili. Come Vergine governata da Mercurio, la tua capacita' di strutturare il caos in ordine e' leggendaria. Oggi questa qualita' si esprime al meglio, permettendoti di gestire progetti complessi con un'efficienza che lascia tutti senza parole. Il tuo sistema, costruito con pazienza e intelligenza, funziona come un orologio svizzero.", advice: "Continua a organizzare con la tua cura meticolosa. Il sistema che hai creato e' il segreto del tuo successo professionale." },
      { text: "Un'analisi approfondita che solo la tua mente di Vergine potrebbe condurre rivela un'opportunita' nascosta. Come segno di terra governato da Mercurio, possiedi la rara combinazione di pensiero analitico e senso pratico. Oggi questa combinazione ti permette di vedere qualcosa che tutti gli altri hanno trascurato: un pattern, un'inefficienza, un'occasione. Questa scoperta potrebbe portare un vantaggio competitivo significativo.", advice: "Il tuo occhio critico e' un vantaggio competitivo unico. La Vergine che analizza in profondita' trova tesori nascosti." },
      { text: "Le costellazioni indicano una giornata di efficienza massima e produttivita' straordinaria. Come Vergine, il tuo standard di lavoro e' gia' alto di default, ma oggi Mercurio lo porta a livelli eccezionali. Ogni compito viene completato con una rapidita' e una qualita' che sorprendono anche te. Approfitta di questo slancio cosmico per completare quei progetti arretrati che aspettano la tua attenzione.", advice: "Approfitta di questo slancio di produttivita' eccezionale. La Vergine in stato di grazia completa in ore cio' che altri fanno in giorni." },
      { text: "La tua dedizione silenziosa viene finalmente notata da chi ha il potere di fare la differenza. Come Vergine, lavori sodo senza cercare applausi, preferendo che siano i risultati a parlare. Oggi Mercurio porta alla luce il tuo contributo prezioso, facendolo brillare sotto gli occhi giusti. Il riconoscimento che arriva sara' tanto piu' dolce perche' non l'hai cercato: te lo sei semplicemente meritato.", advice: "Il lavoro silenzioso prima o poi viene ricompensato generosamente. La Vergine che eccelle con discrezione raccoglie i premi piu' preziosi." },
      { text: "Le stelle parlano di miglioramento continuo come filosofia che ti porta verso l'eccellenza professionale. Come Vergine, non ti accontenti mai del buono abbastanza: vuoi sempre migliorare, affinare, perfezionare. Mercurio alimenta questa sete di eccellenza, dandoti oggi gli strumenti per fare un salto di qualita' nel tuo lavoro. Stai diventando un vero esperto nel tuo campo, e le stelle lo confermano.", advice: "L'eccellenza e' un'abitudine quotidiana, non un atto isolato. La Vergine che migliora ogni giorno diventa insuperabile nel suo campo." },
      { text: "Un problema complesso che ha fermato il team si risolve oggi grazie alla tua logica infallibile di Vergine. Dove altri vedono caos e confusione, la tua mente mercuriana vede strutture, pattern e soluzioni. Oggi questa capacita' analitica ti rende l'eroe silenzioso del tuo ambiente lavorativo. Scomponi il problema nelle sue parti fondamentali e la soluzione apparira' con la chiarezza di un cristallo.", advice: "Scomponi il problema e la soluzione si rivela da sola. La mente analitica della Vergine trasforma il caos in ordine." },
      { text: "Mercurio favorisce oggi la documentazione, l'organizzazione e la messa in ordine di tutto il tuo mondo professionale. Come Vergine, sai che un sistema ordinato non e' un lusso ma una necessita' per la produttivita'. Oggi e' il momento perfetto per aggiornare file, organizzare processi e creare strutture che ti faranno risparmiare tempo prezioso in futuro. L'ordine che crei oggi e' il fondamento del successo di domani.", advice: "Un sistema ordinato libera la mente per la creativita'. La Vergine che organizza oggi si prepara al successo di domani." },
      { text: "Le stelle vedono crescita professionale solida attraverso il continuo sviluppo delle tue competenze tecniche. Come Vergine, il tuo approccio al lavoro e' artigianale: vuoi padroneggiare ogni aspetto del tuo mestiere. Mercurio favorisce oggi l'acquisizione di nuove skill che ti renderanno ancora piu' indispensabile. Investi nel tuo sapere con la dedizione che ti contraddistingue: e' il patrimonio piu' sicuro.", advice: "Le tue competenze sono il patrimonio piu' prezioso. La Vergine che investe nel proprio sapere costruisce una carriera inattaccabile." },
      { text: "La tua umilta' professionale si rivela oggi un'arma segreta di straordinaria efficacia. Come Vergine, non hai bisogno di proclamare i tuoi successi: li lasci parlare da soli. Mercurio amplifica la forza silenziosa di questo approccio, attirando l'attenzione e il rispetto di chi sa riconoscere il valore vero. Chi lavora in silenzio costruisce le fondamenta piu' solide per un successo duraturo e autentico.", advice: "L'umilta' nel lavoro e' la forza della Vergine. Chi costruisce in silenzio crea le opere piu' durature." },
    ],
    libra: [
      { text: "Venere porta armonia perfetta nelle tue relazioni professionali, creando un ambiente di collaborazione ideale. Come Bilancia, sei il diplomatico dello zodiaco, capace di trovare il punto d'incontro tra posizioni apparentemente inconciliabili. Oggi questa abilita' venusiana si esprime al massimo, rendendo possibili accordi e collaborazioni che sembravano impossibili. Il tuo ruolo di mediatore e' il tuo asset piu' grande.", advice: "L'equilibrio nelle relazioni professionali e' la tua specialita'. La Bilancia che armonizza crea valore per tutti." },
      { text: "Le stelle vedono il tuo talento diplomatico brillare in una mediazione professionale cruciale. Come Bilancia governata da Venere, hai la capacita' innata di vedere le ragioni di tutte le parti e di trovare soluzioni che soddisfino tutti. Oggi questa dote e' particolarmente richiesta e apprezzata. La tua presenza trasforma conflitti in opportunita' di crescita collettiva. La diplomazia e' la tua forma d'arte.", advice: "Trova il compromesso che crea valore per tutte le parti. La mediazione della Bilancia trasforma i conflitti in vittorie condivise." },
      { text: "Un'opportunita' creativa si presenta nel tuo percorso professionale, parlando al tuo senso estetico venusiano. Come Bilancia, hai un occhio naturale per la bellezza e l'armonia che si traduce in qualsiasi settore lavorativo. Oggi le stelle portano un progetto o un compito che richiede esattamente le tue qualita' estetiche e creative. La bellezza non e' solo decorazione: e' un valore aggiunto che fa la differenza.", advice: "Porta il tuo senso estetico in tutto cio' che fai. La Bilancia che applica la bellezza al lavoro crea risultati che incantano." },
      { text: "Le costellazioni indicano partnership professionali vantaggiose che si formano sotto l'influenza di Venere. Come Bilancia, dai il meglio quando lavori in tandem con qualcuno che complementa le tue abilita'. Oggi le stelle allineano le persone giuste sulla tua strada: collaboratori che condividono la tua visione di eccellenza e armonia. Due menti complementari in perfetto equilibrio possono conquistare il mondo.", advice: "Due menti complementari valgono infinitamente piu' di una sola. La Bilancia che trova il partner professionale giusto e' inarrestabile." },
      { text: "La tua capacita' di vedere entrambi i lati di ogni questione ti rende oggi il consulente ideale per decisioni importanti. Come Bilancia, la tua obiettivita' e' una risorsa rarissima nel mondo del lavoro. Venere amplifica questa qualita', permettendoti di offrire prospettive equilibrate e sagge. Chi si rivolge a te per consiglio oggi ricevera' un'analisi imparziale che vale piu' di qualsiasi report.", advice: "L'obiettivita' e' una dote rara e preziosa nel mondo del lavoro. La Bilancia che giudica con equita' diventa il punto di riferimento." },
      { text: "Le stelle parlano di giustizia professionale in arrivo. Come Bilancia, credi profondamente nell'equita' e nella meritocrazia, e a volte la realta' ti delude. Oggi Venere ristabilisce l'equilibrio: cio' che meriti arrivera' nella forma giusta al momento giusto. La bilancia del karma professionale si sta riequilibrando a tuo favore. La pazienza che hai dimostrato davanti alle ingiustizie viene oggi ricompensata.", advice: "La bilancia del karma professionale e' sempre in equilibrio. La Bilancia che lavora con integrita' riceve sempre cio' che merita." },
      { text: "Un ambiente lavorativo armonioso e esteticamente piacevole oggi aumenta sensibilmente la tua produttivita'. Come Bilancia, sei profondamente influenzato dall'ambiente che ti circonda: la bellezza ti ispira, il caos ti blocca. Venere ti invita a investire nella qualita' del tuo spazio di lavoro. Un piccolo cambiamento estetico, un tocco di ordine in piu', possono trasformare radicalmente la tua esperienza lavorativa.", advice: "Investi nella bellezza e nell'ordine del tuo spazio professionale. La Bilancia che lavora in armonia produce risultati armoniosi." },
      { text: "Venere favorisce oggi negoziazioni eleganti e raffinate che portano a risultati eccellenti. Come Bilancia, non usi la forza bruta nelle trattative ma la grazia, la persuasione e l'eleganza. Oggi questo approccio venusiano si rivela vincente in modo spettacolare. Un accordo che chiudi oggi portera' il tuo marchio inconfondibile: raffinato, equilibrato e vantaggioso per tutti.", advice: "La grazia nelle negoziazioni e' la tua firma inconfondibile. La Bilancia che tratta con eleganza chiude gli accordi migliori." },
      { text: "Le stelle vedono un perfetto equilibrio tra vita professionale e personale che molti invidiano. Come Bilancia, cerchi l'armonia in ogni aspetto dell'esistenza, e oggi le costellazioni ti confermano che stai trovando la formula giusta. Non e' un equilibrio statico ma dinamico, come una danza continua tra responsabilita' e piacere. Questa capacita' di bilanciare e' la chiave del tuo successo duraturo.", advice: "L'armonia tra lavoro e vita e' la chiave del successo. La Bilancia che trova questo equilibrio non conosce il burnout." },
      { text: "Una decisione professionale importante richiede oggi il tuo giudizio equilibrato e la tua visione panoramica. Come Bilancia, pesi ogni opzione con la cura di un orefice che valuta pietre preziose. Venere ti dona la lucidita' per distinguere l'oro vero dal falso, l'opportunita' reale dalla trappola mascherata. Prenditi il tempo necessario per valutare: la decisione giusta vale piu' di una decisione veloce.", advice: "Pesa ogni opzione con la cura che ti contraddistingue. La Bilancia che decide con equilibrio sceglie sempre la via migliore." },
    ],
    scorpio: [
      { text: "Plutone intensifica la tua determinazione professionale a livelli che nessun altro segno puo' raggiungere. Come Scorpione, quando ti fissi un obiettivo diventi una forza della natura inarrestabile. Oggi questa tenacia plutoniana si manifesta in modo particolarmente potente, permettendoti di superare ostacoli che fermerebbero chiunque altro. La tua capacita' di trasformare la pressione in diamante e' il segreto del tuo successo.", advice: "La tua tenacia e' la tua arma piu' potente nel lavoro. Lo Scorpione determinato supera qualsiasi ostacolo si metta sulla sua strada." },
      { text: "Le stelle vedono una trasformazione professionale in corso che ti portera' a un livello completamente nuovo. Come Scorpione governato da Plutone, il cambiamento non ti spaventa: lo cerchi, perche' sai che ogni trasformazione porta crescita. Un ruolo, un progetto o un approccio sta per cambiare radicalmente, e tu sei pronto ad abbracciare questa evoluzione con la forza che ti contraddistingue.", advice: "Non temere il cambiamento professionale ma accoglilo. Lo Scorpione che si reinventa emerge sempre piu' forte e potente." },
      { text: "Un'informazione cruciale viene alla luce oggi grazie alla tua naturale capacita' investigativa. Come Scorpione, nulla sfugge al tuo sguardo penetrante: vedi cio' che gli altri nascondono e comprendi cio' che gli altri ignorano. Plutone guida oggi le tue ricerche verso una scoperta che ti da un vantaggio strategico significativo. La conoscenza e' potere, e oggi ne possiedi in abbondanza.", advice: "La conoscenza e' potere e tu sai dove trovarla. Lo Scorpione che scava in profondita' trova sempre l'oro nascosto." },
      { text: "Le costellazioni parlano di una strategia vincente che prende forma nella tua mente acuta. Come Scorpione, sei lo stratega dello zodiaco: pianifichi ogni mossa con la precisione di un maestro di scacchi. Plutone amplifica oggi questa capacita' tattica, permettendoti di vedere sette mosse avanti rispetto agli altri. Il piano che stai elaborando ha tutte le caratteristiche per portarti esattamente dove vuoi arrivare.", advice: "Gioca le tue carte professionali al momento giusto. Lo Scorpione che strategizza con pazienza vince la partita decisiva." },
      { text: "La tua capacita' di andare oltre la superficie rivela oggi opportunita' professionali che nessun altro riesce a vedere. Come Scorpione, il tuo sguardo penetra oltre le apparenze, raggiungendo la verita' nascosta di ogni situazione. Plutone potenzia questa visione profonda, rendendoti capace di leggere il mercato, le persone e le tendenze con una lucidita' quasi profetica. Scava dove gli altri si fermano.", advice: "Scava oltre la superficie dove gli altri si fermano. La profondita' dello Scorpione nel lavoro e' un vantaggio competitivo raro." },
      { text: "Le stelle indicano un periodo di crescente potere e influenza nel tuo ambiente professionale. Come Scorpione, il potere non e' un fine ma uno strumento per realizzare la tua visione. Plutone amplifica la tua autorevolezza naturale, facendo si' che le tue parole abbiano un peso sempre maggiore. Ma ricorda che con il potere viene la responsabilita' di usarlo con integrita' e saggezza.", advice: "Con il potere viene la responsabilita' di usarlo con etica. Lo Scorpione che guida con integrita' costruisce un'eredita' duratura." },
      { text: "Un segreto professionale ti viene rivelato oggi, aprendoti prospettive completamente nuove. Come Scorpione, sei il custode naturale dei segreti: le persone si fidano a confidarti cio' che non direbbero a nessun altro. Plutone porta oggi un'informazione riservata che potrebbe cambiare le carte in tavola. Usala con la saggezza e l'etica che contraddistinguono i migliori figli di Plutone.", advice: "L'integrita' nell'uso delle informazioni e' piu' preziosa dell'informazione stessa. Lo Scorpione etico guadagna fiducia illimitata." },
      { text: "Plutone favorisce le rinascite professionali. Un progetto o un'idea che sembrava fallita oggi mostra segni di vita sorprendenti. Come Scorpione, sei il maestro della resurrezione: sai che dalle ceneri nascono le fenici piu' belle e potenti. Non abbandonare quel progetto in cui credi solo perche' ha attraversato una fase difficile. La trasformazione plutoniana sta per compiersi, e il risultato sara' straordinario.", advice: "Dalle ceneri nascono le fenici piu' belle. Lo Scorpione che non si arrende davanti al fallimento trova il successo piu' grande." },
      { text: "La tua intensita' sul lavoro oggi impressiona i superiori e i colleghi in modo significativo. Come Scorpione, quando ti dedichi a qualcosa lo fai con un'intensita' che non lascia spazio alla mediocrita'. Plutone amplifica questa dedizione totale, rendendo ogni tuo contributo indimenticabile. Le stelle vedono riconoscimento per questa passione: chi lavora con te sa che stai dando tutto te stesso.", advice: "Lascia che i risultati parlino per te con la forza dello Scorpione. L'intensita' nel lavoro crea un'impronta che non si cancella." },
      { text: "Le stelle vedono investimenti strategici professionali che stanno per dare i loro frutti. Come Scorpione, pensi sempre in termini di lungo periodo, investendo tempo ed energia dove altri non avrebbero pazienza. Plutone conferma oggi che le scelte strategiche fatte mesi fa stanno maturando. Il tuo fiuto per gli affari, unito alla pazienza plutoniana, crea una combinazione vincente nel mondo del lavoro.", advice: "Pensa sempre in termini di lungo periodo e strategia. Lo Scorpione che investe con visione raccoglie risultati straordinari." },
    ],
    sagittarius: [
      { text: "Giove espande magnificamente le tue opportunita' professionali, aprendo orizzonti che non immaginavi. Come Sagittario, il tuo campo d'azione non ha confini: il mondo intero e' il tuo ufficio. Oggi le stelle portano nuove possibilita' che potrebbero avere una dimensione internazionale o multicultural. La tua capacita' di vedere il quadro grande e' il tuo vantaggio competitivo piu' potente.", advice: "Guarda oltre i confini abituali del tuo settore. Il Sagittario che pensa in grande trova opportunita' che gli altri nemmeno immaginano." },
      { text: "Le stelle vedono crescita professionale attraverso l'apprendimento e l'espansione delle conoscenze. Come Sagittario governato da Giove, la tua sete di sapere e' insaziabile e oggi questa qualita' si traduce in vantaggio professionale concreto. Un corso, un viaggio formativo o anche una semplice lettura potrebbe fornirti l'intuizione che cambia la direzione della tua carriera. L'investimento in formazione e' sempre il piu' redditizio.", advice: "Investi nella tua formazione con l'entusiasmo del Sagittario. Ogni nuova conoscenza e' una freccia in piu' nel tuo arco." },
      { text: "Un'opportunita' con respiro internazionale si profila oggi nel tuo cielo professionale. Come Sagittario, sei il cittadino del mondo dello zodiaco: ti senti a casa ovunque e questo e' un asset inestimabile. Giove favorisce connessioni oltre confine, collaborazioni interculturali e progetti con visione globale. Il mondo si sta aprendo davanti a te: non esitare ad attraversare quella porta.", advice: "Il mondo e' il tuo campo di gioco professionale. Il Sagittario che pensa globalmente agisce con una prospettiva che nessuno puo' eguagliare." },
      { text: "Le costellazioni indicano che il tuo ottimismo contagioso sta trasformando positivamente il tuo ambiente di lavoro. Come Sagittario, porti entusiasmo e visione positiva ovunque tu vada, e oggi questa energia gioviana e' particolarmente potente. Il tuo team si nutre della tua fiducia nel futuro, trovando motivazione dove prima c'era solo routine. L'ottimismo non e' ingenuita': e' strategia.", advice: "Il tuo entusiasmo sagittariano e' la migliore strategia di leadership. L'ottimismo costruttivo trasforma i team e i risultati." },
      { text: "Giove porta fortuna concreta negli affari e nelle iniziative professionali di oggi. Come Sagittario, sei il segno piu' fortunato dello zodiaco, ma la tua fortuna non e' caso: e' il risultato del tuo coraggio di osare. Oggi un rischio calcolato potrebbe ripagare in modo spettacolare. Le stelle favoriscono chi ha il coraggio delle proprie convinzioni e l'audacia di scommettere su se stesso.", advice: "La fortuna favorisce chi osa con intelligenza e coraggio. Il Sagittario che rischia con saggezza e' baciato da Giove." },
      { text: "Le stelle parlano di una visione ampia e lungimirante che ti distingue da tutti nel tuo campo. Come Sagittario, vedi opportunita' dove altri vedono solo ostacoli, e possibilita' dove altri vedono solo limiti. Giove amplifica questa capacita' visionaria, permettendoti di anticipare tendenze e movimenti che si concretizzeranno mesi nel futuro. La prospettiva e' tutto nel business, e la tua e' stellare.", advice: "La tua prospettiva sagittariana e' il tuo vantaggio piu' grande. Chi vede lontano arriva primo, e tu vedi piu' lontano di tutti." },
      { text: "Un viaggio legato al lavoro o un'esperienza fuori dalla routine porta risultati professionali inaspettati. Come Sagittario, i tuoi momenti piu' produttivi spesso avvengono fuori dall'ufficio, in contesti nuovi e stimolanti. Giove favorisce oggi lo spostamento fisico o mentale dalla zona di comfort. Ogni spostamento e' un'opportunita' di vedere le cose da un'angolazione diversa e trovare soluzioni creative.", advice: "Ogni spostamento dalla routine e' un'opportunita' di crescita. Il Sagittario che esplora nuovi contesti trova le idee migliori." },
      { text: "La tua filosofia di vita positiva e espansiva oggi ispira colleghi e collaboratori a dare il meglio. Come Sagittario, non sei solo un professionista: sei un maestro di vita che insegna con l'esempio. Giove amplifica questa qualita' ispirazionale, facendo di te un faro per chi cerca motivazione e senso nel proprio lavoro. Condividi la tua visione generosamente: il mondo del lavoro ne ha bisogno.", advice: "Condividi la tua visione con la generosita' del Sagittario. Le tue parole di ispirazione hanno il potere di trasformare carriere." },
      { text: "Le stelle vedono abbondanza professionale in arrivo, amplificata dalla generosita' di Giove. Come Sagittario, credi nell'abbondanza come stato naturale dell'universo, e oggi questa fede viene ricompensata. La tua generosita' professionale, il tempo dedicato ad aiutare gli altri, le conoscenze condivise liberamente: tutto questo torna a te moltiplicato. Piu' dai, piu' ricevi: e' la legge gioviana.", advice: "La generosita' professionale torna sempre moltiplicata. Il Sagittario che condivide liberamente attrae abbondanza infinita." },
      { text: "Un'avventura professionale emozionante e fuori dall'ordinario si profila all'orizzonte. Come Sagittario, la routine e' il tuo peggior nemico e l'avventura il tuo miglior alleato. Giove porta oggi un'opportunita' che ha tutte le caratteristiche per entusiasmarti: novita', sfida e possibilita' di crescita. Non dire no per paura dell'ignoto: e' proprio nell'ignoto che il Sagittario trova le sue fortune piu' grandi.", advice: "Di' si' all'avventura professionale con il cuore del Sagittario. L'ignoto e' il terreno dove crescono le opportunita' piu' belle." },
    ],
    capricorn: [
      { text: "Saturno, il tuo saggio governatore, premia oggi la disciplina e l'impegno che hai investito nella tua carriera. Come Capricorno, credi che il successo si costruisca giorno dopo giorno con dedizione incrollabile. Le stelle confermano che questa filosofia e' vincente: i tuoi sforzi sistematici stanno producendo risultati che parlano da soli. La montagna che hai scalato pazientemente ti sta finalmente rivelando la vista dalla vetta.", advice: "La perseveranza saturniana e' la madre di ogni successo duraturo. Il Capricorno che non si ferma mai raggiunge vette che altri nemmeno sognano." },
      { text: "Le stelle vedono una promozione o un avanzamento di carriera meritatissimo nel tuo futuro prossimo. Come Capricorno governato da Saturno, il tuo percorso e' stato lungo e impegnativo, ma ogni gradino che hai salito ti ha preparato per questa responsabilita'. Il riconoscimento che arriva non e' un regalo ma il giusto compenso per anni di lavoro eccellente. Accoglilo con la dignita' che ti contraddistingue.", advice: "Hai lavorato duramente per questo momento: accoglilo con orgoglio. Il Capricorno che raccoglie i frutti della dedizione merita ogni soddisfazione." },
      { text: "Un obiettivo professionale ambizioso che sembrava lontanissimo oggi diventa improvvisamente raggiungibile. Come Capricorno, le tue ambizioni sono sempre state alte quanto le montagne che rappresentano il tuo segno. Saturno allinea oggi le circostanze a tuo favore, rendendo possibile cio' che ieri sembrava un sogno. Passo dopo passo, con la determinazione che ti e' propria, anche la vetta piu' alta si raggiunge.", advice: "Passo dopo passo, anche la montagna piu' alta si scala. Il Capricorno che avanza con costanza raggiunge qualsiasi traguardo." },
      { text: "Le costellazioni indicano crescente autorita' e rispetto nel tuo ambiente lavorativo. Come Capricorno, la tua competenza e la tua serieta' ti hanno guadagnato una reputazione solida come la roccia. Saturno amplifica oggi questa autorevolezza, facendo di te il punto di riferimento naturale per decisioni importanti. Le persone si fidano del tuo giudizio perche' sanno che e' fondato su esperienza e integrita'.", advice: "La tua competenza parla per te piu' forte di qualsiasi autopromozione. Il Capricorno autorevole guida con l'esempio silenzioso." },
      { text: "Saturno favorisce oggi la pianificazione strategica a lungo termine, il terreno dove il Capricorno eccelle. Come segno di terra governato dal maestro del tempo, hai una visione naturale che abbraccia anni e decenni. Oggi questa capacita' si rivela particolarmente preziosa per impostare la prossima fase della tua carriera. I piani che tracci oggi saranno le fondamenta del tuo successo di domani.", advice: "Pianifica oggi per raccogliere domani con la saggezza del Capricorno. La visione a lungo termine e' il tuo vantaggio strategico piu' grande." },
      { text: "Le stelle parlano di maturita' professionale raggiunta. Come Capricorno, hai investito anni per sviluppare competenze, costruire relazioni e accumulare esperienza. Oggi Saturno conferma che sei nel tuo prime professionale: il punto dove esperienza, competenza e visione si incontrano in perfetto equilibrio. Questa maturita' non e' vecchiaia ma sapienza operativa, il momento in cui dai il meglio assoluto.", advice: "Sei nel tuo prime professionale: sfruttalo al massimo. L'esperienza del Capricorno maturo vale piu' di qualsiasi talento grezzo." },
      { text: "Un mentore, un superiore o una figura autorevole nota oggi il tuo potenziale e decide di investire su di te. Come Capricorno, rispetti profondamente la gerarchia e la competenza, e oggi questa qualita' ti connette con chi puo' accelerare la tua crescita. Saturno favorisce le relazioni professionali basate sul rispetto reciproco e sulla trasmissione di conoscenza. Accetta la guida con la gratitudine del discepolo saggio.", advice: "Accetta la guida di chi ha piu' esperienza con gratitudine. Il Capricorno che impara dai migliori diventa il migliore." },
      { text: "Le stelle vedono solidita' finanziaria crescente come risultato della tua gestione oculata e disciplinata. Come Capricorno, tratti le finanze con la stessa serieta' con cui tratti ogni aspetto della vita: con rispetto, disciplina e visione a lungo termine. Saturno benedice oggi questa prudenza finanziaria con risultati concreti e rassicuranti. La liberta' economica che stai costruendo e' la base della tua serenita'.", advice: "La disciplina finanziaria saturniana e' la base della vera liberta'. Il Capricorno che gestisce con saggezza costruisce sicurezza duratura." },
      { text: "Un progetto strutturato e meticolosamente pianificato porta oggi risultati misurabili e soddisfacenti. Come Capricorno, il tuo approccio metodico al lavoro produce output di qualita' superiore, verificabile e replicabile. Saturno si compiace della tua capacita' di trasformare la visione in numeri concreti. I risultati che presenti oggi parlano un linguaggio universale: quello della competenza e della dedizione.", advice: "I numeri non mentono e i tuoi sono eccellenti. Il Capricorno che misura i risultati con rigore costruisce una credibilita' invincibile." },
      { text: "Saturno ti ricorda oggi che il tempo e' la risorsa piu' preziosa di cui disponi nel tuo percorso professionale. Come Capricorno, comprendi intuitivamente il valore del tempo: non lo sprechi, non lo dai per scontato, lo investi con la stessa cura di un capitale prezioso. Le stelle confermano che il modo in cui hai investito il tuo tempo sta producendo rendimenti straordinari. Continua con questa saggezza.", advice: "Investi il tempo come investiresti il denaro: con strategia. Il Capricorno padrone del proprio tempo e' padrone del proprio destino." },
    ],
    aquarius: [
      { text: "Urano porta un'ondata di innovazione nel tuo settore professionale che solo la tua mente acquariana puo' cavalcare. Come Acquario, sei nato per essere all'avanguardia, per vedere il futuro prima degli altri. Oggi un'idea rivoluzionaria potrebbe cambiare completamente le regole del gioco nel tuo campo. Non aver paura di essere il primo a proporre qualcosa di radicalmente diverso: il mondo ha bisogno dei tuoi visionari.", advice: "Non temere di essere il primo a fare qualcosa di nuovo. L'Acquario che innova con coraggio traccia sentieri che altri seguiranno." },
      { text: "Le stelle vedono tecnologia e progresso come parole chiave del tuo periodo professionale. Come Acquario governato da Urano, sei naturalmente in sintonia con le frontiere dell'innovazione. Oggi questa connessione con il futuro si traduce in un vantaggio competitivo concreto. Le soluzioni che proponi hanno un sapore di futuro che affascina e convince. Sei all'avanguardia, e il mondo sta finalmente raggiungendo la tua visione.", advice: "Abbraccia il cambiamento tecnologico come il tuo elemento naturale. L'Acquario che cavalca l'innovazione arriva sempre primo." },
      { text: "Un progetto collaborativo e multidisciplinare porta oggi risultati che superano ogni aspettativa. Come Acquario, credi nel potere del collettivo: le menti diverse che lavorano insieme creano qualcosa che nessun individuo potrebbe realizzare da solo. Urano amplifica questa visione comunitaria, portando le collaborazioni giuste al momento giusto. Il team che guidi o a cui partecipi oggi e' una macchina di innovazione.", advice: "L'unione delle menti diverse crea sinergie impossibili per il singolo. L'Acquario che collabora moltiplica il proprio genio." },
      { text: "Le costellazioni parlano della tua originalita' finalmente premiata e valorizzata nel contesto professionale. Come Acquario, il tuo approccio unico alle cose a volte viene frainteso come eccentricita'. Ma oggi Urano mostra al mondo che la tua diversita' e' il tuo valore piu' grande. L'idea che sembrava troppo futuristica, il metodo che pareva troppo non convenzionale: oggi vengono riconosciuti come geniali.", advice: "Non conformarti mai alle aspettative convenzionali. L'Acquario che resta fedele alla propria originalita' viene sempre premiato dal tempo." },
      { text: "Urano porta un cambiamento professionale improvviso e sorprendente che si rivela straordinariamente positivo. Come Acquario, i cambiamenti improvvisi non ti destabilizzano: ti energizzano. La tua capacita' di adattarti all'imprevisto e di trasformarlo in opportunita' e' senza pari nello zodiaco. Un'opportunita' lampo si presenta oggi: sii pronto a coglierla con la velocita' e la visione del tuo segno d'aria.", advice: "Sii sempre pronto a cogliere l'opportunita' improvvisa. L'Acquario che reagisce rapidamente ai cambiamenti ne esce sempre vincitore." },
      { text: "Le stelle indicano un periodo ideale per lanciare qualcosa di completamente nuovo nel tuo settore. Come Acquario, l'innovazione e' il tuo marchio di fabbrica e oggi Urano potenzia al massimo questa energia creativa. Che sia un prodotto, un servizio, un approccio o un progetto: tutto cio' che lanci oggi porta il segno inconfondibile della tua visione futuristica. Il mercato e' pronto per le tue idee.", advice: "L'innovazione e' il tuo marchio di fabbrica professionale. L'Acquario che lancia qualcosa di nuovo al momento giusto cambia le regole." },
      { text: "Una causa sociale o un progetto con impatto positivo ti appassiona e ti motiva profondamente nel lavoro. Come Acquario, hai bisogno di sentire che il tuo lavoro contribuisce a qualcosa di piu' grande. Urano allinea oggi la tua passione umanitaria con un'opportunita' professionale concreta. Quando il lavoro ha uno scopo che va oltre il profitto, per il tuo segno smette di essere lavoro e diventa missione.", advice: "Quando il lavoro ha uno scopo sociale, non e' piu' lavoro ma vocazione. L'Acquario che unisce carriera e missione e' inarrestabile." },
      { text: "Le stelle vedono il networking digitale e le connessioni online portare frutti professionali significativi. Come Acquario, sei il segno piu' a suo agio nel mondo digitale e nelle community virtuali. Urano amplifica oggi queste connessioni, trasformando un contatto online in un'opportunita' reale e tangibile. Il futuro del lavoro e' connesso, collaborativo e senza confini: esattamente il terreno dove l'Acquario prospera.", advice: "Il futuro del lavoro e' connesso e tu sei avanti anni luce. L'Acquario che sfrutta le connessioni digitali crea opportunita' illimitate." },
      { text: "Un'intuizione geniale risolve oggi un problema professionale che sembrava impossibile. Come Acquario, le tue soluzioni non seguono mai il percorso logico tradizionale: arrivano come lampi di genio, connessioni impreviste tra idee apparentemente distanti. Urano alimenta oggi questa capacita' unica, portandoti un momento di illuminazione che cambiera' tutto. La soluzione e' la' dove nessuno ha pensato di cercare.", advice: "Le soluzioni migliori arrivano quando smetti di cercarle nel modo convenzionale. Il genio dell'Acquario si manifesta nell'inaspettato." },
      { text: "Urano ti spinge oggi a rompere gli schemi professionali con strategia e intelligenza. Come Acquario, la rivoluzione e' nel tuo sangue: non accetti lo status quo quando vedi possibilita' di miglioramento. Ma la tua rivoluzione non e' caos: e' evoluzione pianificata, cambiamento costruttivo guidato dalla visione. Oggi le stelle sostengono la tua spinta al cambiamento con energia e circostanze favorevoli.", advice: "La rivoluzione piu' efficace e' quella pianificata con intelligenza. L'Acquario che cambia le regole con strategia crea un futuro migliore." },
    ],
    pisces: [
      { text: "Nettuno ispira oggi una creativita' professionale che ha una qualita' quasi magica e trascendente. Come Pesci, il tuo lavoro migliore nasce dall'ispirazione profonda, da quella connessione con l'inconscio che altri segni non possono raggiungere. Oggi questa vena creativa e' particolarmente forte, trasformando ogni progetto che tocchi in qualcosa di artistico e speciale. La bellezza che porti nel lavoro e' il tuo marchio.", advice: "La creativita' nettuniana e' la tua risorsa professionale piu' preziosa. Il Pesci che crea con l'anima produce opere che toccano il cuore." },
      { text: "Le stelle vedono la tua intuizione professionale raggiungere livelli di precisione sorprendente. Come Pesci governato da Nettuno, hai un sesto senso per le tendenze, i bisogni del mercato e le opportunita' nascoste. Oggi questa capacita' divinatoria si manifesta in un'intuizione specifica che potrebbe guidare decisioni importanti. Quando qualcosa ti sembra giusto a livello viscerale, fidati: il tuo radar nettuniano non mente.", advice: "Quando qualcosa ti sembra giusto a livello profondo, lo e'. L'intuizione professionale del Pesci e' piu' precisa di qualsiasi analisi." },
      { text: "Un progetto creativo o artistico porta oggi soddisfazione e riconoscimento nel tuo percorso professionale. Come Pesci, la separazione tra arte e lavoro per te non esiste: tutto cio' che fai ha una dimensione estetica e emotiva. Nettuno amplifica oggi questa qualita', rendendo il tuo output professionale non solo efficace ma anche bello e toccante. Questo tocco artistico e' cio' che ti distingue dalla massa.", advice: "Non separare mai la dimensione artistica dal lavoro. Il Pesci che porta bellezza in tutto cio' che fa crea un marchio indimenticabile." },
      { text: "Le costellazioni indicano che la tua empatia naturale si rivela un potente strumento di leadership. Come Pesci, la tua capacita' di comprendere gli altri a un livello profondo ti permette di guidare con una sensibilita' che pochi leader possiedono. Nettuno amplifica oggi questa intelligenza emotiva, rendendoti il leader che tutti vorrebbero avere. Capire le persone e' il primo passo per ispirarle.", advice: "L'empatia e' la competenza di leadership piu' potente del futuro. Il Pesci che guida con il cuore crea team straordinariamente fedeli." },
      { text: "Nettuno dissolve oggi gli ostacoli professionali con una fluidita' che sembra quasi soprannaturale. Come Pesci, hai una relazione unica con il flusso della vita: sai quando nuotare controcorrente e quando lasciarti trasportare. Oggi la corrente e' a tuo favore, e cio' che sembrava un muro invalicabile si dissolve come nebbia al sole. La lezione nettuniana e' chiara: non tutto va forzato, a volte basta fluire.", advice: "Lascia che le cose fluiscano senza forzarle. Il Pesci che si fida del flusso cosmico trova la via piu' facile verso il successo." },
      { text: "Le stelle parlano di un'ispirazione quasi divina che porta un'idea brillante nella tua mente creativa. Come Pesci, le tue intuizioni migliori arrivano come lampi di luce dal profondo dell'inconscio. Nettuno oggi apre il canale con una chiarezza rara, permettendo a un'idea straordinaria di raggiungere la tua consapevolezza. Tieni sempre a portata di mano un modo per annotare: questa ispirazione non va persa.", advice: "Cattura ogni ispirazione nel momento in cui arriva. Il Pesci che annota le intuizioni nettuniane costruisce un tesoro di idee geniali." },
      { text: "La tua sensibilita' unica ti permette oggi di anticipare i bisogni del mercato e dei clienti con una precisione impressionante. Come Pesci, percepisci le correnti emotive collettive: sai cosa le persone desiderano prima ancora che lo sappiano loro. Nettuno potenzia questo radar emotivo, trasformandolo in un vantaggio competitivo concreto. L'intuizione e' il business intelligence piu' preciso nel tuo arsenale.", advice: "L'intuizione nettuniana e' il radar professionale piu' preciso. Il Pesci che ascolta il proprio sesto senso anticipa il mercato." },
      { text: "Un sogno ricorrente o un pensiero insistente nasconde un'idea professionale che potrebbe rivelarsi vincente. Come Pesci, i confini tra sogno e realta' sono sottili, e spesso le migliori idee emergono proprio da quello spazio intermedio. Nettuno comunica con te attraverso immagini e sensazioni che la mente razionale fatica a decodificare. Ma se presti attenzione, troverai in quei messaggi la chiave del prossimo passo.", advice: "Presta attenzione ai messaggi dell'inconscio nettuniano. Il Pesci che trasforma i sogni in progetti crea innovazione pura." },
      { text: "Le stelle vedono abbondanza professionale generata dalla tua generosita' e dalla tua capacita' di dare senza calcolo. Come Pesci, credi nel karma del dare: cio' che offri al mondo torna a te moltiplicato. Nettuno conferma oggi questa verita' cosmica con risultati tangibili. Il flusso dell'abbondanza non segue la logica della scarsita' ma quella della condivisione, e tu sei un maestro in questo.", advice: "Il flusso dell'abbondanza passa attraverso la generosita'. Il Pesci che dona liberamente riceve abbondanza da ogni direzione." },
      { text: "Nettuno ti connette oggi con la tua vocazione professionale piu' profonda e autentica. Come Pesci, hai bisogno che il lavoro abbia un significato che va oltre il denaro: deve nutrire la tua anima. Le stelle confermano che sei sulla strada giusta, anche se a volte il percorso sembra tortuoso. Ogni esperienza ti sta avvicinando a quella realizzazione professionale che il tuo cuore cerca da sempre.", advice: "Segui la chiamata del cuore nel lavoro, non solo quella del portafoglio. Il Pesci che lavora con l'anima trova la vera ricchezza." },
    ],
  },
  friendship: {
    aries: [
      { text: "Le stelle vedono la tua energia di fuoco contagiare positivamente tutto il tuo gruppo di amici. Come Ariete governato da Marte, sei l'amico che porta avventura, spontaneita' e una carica di vitalita' irresistibile. Oggi questa energia e' amplificata al massimo, rendendo ogni tuo invito un'occasione imperdibile. I tuoi amici adorano la tua capacita' di trasformare una serata ordinaria in un'avventura memorabile.", advice: "Organizza qualcosa di avventuroso e spontaneo con il gruppo. L'Ariete che propone per primo crea i ricordi migliori." },
      { text: "Un amico ha bisogno della tua forza e del tuo coraggio marziano oggi. Come Ariete, sei l'amico guerriero: quello che difende, protegge e combatte al fianco di chi ama. La tua lealta' feroce e' un dono raro che le stelle oggi ti chiedono di mettere in campo. Qualcuno vicino a te sta attraversando un momento difficile e la tua presenza coraggiosa puo' fare la differenza tra arrendersi e rialzarsi.", advice: "La lealta' in amicizia e' sacra per il tuo segno di fuoco. L'Ariete che difende i propri amici e' un alleato che vale un esercito." },
      { text: "Marte porta dinamismo e novita' nelle tue relazioni sociali, aprendo la porta a conoscenze stimolanti. Come Ariete, sei il segno che rompe il ghiaccio piu' facilmente, che fa il primo passo senza esitazione. Oggi questa audacia sociale ti porta incontro persone interessanti e compatibili con la tua energia. Sii il primo a parlare, a proporre, a invitare: e' nel tuo DNA marziano e funziona sempre.", advice: "Sii il primo a fare il passo verso nuove conoscenze. L'Ariete che non esita nel sociale attira le persone migliori." },
      { text: "Le costellazioni indicano la possibilita' di una riconciliazione con un amico dopo un periodo di distanza. Come Ariete, il tuo temperamento di fuoco a volte accende conflitti, ma la tua capacita' di perdonare e dimenticare e' altrettanto veloce. Marte ti dona oggi la forza di fare il primo passo verso la riappacificazione. L'orgoglio e' il nemico dell'amicizia, e tu sei abbastanza forte da superarlo.", advice: "L'orgoglio marziano a volte va messo da parte per l'amicizia. L'Ariete che sa scusarsi dimostra la forza vera." },
      { text: "La tua spontaneita' oggi attira persone autentiche e genuine nella tua cerchia. Come Ariete, non sopporti le maschere e le finzioni: vuoi amici veri che dicano le cose come stanno. Marte amplifica oggi questa tua ricerca di autenticita', portando nella tua vita relazioni basate sulla sincerita' totale. La qualita' delle amicizie conta infinitamente piu' della quantita', e oggi lo capisci piu' che mai.", advice: "Circondati di chi apprezza la tua autenticita' senza filtri. L'Ariete che sceglie amici genuini costruisce un circolo invincibile." },
      { text: "Le stelle parlano di avventure condivise che cementano legami indissolubili. Come Ariete, i tuoi ricordi piu' belli con gli amici sono quelli delle esperienze vissute insieme, dei momenti adrenalinici e delle risate condivise. Marte favorisce oggi un'esperienza di questo tipo: un'avventura, una sfida, un viaggio improvvisato. E' in questi momenti che le amicizie da buone diventano straordinarie e per la vita.", advice: "Crea esperienze memorabili con chi ami. I ricordi di avventure condivise sono il cemento piu' forte dell'amicizia." },
      { text: "Un vecchio amico riappare nella tua vita con notizie positive e una rinnovata energia. Come Ariete, le tue amicizie storiche sono forgiate nel fuoco delle esperienze condivise. Marte riaccende oggi un legame che il tempo e la distanza avevano raffreddato ma non spento. Le amicizie vere per il tuo segno sono come la brace: possono sembrare spente ma bastano poche parole per farle ardere di nuovo.", advice: "Le amicizie vere resistono al tempo e alla distanza. L'Ariete che ritrova un vecchio amico ritrova una parte di se'." },
      { text: "La tua energia positiva e contagiosa oggi migliora sensibilmente l'umore di tutti quelli che ti circondano. Come Ariete, sei il motore del gruppo: la tua vitalita' marziana si irradia come calore e entusiasmo. Oggi questo effetto e' particolarmente forte. Senza nemmeno rendertene conto, la tua semplice presenza trasforma la giornata di chi ti sta vicino. Questo e' un superpotere sociale che non va sottovalutato.", advice: "Sii la luce e l'energia nella giornata di chi ti circonda. L'Ariete che porta gioia nel gruppo e' un amico insostituibile." },
      { text: "Le stelle vedono un nuovo ingresso nella tua cerchia sociale che portera' freschezza e stimoli nuovi. Come Ariete, sei sempre aperto a nuove connessioni che portano energia e avventura. Marte favorisce oggi un incontro che potrebbe trasformarsi in un'amicizia significativa. Questa nuova persona condivide la tua passione per l'azione e l'avventura, creando fin da subito un'intesa naturale e stimolante.", advice: "Ogni nuova amicizia arricchisce il tuo universo. L'Ariete che accoglie con entusiasmo i nuovi arrivati espande le proprie possibilita'." },
      { text: "Marte ti spinge oggi a difendere un amico che ha bisogno della tua protezione. Come Ariete, la tua natura di guerriero non si manifesta solo nelle battaglie personali ma soprattutto nella difesa di chi ami. Quando un amico e' in difficolta', il tuo istinto protettivo si attiva con una forza che intimorisce gli avversari. Chi ha te come amico ha un leone al proprio fianco, pronto a ruggire per lui.", advice: "La protezione che offri ai tuoi amici e' un dono guerriero. Chi ha un Ariete come amico ha un difensore feroce e leale." },
    ],
    taurus: [
      { text: "Le stelle vedono le tue amicizie solide e profonde come le radici di una quercia centenaria. Come Toro governato da Venere, costruisci legami con la stessa pazienza e cura con cui un giardiniere coltiva le piante piu' preziose. Oggi questa solidita' si manifesta in un momento di condivisione autentica con un amico di lunga data. La profondita' dei vostri legami e' il risultato di anni di fedelta' reciproca.", advice: "Coltiva le amicizie con la stessa dedizione con cui cureresti un giardino prezioso. I legami del Toro sono eterni." },
      { text: "Un amico ti offrira' oggi un consiglio prezioso che merita tutta la tua attenzione. Come Toro, tendi a fidarti del tuo giudizio prima di tutto, ma oggi le stelle ti invitano ad ascoltare con apertura. Venere facilita una comunicazione profonda e sincera con qualcuno che ti conosce meglio di quanto pensi. I veri amici del Toro sono quelli che dicono cio' che hai bisogno di sentire, non cio' che vuoi sentire.", advice: "I veri amici dicono la verita' con amore. Il Toro che ascolta i consigli sinceri cresce insieme alle proprie amicizie." },
      { text: "Venere porta armonia e gioia nel tuo gruppo di amici, creando un momento di convivialita' perfetta. Come Toro, sei l'amico che trasforma ogni incontro in un'esperienza sensoriale: buon cibo, buona compagnia, comfort e calore. Oggi questa tua capacita' venusiana e' al massimo. Condividere un pasto preparato con amore o semplicemente stare insieme in un luogo accogliente: per il Toro, questa e' amicizia nella sua forma piu' pura.", advice: "Condividi un buon pasto e buon vino con chi ami. Il Toro che nutre gli amici con il cibo nutre anche il legame." },
      { text: "Le costellazioni indicano fedelta' reciproca e profonda nel tuo circolo piu' intimo. Come Toro, la tua lealta' non e' data con leggerezza: e' un impegno sacro che mantieni con la costanza della terra. Oggi questa fedelta' viene riconosciuta e ricambiata con uguale intensita'. I tuoi amici piu' stretti sanno di poter contare su di te in qualsiasi circostanza, e tu sai di poter contare su di loro.", advice: "Non dare mai per scontato chi c'e' sempre al tuo fianco. La fedelta' del Toro merita di essere celebrata e ricambiata." },
      { text: "La tua stabilita' e affidabilita' oggi si rivelano un punto di riferimento essenziale per il tuo gruppo di amici. Come Toro, sei la roccia su cui gli altri si appoggiano nei momenti di incertezza. Venere amplifica questa qualita', rendendoti ancora piu' presente e rassicurante. Essere l'amico affidabile non e' un ruolo noioso: e' la forma piu' alta e rispettata di amicizia che esista.", advice: "Essere il punto fermo per gli altri e' un onore, non un peso. L'affidabilita' del Toro e' la forma piu' alta di amicizia." },
      { text: "Le stelle parlano di generosita' reciproca all'interno delle tue amicizie. Come Toro governato da Venere, sei naturalmente generoso con chi ami: il tuo tempo, le tue risorse, la tua attenzione. Oggi questa generosita' torna a te moltiplicata in un gesto o una parola che ti scaldera' il cuore. Il cerchio virtuoso del dare e ricevere tra amici e' una delle esperienze piu' belle della vita.", advice: "La generosita' nelle amicizie crea un cerchio che non si spezza mai. Il Toro generoso riceve sempre piu' di quanto dona." },
      { text: "Un progetto condiviso con un amico fidato porta soddisfazione a entrambi e rafforza il legame. Come Toro, apprezzi le collaborazioni concrete dove mettere in campo le tue qualita' pratiche. Venere favorisce oggi un'attivita' condivisa che unisce l'utile al dilettevole. Lavorare insieme a un obiettivo comune, che sia un viaggio da pianificare o un progetto da realizzare, cementa l'amicizia nel modo piu' solido.", advice: "Lavorare insieme a un obiettivo rafforza il legame come nient'altro. Il Toro che condivide progetti con gli amici costruisce memorie indelebili." },
      { text: "Le stelle vedono comfort, sicurezza e calore come caratteristiche dominanti delle tue amicizie. Come Toro, offri agli amici un rifugio sicuro dove possono essere se stessi senza maschere. Venere amplifica oggi questa qualita' accogliente, rendendo la tua compagnia ancora piu' desiderata. Le amicizie migliori per il tuo segno sono quelle dove ci si sente a casa, accolti e compresi senza bisogno di parole.", advice: "Le amicizie dove puoi essere te stesso sono le piu' preziose. Il Toro che crea spazi sicuri per gli amici e' un tesoro." },
      { text: "Un amico di lunga data ti sorprendera' oggi con un gesto inaspettato che dimostra quanto tieni nella sua vita. Come Toro, a volte sottovaluti l'impatto che la tua presenza costante ha sugli altri. Ma chi ti conosce sa che la tua amicizia e' un pilastro su cui costruire. Le sorprese migliori arrivano da chi ci conosce davvero, da chi ha visto tutte le nostre stagioni e ha scelto di restare.", advice: "Le sorprese piu' belle arrivano da chi ci conosce nel profondo. Il Toro sorpreso dall'amore degli amici scopre quanto vale." },
      { text: "La tua pazienza con un amico che sta attraversando un momento difficile sara' ricompensata con gratitudine eterna. Come Toro, non abbandoni mai chi ami nei momenti bui: resti presente con la costanza della terra, offrendo supporto silenzioso ma incrollabile. Venere benedice oggi questa dedizione, promettendo che la tua presenza fara' una differenza reale. L'amicizia si misura nei momenti difficili, e tu la superi sempre.", advice: "L'amicizia vera si misura nei momenti piu' bui. Il Toro che resta al fianco dell'amico in difficolta' costruisce legami indistruttibili." },
    ],
    gemini: [
      { text: "Mercurio stimola oggi conversazioni brillanti e risate contagiose con i tuoi amici. Come Gemelli, la tua capacita' di intrattenere e stimolare e' un dono che rende ogni incontro sociale un evento. Il tuo umorismo intelligente, le tue storie avvincenti e la tua curiosita' insaziabile trasformano anche la serata piu' ordinaria in qualcosa di speciale. La leggerezza mercuriana e' il sale dell'amicizia.", advice: "La leggerezza e' il sale dell'amicizia vera. Il Gemelli che porta risate e stimoli nel gruppo e' il collante sociale perfetto." },
      { text: "Le stelle vedono nuove connessioni sociali stimolanti entrare nella tua orbita. Come Gemelli governato da Mercurio, attiri naturalmente persone interessanti e diverse tra loro. La tua rete sociale e' un caleidoscopio di personalita', culture e prospettive, e oggi si arricchisce ulteriormente. Ogni persona nuova che incontri porta con se' un mondo diverso da esplorare con la curiosita' che ti contraddistingue.", advice: "Ogni persona nuova porta una prospettiva unica e preziosa. Il Gemelli che espande la cerchia sociale espande anche la propria mente." },
      { text: "Un amico condivide oggi un'idea che accende la tua mente gemellare come una scintilla. Come Gemelli, l'ispirazione reciproca e' il cuore delle tue amicizie migliori. Mercurio amplifica questa connessione intellettuale, creando uno scambio di idee che arricchisce entrambi. Le amicizie che ti stimolano a pensare in modo diverso sono quelle che il tuo segno d'aria apprezza e cerca di piu'.", advice: "Gli amici migliori sono quelli che ti fanno pensare in modi nuovi. Il Gemelli che si circonda di menti brillanti brilla ancora di piu'." },
      { text: "Le costellazioni indicano una comunicazione straordinariamente fluida con il tuo gruppo di amici. Come Gemelli, la comunicazione e' il tuo linguaggio d'amore nelle amicizie: un messaggio al momento giusto, una chiamata inaspettata, un meme che dice tutto. Mercurio potenzia oggi questi fili invisibili che ti collegano alle persone che ami. Mantieni vivi i contatti: per il tuo segno, comunicare e' amare.", advice: "Mantieni vivi i contatti anche con un semplice messaggio. Per il Gemelli, comunicare con gli amici e' nutrire il legame." },
      { text: "La tua versatilita' oggi ti rende l'amico perfetto per qualsiasi occasione e situazione. Come Gemelli, ti adatti con naturalezza a contesti diversi, passando dal serio al giocoso senza sforzo. Mercurio amplifica questa capacita' camaleontica, permettendoti di essere esattamente cio' di cui ogni amico ha bisogno in quel momento. Questa adattabilita' non e' superficialita': e' intelligenza sociale pura.", advice: "Adattarsi a ogni situazione e' intelligenza sociale, non incoerenza. La versatilita' del Gemelli e' un dono che ogni gruppo apprezza." },
      { text: "Le stelle parlano di divertimento puro e spensieratezza nelle tue relazioni amicali. Come Gemelli, porti una ventata di freschezza ovunque vai, ricordando a tutti che la vita e' anche gioco e risate. Mercurio favorisce oggi momenti di pura gioia condivisa, senza complicazioni o pesantezze. Non serve un motivo per festeggiare con gli amici: la vostra compagnia reciproca e' gia' motivo sufficiente.", advice: "Non serve un motivo speciale per festeggiare l'amicizia. Il Gemelli che porta gioia nel quotidiano rende la vita piu' bella per tutti." },
      { text: "Un invito inaspettato porta a un incontro che si rivela memorabile e pieno di sorprese. Come Gemelli, la tua vita sociale e' piena di momenti imprevisti che spesso si trasformano nelle esperienze migliori. Mercurio favorisce oggi la spontaneita' e gli incontri casuali che diventano ricordi indimenticabili. Di' sempre si' agli inviti dell'ultimo minuto: il tuo segno d'aria trova le perle nei momenti improvvisati.", advice: "Di' sempre si' agli inviti spontanei e inaspettati. Il Gemelli che accoglie l'imprevisto colleziona le esperienze piu' belle." },
      { text: "Mercurio favorisce oggi la risoluzione di una piccola incomprensione con un amico attraverso il dialogo aperto. Come Gemelli, hai il dono della parola e oggi questo talento si esprime al suo meglio nel territorio delicato dei chiarimenti. Una conversazione sincera e priva di giudizio puo' dissolvere in pochi minuti tensioni che il silenzio alimenterebbe per settimane. Parla apertamente: le parole giuste guariscono.", advice: "Un dialogo sincero e aperto vale piu' di mille silenzi. Il Gemelli che comunica con onesta' risolve ogni malinteso." },
      { text: "Le stelle vedono il tuo circolo sociale espandersi con l'arrivo di volti nuovi e interessanti. Come Gemelli, sei il connettore naturale dello zodiaco: metti in contatto persone che non si sarebbero mai incontrate senza di te. Mercurio amplifica oggi questo ruolo, portandoti incontri che arricchiscono non solo la tua vita ma quella di tutto il gruppo. La tua apertura mentale e' un magnete per anime affini.", advice: "L'apertura mentale del Gemelli attira le persone piu' interessanti. Continua a espandere la tua rete con curiosita' e entusiasmo." },
      { text: "La tua capacita' unica di intrattenere e far divertire rende oggi ogni incontro con te un momento speciale. Come Gemelli, il tuo umorismo brillante e la tua arte nel racconto trasformano aneddoti ordinari in storie epiche. Mercurio potenzia questo talento naturale, rendendoti il centro di ogni conversazione non per ego ma per puro fascino comunicativo. Il tuo dono di far sorridere gli altri e' un tesoro inestimabile.", advice: "Il tuo umorismo e la tua arte narrativa sono doni preziosi. Il Gemelli che fa ridere e pensare e' un amico insostituibile." },
    ],
    cancer: [
      { text: "La Luna illumina oggi le amicizie piu' intime del tuo cuore, portando alla luce la profondita' dei tuoi legami. Come Cancro, non hai tanti amici ma quelli che hai sono legami dell'anima, connessioni che vanno oltre la superficie. Oggi uno di questi legami si approfondisce ulteriormente, raggiungendo un livello di intimita' e comprensione reciproca che pochi conoscono. L'amicizia per te e' famiglia scelta.", advice: "Le amicizie piu' profonde sono quelle del cuore. Il Cancro che nutre i legami intimi crea una famiglia scelta e indistruttibile." },
      { text: "Le stelle vedono un amico che ha bisogno del tuo calore lunare e della tua capacita' unica di comprendere senza giudicare. Come Cancro, sei il rifugio emotivo dello zodiaco: chi viene da te sa di trovare ascolto, comprensione e un abbraccio che guarisce. Oggi qualcuno si avvicinera' cercando esattamente questo. Il tuo dono di sentire le emozioni altrui come fossero tue e' la medicina di cui hanno bisogno.", advice: "Un abbraccio sincero puo' cambiare la giornata di qualcuno. Il Cancro che offre il suo calore guarisce chi gli sta vicino." },
      { text: "Un ricordo condiviso con un amico di lunga data emerge oggi rafforzando un legame gia' profondo. Come Cancro, la nostalgia non e' per te malinconia ma un modo per onorare i momenti che hanno costruito le tue amicizie. La Luna amplifica questa connessione con il passato, trasformando un ricordo in un ponte che collega ieri a oggi. Le amicizie antiche del Cancro sono tesori che il tempo rende piu' preziosi.", advice: "La nostalgia condivisa con un amico e' un collante potentissimo. Il Cancro che onora i ricordi rafforza i legami nel presente." },
      { text: "Le costellazioni indicano protezione reciproca come tema dominante nelle tue amicizie. Come Cancro, il tuo istinto protettivo si estende naturalmente a chi consideri parte della tua famiglia emotiva. Oggi questa protezione reciproca si manifesta in modo tangibile: un amico ti coprira' le spalle quando ne avrai bisogno, e tu farai lo stesso per lui. Questo scudo emotivo condiviso e' la forza del tuo cerchio intimo.", advice: "Gli amici veri si proteggono a vicenda come una famiglia. Il Cancro che protegge i propri amici riceve protezione uguale e sincera." },
      { text: "La tua empatia lunare oggi ti rende il confidente perfetto per un amico che ha bisogno di aprirsi. Come Cancro, ascoltare non e' per te un atto passivo ma una forma attiva di amore. Quando qualcuno si confida con te, offri molto piu' di un orecchio: offri la tua comprensione profonda, la tua assenza di giudizio, il tuo cuore aperto. Oggi qualcuno scegliera' te come custode dei propri segreti.", advice: "Ascoltare con il cuore aperto e' il regalo piu' grande che puoi fare. Il Cancro confidente e' un tesoro che gli amici custodiscono gelosamente." },
      { text: "Le stelle parlano dei tuoi amici come una famiglia scelta con il cuore, non con il sangue. Come Cancro, per te non esiste distinzione tra amici intimi e famiglia: chi entra nel tuo cerchio interno riceve lo stesso amore incondizionato. La Luna benedice oggi questa tribu' del cuore, rafforzando i legami che hai costruito con cura e dedizione. La famiglia che scegli e' spesso quella che ti capisce di piu'.", advice: "La famiglia del cuore e' quella che scegli con l'anima. Il Cancro che crea una tribu' di amici veri non sara' mai solo." },
      { text: "Un gesto di cura e attenzione verso un amico lascia oggi un segno indelebile nella sua memoria. Come Cancro, esprimi l'amicizia attraverso azioni concrete: preparare qualcosa per qualcuno, ricordare un dettaglio importante, essere presente nel momento del bisogno. La Luna amplifica oggi l'impatto di questi gesti apparentemente piccoli. Per chi li riceve, sono grandi come il mare del tuo segno d'acqua.", advice: "I piccoli gesti di cura creano i grandi legami. Il Cancro che si prende cura degli amici con i dettagli costruisce amicizie eterne." },
      { text: "La Luna porta oggi un'intuizione chiara su cio' che un amico ha bisogno, anche se non lo chiede esplicitamente. Come Cancro, il tuo radar emotivo percepisce le sfumature che sfuggono a tutti gli altri. Capirai esattamente cosa serve a chi ami prima ancora che lo esprima. Questa capacita' quasi telepatica e' il segno di un'amicizia cosi' profonda da trascendere le parole. Agisci su questa intuizione.", advice: "Non aspettare che ti chiedano aiuto: offilo spontaneamente. L'intuizione del Cancro sa sempre cosa serve ai propri amici." },
      { text: "Le stelle vedono una riunione gioiosa con il tuo gruppo di amici piu' cari. Come Cancro, i momenti di condivisione con le persone che ami sono nutrimento per la tua anima. La Luna favorisce oggi un incontro che riempie il cuore di calore e appartenenza. Organizza un momento di ritrovo: la tua capacita' di creare atmosfere accoglienti trasformera' una semplice riunione in un ricordo che tutti custodiranno.", advice: "Organizza un incontro con chi ami di piu'. Il Cancro che riunisce il suo cerchio crea momenti di pura magia emotiva." },
      { text: "La tua sensibilita' lunare oggi ti permette di notare quando un amico soffre in silenzio dietro un sorriso. Come Cancro, vedi oltre le maschere con una chiarezza che gli altri segni non possiedono. Un semplice 'come stai davvero?' pronunciato con la sincerita' del tuo cuore acquatico puo' abbattere le difese e permettere a qualcuno di sentirsi finalmente visto e compreso. Questo e' il potere dell'empatia.", advice: "Un 'come stai davvero?' detto con il cuore fa miracoli. La sensibilita' del Cancro vede oltre le maschere e guarisce le ferite nascoste." },
    ],
    leo: [
      { text: "Il Sole rende oggi le tue amicizie luminose, calde e piene di vita, esattamente come il tuo spirito leonino. Come Leone, sei il cuore pulsante del tuo gruppo: la tua energia solare irradia gioia e calore a tutti quelli che ti circondano. Oggi questa qualita' e' al suo massimo. La tua semplice presenza trasforma qualsiasi ritrovo in una celebrazione, perche' dove c'e' il Leone, c'e' sempre festa.", advice: "Usa la tua luce solare per illuminare anche chi attraversa momenti bui. Il Leone generoso con il proprio calore e' un amico indimenticabile." },
      { text: "Le stelle vedono una celebrazione speciale con gli amici che riempira' il tuo cuore di gioia pura. Come Leone governato dal Sole, ami festeggiare la vita e le persone che la rendono speciale. Oggi le costellazioni portano un momento di festa, che sia un traguardo raggiunto da un amico o semplicemente la gioia di stare insieme. La tua capacita' di trasformare ogni occasione in un evento e' un dono che tutti apprezzano.", advice: "Festeggia ogni piccola e grande vittoria con chi ami. Il Leone che celebra l'amicizia con generosita' crea ricordi che durano per sempre." },
      { text: "Un amico riconosce oggi la tua generosita' leonina con una gratitudine sincera che ti commuove. Come Leone, dai molto nelle amicizie: il tuo tempo, la tua energia, il tuo supporto incondizionato. A volte ti chiedi se questo viene notato, e oggi la risposta arriva forte e chiara. La gratitudine sincera di chi hai aiutato e' la ricompensa piu' bella per il tuo grande cuore solare.", advice: "Dare senza aspettarsi nulla e' la nobilta' del tuo spirito leonino. Ma oggi accetta la gratitudine con la grazia di chi sa di meritarla." },
      { text: "Le costellazioni indicano che il tuo ruolo naturale di leader nel gruppo oggi e' particolarmente importante. Come Leone, tutti guardano a te per ispirazione, motivazione e direzione. Il Sole amplifica questa leadership sociale, dandoti la capacita' di guidare il gruppo verso esperienze condivise memorabili. Ma ricorda: la leadership leonina migliore e' quella che mette gli altri al centro, non se stessa.", advice: "Guida il gruppo con generosita' e umilta'. Il Leone che usa la leadership per far brillare gli altri brilla ancora di piu'." },
      { text: "La tua lealta' feroce e incondizionata oggi protegge qualcuno che ne ha bisogno. Come Leone, quando un amico e' minacciato o in difficolta', il tuo istinto protettivo si attiva con una forza che intimorisce. Il Sole alimenta questa lealta' regale, rendendoti lo scudo piu' potente che un amico possa desiderare. Chi ha te al proprio fianco sa di poter affrontare qualsiasi cosa senza paura.", advice: "Chi ha un Leone come amico ha un protettore regale al fianco. La tua lealta' feroce e' un dono che pochi sanno offrire." },
      { text: "Le stelle parlano di una serata o un momento memorabile con gli amici che si avvicina. Come Leone, hai il talento innato per organizzare e animare incontri che diventano leggende nel gruppo. Il Sole ti ispira oggi a creare qualcosa di speciale: una cena, un'uscita, una sorpresa. La tua capacita' di trasformare l'ordinario in straordinario e' il motivo per cui sei sempre al centro dei ricordi migliori.", advice: "Crea momenti che diventino storie da raccontare per anni. Il Leone che organizza con il cuore regala esperienze indimenticabili." },
      { text: "Un amico ha bisogno della tua motivazione e delle tue parole di incoraggiamento oggi. Come Leone governato dal Sole, le tue parole hanno il potere di accendere la fiamma della motivazione in chi si sente spento. Oggi questa capacita' ispirazionale e' particolarmente forte. Un discorso sincero, un messaggio di supporto, una parola di fiducia: dal tuo cuore solare possono scaturire parole che cambiano prospettive.", advice: "Le tue parole di incoraggiamento hanno un potere enorme. Il Leone che motiva gli amici accende luci che non si spengono." },
      { text: "Il Sole porta calore e gioia in ogni tua interazione amicale oggi. Come Leone, hai la capacita' rara di far sentire chiunque speciale e importante quando e' con te. Questa generosita' di attenzione e' il tuo dono solare piu' grande nelle amicizie. Oggi un complimento sincero, un gesto di apprezzamento o semplicemente il tuo sorriso luminoso illuminera' la giornata di qualcuno in modo indimenticabile.", advice: "Un complimento sincero dal cuore del Leone illumina la giornata intera. Non sottovalutare mai il potere della tua luce sugli altri." },
      { text: "Le stelle vedono orgoglio genuino e gioia per il successo di un amico caro. Come Leone, la tua generosita' di spirito ti permette di gioire dei traguardi altrui come fossero tuoi. Oggi un amico raggiunge un obiettivo importante e la tua felicita' per lui e' autentica e traboccante. Questa capacita' di celebrare gli altri senza invidia e' la marca della vera nobilta' d'animo del tuo segno solare.", advice: "Gioire per gli altri e' la forma piu' pura e nobile di amicizia. Il Leone che celebra i successi altrui eleva tutto il gruppo." },
      { text: "La tua presenza trasforma oggi qualsiasi riunione amicale in un evento memorabile. Come Leone, porti con te un'energia che e' impossibile ignorare: vitalita', calore, carisma e un'irrefrenabile voglia di vivere. Il Sole amplifica questa aura, rendendoti il catalizzatore di ogni momento sociale. Non sottovalutare l'effetto che la tua semplice presenza ha sugli altri: per molti, sei la ragione per cui vale la pena uscire.", advice: "Non sottovalutare mai il tuo effetto sugli altri. La presenza del Leone trasforma ogni momento ordinario in un'occasione straordinaria." },
    ],
    virgo: [
      { text: "Le stelle vedono un amico che apprezza profondamente i tuoi consigli pratici e la tua saggezza terrestre. Come Vergine governata da Mercurio, offri un tipo di amicizia rara: quella basata sul supporto concreto e sul problem solving. Quando un amico viene da te con un problema, non trova solo comprensione ma anche soluzioni pratiche e applicabili. Questa combinazione di empatia e pragmatismo e' il tuo dono unico.", advice: "La tua saggezza pratica e' un dono raro e prezioso. La Vergine che aiuta con soluzioni concrete e' l'amico che tutti vorrebbero avere." },
      { text: "Mercurio favorisce oggi l'organizzazione di un incontro perfetto nei minimi dettagli. Come Vergine, quando organizzi qualcosa lo fai con una cura che trasforma anche un semplice caffe' in un'esperienza impeccabile. I tuoi amici sanno che quando sei tu a organizzare, tutto funzionera' alla perfezione. Oggi questo talento organizzativo si esprime al meglio, creando un momento che tutti apprezzeranno.", advice: "I dettagli che curi con tanta attenzione rendono ogni momento speciale. La Vergine organizzatrice crea esperienze che gli amici ricordano." },
      { text: "Un amico nota oggi il tuo impegno silenzioso e costante e decide di dirti quanto significhi per lui. Come Vergine, non cerchi mai riconoscimenti per la tua dedizione nelle amicizie: fai le cose perche' ti viene naturale, non per essere ringraziato. Ma oggi qualcuno che ti conosce davvero trovera' le parole per esprimerti gratitudine sincera. Accettala senza sminuirti: la meriti pienamente.", advice: "Chi ti conosce davvero vede tutto cio' che fai in silenzio. La Vergine che accetta la gratitudine senza sminuirsi onora l'amicizia." },
      { text: "Le costellazioni indicano un momento in cui il tuo supporto pratico fa una differenza reale nella vita di un amico. Come Vergine, il tuo modo di aiutare e' concreto: non offri solo parole di conforto ma soluzioni, piani d'azione, assistenza pratica. Mercurio amplifica oggi questa capacita', guidandoti verso l'azione giusta al momento giusto. A volte aiutare davvero significa fare, non solo parlare.", advice: "A volte aiutare significa agire concretamente. La Vergine che offre supporto pratico risolve problemi che le parole non possono." },
      { text: "La tua affidabilita' leggendaria oggi cementa un'amicizia rendendola ancora piu' solida e duratura. Come Vergine, la tua costanza non fa notizia ma fa la differenza: esserci sempre, rispettare gli impegni, mantenere le promesse. Mercurio oggi evidenzia questa qualita' silenziosa ma fondamentale. Le amicizie piu' durature non si costruiscono sui gesti eclatanti ma sulla presenza costante e affidabile.", advice: "Essere presenti costantemente e' la vera amicizia. L'affidabilita' della Vergine e' il cemento piu' forte che esista nei legami." },
      { text: "Le stelle parlano di miglioramento reciproco come tema dominante nelle tue amicizie. Come Vergine, cerchi amici che ti stimolino a crescere e a migliorare, e offri lo stesso in cambio. Mercurio favorisce oggi scambi di idee che elevano entrambe le parti. Le amicizie che ti fanno diventare una versione migliore di te stesso sono quelle che il tuo segno di terra apprezza e coltiva con piu' dedizione.", advice: "Circondati di chi ti stimola a crescere e ricambia lo stimolo. La Vergine che migliora insieme agli amici eleva tutto il gruppo." },
      { text: "Un consiglio che dai oggi a un amico avra' un impatto profondo e duraturo sulla sua prospettiva. Come Vergine, le tue parole sono misurate, pensate e sempre pertinenti. Non sprechi fiato in luoghi comuni ma offri osservazioni precise che vanno al cuore del problema. Mercurio affina oggi questa capacita', dandoti le parole esatte che il tuo amico ha bisogno di sentire. La chiarezza e' il tuo regalo.", advice: "Le parole giuste al momento giusto sono un dono prezioso. La Vergine che consiglia con precisione cambia prospettive e vite." },
      { text: "Mercurio porta chiarezza e comprensione in una dinamica di gruppo che era diventata complicata. Come Vergine, la tua capacita' di analizzare le situazioni sociali con lucidita' ti permette di vedere le cause dei malintesi dove altri vedono solo confusione. Oggi questa visione analitica si rivela essenziale per riportare armonia nel gruppo. La tua analisi obiettiva e gentile dissolve le tensioni come nebbia al sole.", advice: "La tua analisi lucida risolve conflitti che sembravano impossibili. La Vergine mediatrice porta pace con intelligenza e delicatezza." },
      { text: "Le stelle vedono ordine e armonia stabilirsi nel tuo circolo sociale grazie alla tua influenza stabilizzante. Come Vergine, porti struttura e organizzazione anche nelle dinamiche amicali. Mercurio favorisce oggi la creazione di abitudini e rituali condivisi con gli amici: un appuntamento fisso, una tradizione settimanale, un progetto comune. Le amicizie sane hanno confini rispettati e routine che le nutrono.", advice: "Le amicizie sane hanno routine e confini rispettati. La Vergine che porta struttura nelle relazioni le rende piu' forti." },
      { text: "La tua attenzione ai bisogni degli altri ti rende oggi un amico letteralmente insostituibile. Come Vergine, noti cose che tutti gli altri ignorano: il tono leggermente diverso nella voce, il sorriso che non raggiunge gli occhi, il messaggio non inviato. Mercurio amplifica questa sensibilita' ai dettagli, permettendoti di essere presente per i tuoi amici nel modo piu' preciso e mirato possibile. Notare i dettagli e' amare.", advice: "Notare i piccoli dettagli degli amici e' la forma piu' attenta di amore. La Vergine che osserva con cura ama con precisione." },
    ],
    libra: [
      { text: "Venere porta armonia perfetta nelle tue amicizie, creando un equilibrio sociale che solo la Bilancia sa raggiungere. Come segno d'aria governato da Venere, sei il tessitore naturale di relazioni: metti in contatto persone, appiani conflitti e crei atmosfere dove tutti si sentono a proprio agio. Oggi questa abilita' venusiana raggiunge il suo apice, rendendo ogni tua interazione un piccolo capolavoro di grazia sociale.", advice: "L'armonia nelle relazioni e' la tua arte piu' raffinata. La Bilancia che armonizza il gruppo crea uno spazio dove tutti fioriscono." },
      { text: "Le stelle vedono il tuo talento diplomatico risolvere una tensione nel gruppo con eleganza e grazia. Come Bilancia, hai la capacita' unica di vedere le ragioni di tutti senza schierarti, trovando il punto d'incontro che soddisfa ogni parte. Venere amplifica oggi questa dote preziosa, rendendo la tua mediazione non solo efficace ma quasi magica. Dove c'era conflitto, dopo il tuo intervento c'e' comprensione.", advice: "La tua diplomazia venusiana e' un superpotere sociale raro. La Bilancia che media con grazia trasforma i conflitti in opportunita' di crescita." },
      { text: "Un'amicizia si eleva oggi a un livello di comprensione reciproca piu' profondo e autentico. Come Bilancia, cerchi nelle amicizie lo stesso equilibrio e la stessa armonia che cerchi in ogni aspetto della vita. Venere favorisce oggi un momento di apertura reciproca con qualcuno di speciale. I rapporti migliori sono quelli che evolvono continuamente, e oggi il tuo evolve verso una consapevolezza nuova e bellissima.", advice: "I rapporti migliori evolvono e si approfondiscono nel tempo. La Bilancia che cresce insieme agli amici raggiunge livelli di connessione rari." },
      { text: "Le costellazioni indicano l'arrivo di un nuovo amico che condivide profondamente i tuoi valori di armonia e giustizia. Come Bilancia, non cerchi amicizie basate sulla convenienza ma su valori condivisi e rispetto reciproco. Venere porta oggi nella tua vita una persona la cui visione del mondo rispecchia la tua. Le amicizie basate sui valori sono quelle destinate a durare per tutta la vita.", advice: "Le amicizie basate sui valori condivisi sono le piu' durature. La Bilancia che trova anime affini costruisce legami per la vita." },
      { text: "La tua grazia sociale oggi rende ogni interazione con gli amici piacevole e significativa. Come Bilancia governata da Venere, hai il dono di far sentire ogni persona speciale e ascoltata. Questa gentilezza non e' superficiale: e' l'espressione naturale del tuo desiderio profondo di armonia. Oggi questa qualita' tocca particolarmente chi ti sta vicino, creando momenti di connessione autentica e appagante.", advice: "La gentilezza venusiana e' la chiave universale per ogni cuore. La Bilancia che tratta gli amici con grazia riceve grazia in cambio." },
      { text: "Le stelle parlano di giustizia ed equilibrio perfetto nelle tue amicizie. Come Bilancia, sei naturalmente attento a che il dare e il ricevere siano bilanciati in ogni rapporto. Venere oggi conferma che le tue amicizie piu' significative sono quelle dove questa reciprocita' e' reale e sentita. Non si tratta di tenere il conto ma di sentire che l'investimento emotivo e' condiviso equamente.", advice: "L'equilibrio nel dare e ricevere e' il segreto delle amicizie durature. La Bilancia che bilancia anche le relazioni trova la serenita'." },
      { text: "Un evento sociale porta gioia, nuove connessioni e un senso di appartenenza che nutre il tuo spirito. Come Bilancia, sei il segno piu' a suo agio nei contesti sociali raffinati dove l'interazione e' un'arte. Venere favorisce oggi la partecipazione a un evento o un incontro che soddisfa il tuo bisogno di bellezza e compagnia. La tua presenza elegante arricchisce qualsiasi contesto sociale.", advice: "Partecipa attivamente alla vita sociale con lo stile della Bilancia. La tua presenza elegante trasforma ogni incontro in un'occasione speciale." },
      { text: "Venere favorisce oggi la bellezza nelle relazioni, spingendoti a eliminare la negativita' e a coltivare solo il positivo. Come Bilancia, hai un senso estetico che si applica anche alle amicizie: cerchi relazioni belle, armoniose e elevanti. Oggi le stelle ti danno la chiarezza per distinguere le amicizie che ti nutrono da quelle che ti svuotano. Circondati di persone che portano luce nella tua vita.", advice: "Le amicizie che non portano bellezza nella tua vita non meritano il tuo tempo. La Bilancia che sceglie con cura crea un cerchio prezioso." },
      { text: "Le stelle vedono una collaborazione creativa con un amico che produce qualcosa di bello e significativo. Come Bilancia, la creativita' condivisa e' una delle tue esperienze piu' appaganti. Venere ispira oggi un progetto artistico o creativo che rafforza il legame con qualcuno di speciale. Creare qualcosa insieme, che sia un viaggio, un'opera o un'idea, e' il modo in cui la Bilancia cementa le amicizie piu' care.", advice: "Creare qualcosa insieme e' il cemento piu' bello per un'amicizia. La Bilancia che collabora creativamente con gli amici genera bellezza." },
      { text: "La tua capacita' unica di vedere il bello nelle persone fa sentire oggi i tuoi amici veramente speciali. Come Bilancia, hai il dono di riconoscere e valorizzare le qualita' migliori di chi ti circonda. Venere amplifica questa visione positiva, permettendoti di esprimere apprezzamento sincero che tocca il cuore. Ogni persona ha qualcosa di unico e bello: il tuo talento e' trovarlo e illuminarlo.", advice: "Ogni persona ha qualcosa di unico e bello: il tuo talento e' scoprirlo. La Bilancia che valorizza gli amici li rende versioni migliori di se stessi." },
    ],
    scorpio: [
      { text: "Le stelle vedono lealta' profonda e incrollabile come fondamento delle tue amicizie scorpioniche. Come Scorpione governato da Plutone, i tuoi legami amicali non sono mai superficiali: sono patti sacri, connessioni dell'anima che attraversano il tempo e le difficolta'. Oggi questa lealta' viene messa in luce e apprezzata da chi la riceve. Chi guadagna la tua fiducia possiede un tesoro di valore inestimabile.", advice: "Chi guadagna la tua fiducia ha un tesoro inestimabile. La lealta' dello Scorpione e' assoluta e chi la riceve non la dimentica mai." },
      { text: "Plutone intensifica oggi un legame amicale portandolo a un livello di profondita' che pochi conoscono. Come Scorpione, le tue amicizie non vivono in superficie: esplorano le profondita' dell'anima umana. Oggi una conversazione con un amico fidato raggiunge livelli di intimita' e verita' che trasformano il rapporto. Questa connessione profonda e' il tipo di amicizia che il tuo segno d'acqua cerca e che raramente trova.", advice: "Le amicizie piu' autentiche sono quelle che non temono la profondita'. Lo Scorpione che si apre con gli amici fidati crea legami eterni." },
      { text: "Un amico ti rivela un segreto importante oggi, confermando la fiducia assoluta che ripone in te. Come Scorpione, sei il custode naturale dei segreti: le persone sentono istintivamente che possono confidarti le verita' piu' delicate. Plutone rafforza oggi questa reputazione di discrezione e affidabilita'. La capacita' di custodire i segreti altrui e' una forma di rispetto e amore che il tuo segno onora profondamente.", advice: "Custodire i segreti degli amici e' un atto sacro di rispetto. Lo Scorpione confidente protegge le verita' affidategli con la vita." },
      { text: "Le costellazioni indicano un'evoluzione positiva nelle dinamiche del tuo gruppo di amici. Come Scorpione, comprendi che i gruppi, come le persone, attraversano fasi di trasformazione. Plutone favorisce oggi un cambiamento nella struttura del tuo cerchio sociale che, anche se inizialmente scomodo, portera' a un equilibrio migliore. Le amicizie che sopravvivono alla trasformazione ne escono piu' forti e autentiche.", advice: "I gruppi cambiano e evolvono come le persone. Lo Scorpione che accoglie la trasformazione nelle amicizie le rende piu' autentiche." },
      { text: "La tua intensita' emotiva crea oggi legami che altri segni non riescono nemmeno a immaginare. Come Scorpione, non conosci le amicizie tiepide: per te e' tutto o niente, profondita' o superficie. Plutone amplifica questa qualita', portandoti in una connessione cosi' intensa con un amico da sembrare quasi telepatica. Questa intensita' non e' per tutti, ma chi la accetta scopre l'amicizia nella sua forma piu' pura.", advice: "La tua profondita' crea legami che trascendono l'ordinario. Lo Scorpione che ama intensamente offre un'amicizia che trasforma." },
      { text: "Le stelle parlano della tua feroce protezione verso chi ami manifestarsi in modo concreto. Come Scorpione, quando un amico e' minacciato o trattato ingiustamente, il tuo istinto plutoniano si attiva con una forza primordiale. Oggi questa protezione e' necessaria e apprezzata. La tua capacita' di difendere chi ami con intelligenza e determinazione e' una qualita' che rende la tua amicizia un rifugio sicuro.", advice: "Difendi chi ti sta a cuore con la determinazione dello Scorpione. La tua protezione feroce e' un dono che gli amici non dimenticano mai." },
      { text: "Un tradimento passato si trasforma oggi in saggezza che rafforza le tue amicizie presenti. Come Scorpione, le ferite del passato non si dimenticano facilmente, ma Plutone ti insegna a trasformarle in lezioni preziose. Le cicatrici che porti ti hanno reso piu' selettivo e attento, e questo e' un bene. Chi supera il tuo filtro di fiducia e' davvero degno della tua amicizia profonda e incondizionata.", advice: "Le cicatrici del passato insegnano chi merita la tua fiducia. Lo Scorpione che impara dal dolore sceglie amici degni del suo cuore." },
      { text: "Plutone favorisce oggi la rinascita di un'amicizia che sembrava irrimediabilmente compromessa. Come Scorpione, credi nel potere della trasformazione e della rinascita in ogni ambito della vita. Un legame che aveva attraversato una fase di morte apparente mostra oggi segni di vita nuova. Non tutte le amicizie sono destinate a sopravvivere, ma quelle che attraversano il fuoco e rinascono sono eterne.", advice: "Le amicizie che attraversano il fuoco e rinascono sono le piu' forti. Lo Scorpione sa che la morte apparente precede la rinascita." },
      { text: "Le stelle vedono il tuo circolo di amici come un gruppo ristretto ma di qualita' assoluta. Come Scorpione, preferisci pochi amici veri a molte conoscenze superficiali. Plutone conferma oggi la saggezza di questa scelta: le persone che hai selezionato con il tuo sesto senso infallibile sono gemme rare. Ogni amico nel tuo cerchio intimo ha superato prove di lealta' e autenticita' che pochi avrebbero superato.", advice: "Pochi ma autentici e' la filosofia vincente dello Scorpione. La qualita' delle amicizie vale infinitamente piu' della quantita'." },
      { text: "La tua capacita' di leggere le persone ti protegge oggi da chi non merita la tua fiducia e il tuo tempo. Come Scorpione, il tuo radar emotivo percepisce le intenzioni nascoste con una precisione che intimidisce. Plutone potenzia oggi questo sesto senso, aiutandoti a distinguere con chiarezza chi e' sincero da chi indossa una maschera. Fidati del tuo istinto: raramente sbaglia nella valutazione delle persone.", advice: "Fidati del tuo istinto nella valutazione delle persone. Lo Scorpione che ascolta il proprio radar emotivo si circonda solo di anime vere." },
    ],
    sagittarius: [
      { text: "Giove espande la tua cerchia sociale in modo spettacolare, portando amici da contesti e culture diverse. Come Sagittario, l'amicizia per te non conosce confini: il tuo cuore e' grande quanto il mondo che ami esplorare. Oggi le stelle portano connessioni internazionali o interculturali che arricchiscono enormemente la tua prospettiva. Ogni nuovo amico e' una finestra su un mondo diverso dal tuo.", advice: "L'amicizia non conosce confini geografici o culturali. Il Sagittario che abbraccia la diversita' arricchisce immensamente la propria vita." },
      { text: "Le stelle vedono avventure emozionanti condivise con gli amici che creeranno legami indimenticabili. Come Sagittario governato da Giove, credi che le esperienze condivise siano il collante piu' forte dell'amicizia. Oggi le costellazioni favoriscono un viaggio, un'escursione o un'esperienza nuova da vivere insieme. I ricordi che creerete in questa avventura diventeranno storie che racconterete per anni.", advice: "Le esperienze condivise creano legami che nulla puo' spezzare. Il Sagittario che esplora con gli amici crea memorie eterne." },
      { text: "La tua onesta' diretta e senza filtri viene oggi apprezzata come mai prima da un amico che ne aveva bisogno. Come Sagittario, la tua sincerita' a volte puo' sembrare brutale, ma chi ti conosce sa che viene sempre dal cuore. Giove amplifica oggi questa verita' sagittariana, dandole la giusta dose di gentilezza. Un amico ti ringrazia per aver detto cio' che nessun altro aveva il coraggio di dire.", advice: "La verita' detta con amore e' il regalo piu' grande nelle amicizie. L'onesta' del Sagittario e' rara e preziosa in un mondo di convenevoli." },
      { text: "Le costellazioni indicano che il tuo ottimismo contagioso sta sollevando il morale dell'intero gruppo. Come Sagittario, porti speranza e positivita' anche nei momenti piu' bui. Giove amplifica questa energia ottimista, rendendola un faro per chi si sente perso. La tua capacita' di vedere il bicchiere mezzo pieno non e' ingenuita': e' una scelta consapevole che ispira gli altri a fare lo stesso.", advice: "Il tuo entusiasmo sagittariano e' la medicina migliore per il morale. L'ottimismo contagioso del Sagittario guarisce l'anima degli amici." },
      { text: "Giove porta fortuna anche attraverso le amicizie: un contatto sociale oggi apre una porta inaspettata. Come Sagittario, la tua rete di amicizie e' anche una rete di opportunita'. Oggi una connessione amicale si rivela provvidenziale, portando un'occasione che non saresti mai riuscito a trovare da solo. Le connessioni giuste, quelle nate dalla genuinita' e non dal calcolo, possono letteralmente cambiare la vita.", advice: "Le connessioni giuste nate dall'amicizia vera cambiano la vita. Il Sagittario che coltiva amicizie genuine raccoglie opportunita' inaspettate." },
      { text: "Le stelle parlano di liberta' condivisa come valore fondamentale nelle tue amicizie. Come Sagittario, hai bisogno di amici che rispettino la tua indipendenza senza sentirsene minacciati. Giove conferma oggi che le amicizie piu' sane sono quelle dove ciascuno e' libero di essere se stesso. Non c'e' possesso, non c'e' obbligo: solo la scelta quotidiana di esserci l'uno per l'altro.", advice: "Le amicizie sane rispettano la liberta' di ciascuno. Il Sagittario che trova amici liberi come lui costruisce rapporti senza catene." },
      { text: "Un'avventura spontanea con gli amici crea oggi un ricordo che diventa immediatamente leggendario. Come Sagittario, i tuoi momenti migliori sono quelli non pianificati, le decisioni prese all'ultimo secondo, i si' detti senza pensarci troppo. Giove favorisce oggi questa spontaneita', portando un'esperienza condivisa che supera ogni aspettativa. Le storie migliori iniziano sempre con 'non ci crederai, ma...'.", advice: "Di' sempre si' alle proposte spontanee dell'ultimo minuto. Il Sagittario che abbraccia l'imprevisto colleziona le avventure piu' belle." },
      { text: "La tua filosofia di vita espansiva e ottimista oggi ispira gli amici a vedere il mondo con occhi nuovi. Come Sagittario, sei un maestro di vita naturale: le tue intuizioni, le tue esperienze, la tua visione ampia del mondo sono risorse preziose per chi ti circonda. Giove amplifica questa qualita' ispirazionale, rendendo le tue parole oggi particolarmente significative e illuminanti per chi le ascolta.", advice: "Condividi la tua visione del mondo con generosita'. Le parole del Sagittario hanno il potere di aprire menti e cuori." },
      { text: "Le stelle vedono risate genuine, gioia condivisa e un momento di pura felicita' amicale. Come Sagittario governato dal generoso Giove, la tua risata e' contagiosa e la tua gioia di vivere e' un regalo per chiunque ti stia vicino. Oggi questo aspetto del tuo carattere brilla con una luce particolare, creando un momento di connessione leggera ma profonda con i tuoi amici. La risata condivisa e' il cemento invisibile dell'amicizia.", advice: "Ridere insieme e' la colla invisibile dell'amicizia. Il Sagittario che porta gioia nel gruppo crea legami che resistono a tutto." },
      { text: "Giove benedice oggi le amicizie basate sulla sincerita' e sull'autenticita', esattamente il tipo che il tuo segno cerca. Come Sagittario, non hai tempo per le amicizie di facciata: vuoi persone vere, che dicano cio' che pensano e vivano cio' che credono. Oggi le stelle ti confermano che il tuo cerchio di amici e' composto da cuori autentici. L'autenticita' attira autenticita', e il tuo cerchio ne e' la prova vivente.", advice: "L'autenticita' attira anime altrettanto genuine. Il Sagittario che vive senza maschere si circonda di amici veri." },
    ],
    capricorn: [
      { text: "Saturno premia oggi le amicizie che hai costruito nel tempo con pazienza e impegno genuino. Come Capricorno, non sei il tipo che colleziona amici come trofei: preferisci pochi legami profondi e duraturi. Le stelle confermano che questa selezione naturale ha prodotto un cerchio di amici di qualita' eccezionale. Come il vino migliore, le tue amicizie maturano e migliorano con ogni anno che passa.", advice: "Le amicizie migliori maturano come il vino pregiato. Il Capricorno che investe tempo nei legami raccoglie rapporti di valore inestimabile." },
      { text: "Le stelle vedono rispetto reciproco e stima genuina come fondamenta delle tue amicizie capricorniane. Come Capricorno governato da Saturno, la tua integrita' ti guadagna un tipo di rispetto che va oltre la simpatia superficiale. I tuoi amici ti stimano perche' sanno che sei una persona di parola, coerente e affidabile. Questo rispetto profondo oggi si manifesta in un riconoscimento che ti commuove.", advice: "Il rispetto e' la base di ogni relazione vera e duratura. Il Capricorno che vive con integrita' guadagna amicizie che resistono a tutto." },
      { text: "Un amico fidato ti offre supporto concreto in un momento importante della tua vita. Come Capricorno, tendi a portare sulle tue spalle tutto il peso senza chiedere aiuto, convinto che la forza stia nell'autosufficienza. Oggi Saturno ti insegna una lezione diversa: la vera forza sta anche nel saper accettare il supporto di chi ti vuole bene. I tuoi amici vogliono esserci per te come tu ci sei per loro.", advice: "Accetta l'aiuto degli amici con gratitudine, non e' debolezza. Il Capricorno che lascia entrare il supporto scopre una forza nuova." },
      { text: "Le costellazioni indicano la condivisione di saggezza e prospettive come cuore pulsante delle tue amicizie. Come Capricorno, cerchi amici che ti stimolino intellettualmente e ti offrano visioni diverse dalla tua. Saturno favorisce oggi una conversazione profonda che cambia la tua prospettiva su qualcosa di importante. I mentori migliori sono spesso gli amici, e oggi ne avrai la conferma.", advice: "I mentori migliori sono spesso nascosti tra gli amici. Il Capricorno che ascolta la saggezza degli amici cresce in modi inaspettati." },
      { text: "La tua affidabilita' oggi ti rende il pilastro centrale del tuo gruppo di amici. Come Capricorno, la tua presenza costante e la tua parola sempre mantenuta ti hanno guadagnato una posizione di rispetto e fiducia. Saturno amplifica questa reputazione oggi, facendo di te il punto di riferimento naturale per decisioni e consigli. Essere il pilastro per gli altri non e' un peso ma un privilegio che pochi meritano.", advice: "Essere il punto fermo per gli amici e' un onore che rispecchia il tuo valore. Il Capricorno affidabile e' un tesoro che il gruppo custodisce." },
      { text: "Le stelle parlano di tradizioni e rituali condivisi con gli amici che si consolidano e diventano sacri. Come Capricorno, apprezzi le abitudini e le routine che danno struttura anche alle relazioni amicali. Saturno favorisce oggi la creazione o il rafforzamento di un rituale con il tuo gruppo: un appuntamento fisso, una tradizione annuale, un luogo speciale. Questi rituali sono le ancore che tengono salda l'amicizia nel tempo.", advice: "Le tradizioni condivise con gli amici creano legami che il tempo rafforza. Il Capricorno che crea rituali costruisce ponti verso il futuro." },
      { text: "Saturno porta oggi serieta' e profondita' nelle conversazioni con i tuoi amici piu' cari. Come Capricorno, non ti soddisfano le chiacchiere leggere: cerchi dialoghi che abbiano sostanza e significato. Oggi le stelle portano esattamente questo tipo di scambio nella tua giornata. Una conversazione autentica e profonda con un amico ti lascia con una comprensione nuova e un legame ancora piu' forte.", advice: "Le conversazioni vere e profonde sono quelle che lasciano il segno. Il Capricorno che dialoga con sostanza crea legami intellettuali duraturi." },
      { text: "Un amico riconosce il tuo valore dopo un lungo silenzio e torna nella tua vita con rispetto e gratitudine. Come Capricorno, non insegui mai chi se ne va: se qualcuno sceglie di allontanarsi, lo lasci andare con dignita'. Saturno premia oggi questa dignita' con il ritorno di qualcuno che ha capito, con il tempo e la distanza, quanto sia raro e prezioso avere un Capricorno come amico.", advice: "Chi torna lo fa perche' ha capito quanto vale la tua amicizia. Il Capricorno che mantiene la propria dignita' attrae chi merita davvero." },
      { text: "Le stelle vedono la possibilita' di crescita professionale attraverso amicizie strategiche e autentiche. Come Capricorno, le tue relazioni hanno spesso una dimensione pragmatica che non toglie nulla alla loro autenticita'. Saturno favorisce oggi connessioni che sono al tempo stesso amicizie genuine e alleanze professionali. Le relazioni giuste, basate su stima reciproca, aprono porte che nessun curriculum potrebbe aprire.", advice: "Le amicizie autentiche possono anche aprire porte professionali. Il Capricorno che unisce genuinita' e strategia nelle relazioni va lontano." },
      { text: "La tua lealta' silenziosa e costante oggi viene riconosciuta come la forma piu' alta e matura di amicizia. Come Capricorno, non proclami la tua devozione con gesti eclatanti: la dimostri giorno dopo giorno con la tua presenza discreta ma incrollabile. Saturno illumina oggi questa qualita' silenziosa, facendola notare a chi a volte la dava per scontata. La vera amicizia non ha bisogno di parole: basta esserci sempre.", advice: "Non serve gridare l'amicizia: la presenza costante dice tutto. La lealta' silenziosa del Capricorno e' la dichiarazione d'amicizia piu' forte." },
    ],
    aquarius: [
      { text: "Urano porta oggi amicizie uniche e anticonvenzionali che rispecchiano perfettamente la tua natura acquariana. Come Acquario, il tuo gruppo di amici e' un mosaico di personalita' diverse e originali che insieme creano qualcosa di speciale. Oggi una nuova tessera si aggiunge a questo mosaico: qualcuno che condivide la tua visione non convenzionale del mondo. Le amicizie piu' belle per il tuo segno sono quelle fuori dagli schemi.", advice: "Le amicizie piu' belle sono quelle che sfidano le convenzioni. L'Acquario che accoglie l'unicita' altrui crea un cerchio straordinario." },
      { text: "Le stelle vedono una connessione profonda nascere dalla condivisione di ideali e valori che ti stanno a cuore. Come Acquario governato da Urano, le tue amicizie piu' significative sono quelle basate su visioni condivise del mondo. Oggi questa connessione ideale si manifesta con una forza particolare: incontri qualcuno o riscopri in un amico una passione comune che va oltre l'interesse personale e tocca l'universale.", advice: "Chi condivide i tuoi valori profondi e' un amico per la vita. L'Acquario che trova anime affini ideologicamente costruisce alleanze che cambiano il mondo." },
      { text: "Un amico apprezza oggi la tua originalita' e la tua capacita' di pensare in modo diverso da tutti gli altri. Come Acquario, la tua unicita' e' il tuo valore piu' grande, anche se a volte il mondo ti fa sentire strano per questo. Urano amplifica oggi l'apprezzamento per la tua diversita': qualcuno ti dira' esplicitamente quanto la tua prospettiva unica arricchisca il gruppo. Non cambiare mai: il tuo essere diverso e' il tuo dono.", advice: "La tua diversita' e' il tuo regalo al mondo. L'Acquario che resta fedele alla propria originalita' ispira tutti a essere piu' autentici." },
      { text: "Le costellazioni indicano attivismo e impegno sociale condiviso con amici come forza trainante delle tue relazioni. Come Acquario, hai bisogno di sentire che le tue amicizie hanno uno scopo che va oltre il divertimento. Urano porta oggi un'opportunita' di fare qualcosa di significativo insieme ai tuoi amici: un progetto comunitario, una causa condivisa, un'azione che fa la differenza. Insieme potete cambiare le cose.", advice: "L'amicizia con uno scopo sociale e' piu' forte di qualsiasi legame. L'Acquario che agisce per il bene comune insieme agli amici crea impatto reale." },
      { text: "Urano porta una sorpresa sociale piacevole che ti ricorda perche' la vita e' piu' bella con gli amici giusti. Come Acquario, ami le sorprese e gli imprevisti che rompono la routine. Oggi le stelle orchestrano un incontro o un evento inaspettato che portera' gioia e freschezza nella tua vita sociale. Le migliori amicizie per il tuo segno d'aria sono quelle che ti sorprendono continuamente.", advice: "Le sorprese sociali migliori arrivano quando meno te le aspetti. L'Acquario che abbraccia l'imprevisto sociale vive le esperienze piu' memorabili." },
      { text: "Le stelle parlano di liberta' nell'amicizia come valore non negoziabile per il tuo segno. Come Acquario governato da Urano, le tue amicizie sono scelte libere, non obblighi sociali. Ogni amico nel tuo cerchio e' li' perche' ha scelto di esserci, e tu hai scelto di accoglierlo. Questa liberta' reciproca e' il fondamento di rapporti autentici e sani. L'amicizia senza catene e' l'unica che il tuo segno d'aria puo' respirare.", advice: "Gli amici veri scelgono di esserci, non sono obbligati. L'Acquario che vive amicizie libere respira la forma piu' pura di legame." },
      { text: "Un'idea condivisa con un amico prende forma oggi e diventa un progetto entusiasmante e concreto. Come Acquario, le tue conversazioni spesso generano idee che hanno il potenziale di cambiare le cose. Urano alimenta oggi questa scintilla creativa condivisa, trasformando un concetto astratto in qualcosa di realizzabile. Due visionari che lavorano insieme possono creare cio' che un singolo sognatore non potrebbe mai.", advice: "Due visionari insieme possono letteralmente cambiare il mondo. L'Acquario che co-crea con gli amici moltiplica il proprio potenziale creativo." },
      { text: "La tua mente aperta e inclusiva attira oggi persone da ogni cammino e condizione di vita. Come Acquario, non giudichi mai un libro dalla copertina: sei interessato alla storia dentro, indipendentemente dall'aspetto esterno. Urano amplifica questa apertura mentale, portando nella tua orbita individui che arricchiscono la tua comprensione del mondo. La diversita' nel tuo gruppo non e' un caso: e' una scelta consapevole.", advice: "La diversita' nel gruppo di amici e' la ricchezza dell'Acquario. Ogni persona diversa da te ti insegna qualcosa di nuovo sul mondo." },
      { text: "Le stelle vedono una community che cresce intorno ai tuoi ideali e alla tua visione del futuro. Come Acquario, sei un catalizzatore naturale di persone: non cerchi seguaci ma compagni di viaggio che condividano la tua direzione. Urano amplifica oggi questa forza aggregativa, portando anime affini nella tua orbita. Questa community non e' un gruppo qualsiasi: e' un movimento, un'energia collettiva guidata dalla tua visione.", advice: "Sei un catalizzatore naturale di persone e idee. L'Acquario che aggrega anime affini crea movimenti che lasciano il segno." },
      { text: "Urano stimola oggi conversazioni rivoluzionarie e stimolanti con i tuoi amici piu' cari. Come Acquario, hai bisogno di dialoghi che sfidino le convenzioni, che esplorino territori inesplorati del pensiero. Oggi le stelle portano esattamente questo tipo di scambio: una conversazione che ribalta prospettive e apre orizzonti nuovi. Le idee migliori e piu' rivoluzionarie nascono dal confronto tra menti libere e curiose.", advice: "Le idee migliori nascono dal confronto tra menti libere. L'Acquario che dialoga senza limiti con gli amici genera pensieri rivoluzionari." },
    ],
    pisces: [
      { text: "Nettuno avvolge oggi le tue amicizie in un'aura di magia e connessione spirituale profonda. Come Pesci, i tuoi legami amicali trascendono il piano materiale: sono connessioni dell'anima che comunicano a un livello che le parole non raggiungono. Oggi questa qualita' nettuniana si manifesta in un momento di comprensione telepatica con un amico caro. Sentite le stesse cose, pensate gli stessi pensieri: questa e' amicizia cosmica.", advice: "Le amicizie dell'anima comunicano oltre le parole. Il Pesci che coltiva connessioni spirituali con gli amici vive legami eterni." },
      { text: "Le stelle vedono empatia reciproca al massimo livello tra te e un amico che ti capisce senza bisogno di spiegazioni. Come Pesci governato da Nettuno, la telepatia emotiva e' il tuo modo naturale di comunicare con chi ami. Oggi questa connessione e' particolarmente forte: un amico capisce cosa provi prima che tu apra bocca. Questa comprensione silenziosa e' il segno dell'amicizia vera, quella che va oltre le parole.", advice: "La telepatia emotiva con un amico e' il segno del legame piu' autentico. Il Pesci che comunica senza parole ha trovato un'anima gemella." },
      { text: "La tua sensibilita' nettuniana oggi guarisce un amico che sta attraversando un momento difficile. Come Pesci, la tua semplice presenza ha un effetto terapeutico sugli altri: emani una pace e una comprensione che sciolgono le tensioni. Oggi questo dono si manifesta in modo particolarmente potente. Non devi fare nulla di speciale: la tua presenza empatica e' gia' la medicina piu' efficace per chi soffre.", advice: "La tua semplice presenza e' gia' una medicina per chi soffre. Il Pesci che sta accanto all'amico in difficolta' guarisce con la propria luce." },
      { text: "Le costellazioni indicano creativita' condivisa con un amico come esperienza che rafforza profondamente il legame. Come Pesci, l'arte e la creativita' sono il tuo linguaggio naturale, e condividerle con qualcuno di speciale moltiplica la gioia. Nettuno ispira oggi un progetto creativo condiviso: dipingere, scrivere, suonare, cucinare insieme. L'atto creativo condiviso e' una forma di intimita' che pochi conoscono.", advice: "L'arte condivisa con un amico rafforza il legame in modo unico. Il Pesci che crea insieme agli amici genera bellezza e connessione." },
      { text: "Nettuno dissolve oggi un malinteso o una tensione con un amico in modo naturale e senza forzature. Come Pesci, preferisci che le cose si risolvano fluendo naturalmente piuttosto che attraverso confronti diretti. Oggi le stelle favoriscono questa dissoluzione dolce: una tensione che pesava si scioglie come neve al sole, senza bisogno di parole o spiegazioni. A volte il perdono piu' potente e' quello silenzioso.", advice: "A volte basta lasciar fluire le cose per risolvere tutto. Il Pesci che si fida del flusso naturale trova la pace nelle relazioni." },
      { text: "Le stelle parlano di sogni e visioni condivise con un amico che rafforzano un legame gia' speciale. Come Pesci, hai bisogno di amici che sappiano sognare con te, che credano nella magia delle possibilita'. Nettuno porta oggi un momento di condivisione onirica: un sogno, un progetto, una visione del futuro che diventa piu' reale perche' condivisa. Sognare insieme e' il primo passo per realizzare insieme.", advice: "Sognare insieme a un amico e' il primo passo per realizzare. Il Pesci che condivide le proprie visioni le avvicina alla realta'." },
      { text: "La tua gentilezza naturale attira oggi anime pure e sincere nel tuo spazio vitale. Come Pesci governato da Nettuno, emani una dolcezza che funziona come un magnete per chi cerca autenticita' e comprensione. Il tuo gruppo di amici e' un rifugio per anime sensibili, un luogo dove la vulnerabilita' e' accolta e non giudicata. Oggi questo spazio sacro si arricchisce di una presenza nuova e luminosa.", advice: "Il tuo cuore gentile crea un rifugio per le anime sensibili. Il Pesci che protegge questo spazio sacro nutre le amicizie piu' preziose." },
      { text: "Un amico percepisce oggi il tuo stato d'animo con una precisione che ti sorprende e ti commuove. Come Pesci, sei abituato a sentire gli altri ma raramente qualcuno sente te con la stessa profondita'. Nettuno facilita oggi questa reciprocita' emotiva, permettendo a un amico di leggere nel tuo cuore come tu leggi nel suo. Questa connessione bidirezionale e' rara e preziosa: custodiscila con cura.", advice: "Le connessioni emotive bidirezionali sono tesori rari. Il Pesci che riceve la stessa empatia che offre ha trovato un legame dell'anima." },
      { text: "Le stelle vedono un gesto di generosita' disinteressata verso un amico che definisce chi sei veramente. Come Pesci, la tua capacita' di sacrificio per chi ami e' profonda come l'oceano che rappresenta il tuo segno. Oggi un gesto che fai senza aspettarti nulla in cambio lascera' un'impronta indelebile nel cuore di qualcuno. I gesti disinteressati sono quelli che rivelano la vera natura dell'anima.", advice: "I gesti disinteressati definiscono la grandezza della tua anima. Il Pesci che dona senza calcolo riceve l'amicizia piu' pura in cambio." },
      { text: "Nettuno ispira oggi compassione e supporto reciproco nel tuo cerchio di amici. Come Pesci, credi in un mondo dove le persone si sostengono a vicenda senza giudicare, dove la vulnerabilita' e' forza e la compassione e' saggezza. Oggi il tuo gruppo di amici riflette esattamente questo ideale nettuniano. Un cerchio di anime compassionevoli che si supportano reciprocamente e' il tesoro piu' grande che la vita possa offrire.", advice: "Un cerchio di amici compassionevoli e' il tesoro piu' grande. Il Pesci che crea comunita' basate sulla compassione cambia il mondo una persona alla volta." },
    ],
  },
};

export const getStarResponse = (
  category: StarCategory,
  sign: ZodiacSignId,
  questionIndex: number,
  dateStr: string,
): StarResponse => {
  const responses = RESPONSES[category]?.[sign] ?? RESPONSES.love.aries;
  const seed = dateStr.split("-").reduce((a, b) => a + parseInt(b), 0);
  const index = (seed + questionIndex * 7) % responses.length;
  return responses[index];
};
